-- ============================================================
-- SCRIPT DE INICIALIZAÇÃO COMPLETO - ASSETTRACK PRO
-- EXECUTE ESTE BLOCO NO SQL EDITOR DO SUPABASE
-- ============================================================

-- 1. Criação das Tabelas Operacionais (Se não existirem)
CREATE TABLE IF NOT EXISTS public.departments (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    "costCenter" TEXT,
    "createdAt" TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.employees (
    id TEXT PRIMARY KEY,
    "departmentId" TEXT REFERENCES public.departments(id),
    name TEXT NOT NULL,
    sector TEXT,
    role TEXT,
    cpf TEXT,
    "isActive" BOOLEAN DEFAULT TRUE
);

CREATE TABLE IF NOT EXISTS public.assets (
    id TEXT PRIMARY KEY,
    "departmentId" TEXT REFERENCES public.departments(id),
    type TEXT NOT NULL,
    brand TEXT,
    model TEXT,
    status TEXT DEFAULT 'Disponível',
    "assignedTo" TEXT REFERENCES public.employees(id),
    "qrCode" TEXT,
    observations TEXT,
    photos TEXT[],
    history JSONB DEFAULT '[]'::jsonb,
    "createdAt" TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.requests (
    id TEXT PRIMARY KEY,
    "requesterId" TEXT,
    "employeeId" TEXT REFERENCES public.employees(id),
    items TEXT[],
    "itemFulfillments" JSONB DEFAULT '[]'::jsonb,
    observation TEXT,
    status TEXT DEFAULT 'Pendente',
    "createdAt" TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.users (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    username TEXT UNIQUE NOT NULL,
    password TEXT,
    sector TEXT,
    modules TEXT[]
);

CREATE TABLE IF NOT EXISTS public.notifications (
    id TEXT PRIMARY KEY,
    title TEXT,
    message TEXT,
    type TEXT,
    "targetModule" TEXT,
    "isRead" BOOLEAN DEFAULT FALSE,
    "createdAt" TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.audit_sessions (
    id TEXT PRIMARY KEY,
    sector TEXT,
    entries JSONB DEFAULT '[]'::jsonb,
    "isFinished" BOOLEAN DEFAULT FALSE,
    "createdAt" TIMESTAMPTZ DEFAULT NOW()
);

-- 2. Tabelas do Módulo Contábil
CREATE TABLE IF NOT EXISTS public.accounting_accounts (
    id TEXT PRIMARY KEY,
    code TEXT NOT NULL,
    name TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS public.accounting_classifications (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    code TEXT NOT NULL,
    "accountId" TEXT REFERENCES public.accounting_accounts(id) ON DELETE RESTRICT
);

CREATE TABLE IF NOT EXISTS public.asset_type_configs (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    "classificationId" TEXT REFERENCES public.accounting_classifications(id) ON DELETE SET NULL
);

-- 3. Habilitação de Segurança (RLS) para TODAS as tabelas
ALTER TABLE public.departments ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.assets ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.requests ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.audit_sessions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.accounting_accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.accounting_classifications ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.asset_type_configs ENABLE ROW LEVEL SECURITY;

-- 4. Criação de Políticas de Acesso Público (Permissivo para desenvolvimento/demo)
-- Nota: Para produção real com dados sensíveis, use roles autenticadas.

DO $$ 
DECLARE 
    t TEXT;
BEGIN
    FOR t IN 
        SELECT table_name 
        FROM information_schema.tables 
        WHERE table_schema = 'public' 
        AND table_type = 'BASE TABLE'
    LOOP
        EXECUTE format('DROP POLICY IF EXISTS "Public Full Access" ON public.%I', t);
        EXECUTE format('CREATE POLICY "Public Full Access" ON public.%I FOR ALL USING (true) WITH CHECK (true)', t);
    END LOOP;
END $$;

-- 5. Usuário Administrador Inicial (Obrigatório para o primeiro login)
