import React, { useState, useMemo } from 'react';
import { 
  Layers, 
  Plus, 
  Search, 
  Trash2, 
  Edit2, 
  Package, 
  X, 
  ChevronRight, 
  ShieldCheck, 
  FileText, 
  History, 
  TrendingUp, 
  Activity,
  ArrowRight,
  Clock,
  Briefcase,
  User,
  Heart
} from 'lucide-react';
import { Department, Asset, HistoryEntry } from '../types';

interface CompanyManagerProps {
  companies: Department[];
  assets: Asset[];
  onAddCompany: (company: Omit<Department, 'id' | 'createdAt'>) => void;
  onUpdateCompany: (company: Department) => void;
  onRemoveCompany: (id: string) => void;
}

const CompanyManager: React.FC<CompanyManagerProps> = ({ companies, assets, onAddCompany, onUpdateCompany, onRemoveCompany }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingCompany, setEditingCompany] = useState<Department | null>(null);
  const [selectedDeptForReport, setSelectedDeptForReport] = useState<Department | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({ name: '', costCenter: '' });

  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.costCenter?.includes(searchTerm)
  );

  // Alterado para contar apenas ativos que NÃO estão baixados
  const getAssetCount = (departmentId: string) => assets.filter(a => a.departmentId === departmentId && a.status !== 'Baixado').length;

  const handleEdit = (department: Department) => {
    setEditingCompany(department);
    setFormData({ name: department.name, costCenter: department.costCenter || '' });
    setShowForm(true);
  };

  const handleOpenCreate = () => {
    setEditingCompany(null);
    setFormData({ name: '', costCenter: '' });
    setShowForm(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCompany) {
      onUpdateCompany({
        ...editingCompany,
        name: formData.name,
        costCenter: formData.costCenter
      });
    } else {
      onAddCompany(formData);
    }
    setFormData({ name: '', costCenter: '' });
    setShowForm(false);
    setEditingCompany(null);
  };

  const departmentAssets = useMemo(() => {
    if (!selectedDeptForReport) return [];
    return assets.filter(a => a.departmentId === selectedDeptForReport.id && a.status !== 'Baixado');
  }, [assets, selectedDeptForReport]);

  const healthScore = useMemo(() => {
    if (departmentAssets.length === 0) return 100;
    const maintenance = departmentAssets.filter(a => a.status === 'Manutenção').length;
    return Math.round(100 - (maintenance / departmentAssets.length * 100));
  }, [departmentAssets]);

  const aggregatedHistory = useMemo(() => {
    if (!selectedDeptForReport) return [];
    const allHistory: (HistoryEntry & { assetId: string; assetType: string })[] = [];

    // Pegamos ativos atuais e antigos vinculados a este depto para um histórico completo
    assets.filter(a => a.departmentId === selectedDeptForReport.id).forEach(asset => {
      (asset.history || []).forEach(entry => {
        allHistory.push({
          ...entry,
          assetId: asset.id,
          assetType: asset.type
        });
      });
    });

    return allHistory.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [assets, selectedDeptForReport]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar departamento..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none shadow-sm font-medium transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Plus className="w-5 h-5" />
          Novo Departamento
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredCompanies.map(dept => (
          <div 
            key={dept.id} 
            className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl hover:border-blue-200 transition-all group relative overflow-hidden flex flex-col"
          >
            <div className="flex justify-between items-start mb-6">
              <div 
                onClick={() => handleEdit(dept)}
                className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all duration-500 shadow-sm cursor-pointer"
              >
                <Layers className="w-7 h-7" />
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={() => setSelectedDeptForReport(dept)}
                  className="p-3 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                >
                  <FileText className="w-5 h-5" />
                </button>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    if(confirm(`Deseja realmente remover ${dept.name}?`)) onRemoveCompany(dept.id);
                  }}
                  className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="space-y-1 cursor-pointer flex-1" onClick={() => setSelectedDeptForReport(dept)}>
              <h4 className="text-xl font-black text-slate-800 tracking-tight group-hover:text-blue-600 transition-colors">{dept.name}</h4>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{dept.costCenter || 'C. Custo não informado'}</p>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-50 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Package className="w-4 h-4 text-slate-300" />
                <span className="text-sm font-black text-slate-700">{getAssetCount(dept.id)} Itens</span>
              </div>
              <button 
                onClick={() => setSelectedDeptForReport(dept)}
                className="flex items-center gap-1 text-blue-600 font-black text-[10px] uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0"
              >
                Relatório <ChevronRight className="w-3 h-3" />
              </button>
            </div>
          </div>
        ))}
      </div>

      {selectedDeptForReport && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-5xl h-[90vh] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-300">
              <div className="p-8 bg-slate-900 text-white flex items-center justify-between shrink-0">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl">
                       <FileText className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black tracking-tight">{selectedDeptForReport.name}</h3>
                       <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Mapa de Saúde e Inventário de Ativos</p>
                    </div>
                 </div>
                 <button onClick={() => setSelectedDeptForReport(null)} className="p-3 hover:bg-white/10 rounded-full transition-colors">
                    <X className="w-7 h-7" />
                 </button>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                 <div className="w-full lg:w-1/3 border-r border-slate-100 bg-slate-50/50 p-8 overflow-y-auto custom-scrollbar space-y-8">
                    <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm text-center">
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2">Saúde Operacional</p>
                       <div className="flex items-center justify-center gap-2 mb-2">
                          <Heart className={`w-5 h-5 ${healthScore > 80 ? 'text-emerald-500 fill-emerald-500' : 'text-amber-500 fill-amber-500'}`} />
                          <span className="text-4xl font-black text-slate-900">{healthScore}%</span>
                       </div>
                       <p className="text-[9px] text-slate-500 font-bold uppercase">Índice de Ativos Disponíveis</p>
                    </div>

                    <div className="space-y-4">
                       <h5 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Frota do Setor</h5>
                       {departmentAssets.map(asset => (
                         <div key={asset.id} className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                              asset.status === 'Em Uso' ? 'bg-emerald-50 text-emerald-600' : 
                              asset.status === 'Manutenção' ? 'bg-amber-50 text-amber-600' : 'bg-slate-50 text-slate-400'
                            }`}>
                               <Package className="w-5 h-5" />
                            </div>
                            <div className="min-w-0">
                               <p className="text-xs font-black text-slate-800 truncate">{asset.brand} {asset.model}</p>
                               <p className="text-[10px] font-mono text-slate-400 uppercase">{asset.status}</p>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>

                 <div className="flex-1 p-10 overflow-y-auto custom-scrollbar bg-white">
                    <div className="flex items-center justify-between mb-8">
                       <div className="flex items-center gap-3">
                          <History className="w-5 h-5 text-blue-600" />
                          <h4 className="text-lg font-black text-slate-900 tracking-tight">Histórico Completo de Movimentação</h4>
                       </div>
                    </div>

                    <div className="relative pl-8 space-y-10 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100">
                       {aggregatedHistory.map((entry, idx) => (
                         <div key={`${entry.id}-${idx}`} className="relative group">
                            <div className={`absolute -left-[30px] top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                              entry.type === 'Manutenção' ? 'bg-amber-500' :
                              entry.type === 'Atribuição' ? 'bg-emerald-500' : 'bg-blue-600'
                            }`}>
                               <Clock className="w-3 h-3 text-white" />
                            </div>
                            <div className="space-y-1.5">
                               <div className="flex items-center gap-3">
                                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(entry.date).toLocaleDateString()}</span>
                                  <span className="bg-slate-100 px-2 py-0.5 rounded text-[8px] font-black uppercase text-slate-500">
                                     {entry.assetType} • {entry.assetId}
                                  </span>
                               </div>
                               <p className="text-sm font-bold text-slate-800 leading-relaxed group-hover:text-blue-700 transition-colors">
                                  {entry.description}
                                </p>
                               <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase">
                                  <ShieldCheck className="w-3 h-3" /> {entry.performedBy || 'Sistema'}
                               </div>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>

              <div className="p-8 border-t border-slate-100 bg-slate-50 flex justify-end">
                 <button onClick={() => setSelectedDeptForReport(null)} className="px-12 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-[10px]">Fechar Relatório</button>
              </div>
           </div>
        </div>
      )}

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className={`p-8 ${editingCompany ? 'bg-amber-600' : 'bg-blue-600'} text-white flex justify-between items-center transition-colors`}>
               <h3 className="text-2xl font-black tracking-tight">{editingCompany ? 'Editar Departamento' : 'Novo Departamento'}</h3>
               <button onClick={() => { setShowForm(false); setEditingCompany(null); }} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-10 space-y-6">
               <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome</label>
                  <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />
               </div>
               <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Centro de Custo</label>
                  <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold" value={formData.costCenter} onChange={e => setFormData({...formData, costCenter: e.target.value})} />
               </div>
               <div className="flex gap-3 pt-4">
                 <button type="button" onClick={() => setShowForm(false)} className="flex-1 py-5 rounded-[2rem] font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                 <button type="submit" className={`flex-[2] text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs ${editingCompany ? 'bg-amber-600' : 'bg-blue-600'}`}>Salvar</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CompanyManager;

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { 
  ShieldCheck, 
  Activity, 
  AlertTriangle, 
  Layers,
  Truck,
  ArrowRight,
  Package,
  X,
  User,
  Archive,
  Info
} from 'lucide-react';
import { Asset, EquipmentRequest, Employee } from '../types';

interface DashboardProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
}

const COLORS = ['#2563eb', '#059669', '#d97706', '#dc2626', '#4f46e5'];

type DetailType = 'total' | 'in-use' | 'maintenance' | 'retired' | null;

const Dashboard: React.FC<DashboardProps> = ({ assets, requests, employees }) => {
  const [selectedDetail, setSelectedDetail] = useState<DetailType>(null);

  const today = new Date().toISOString().split('T')[0];

  // Filtra apenas ativos que compõem a frota operacional (Ignora Baixados para contagens de "Total")
  const activeAssets = useMemo(() => assets.filter(a => a.status !== 'Baixado'), [assets]);

  const todayDeliveries = useMemo(() => {
    const deliveries: any[] = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach(f => {
        if (f.purchaseStatus === 'Comprado' && !f.isDelivered && f.deliveryForecastDate === today) {
          const emp = employees.find(e => e.id === req.employeeId);
          deliveries.push({
            id: req.id,
            item: f.type,
            employeeName: emp?.name || 'N/A',
            sector: emp?.sector || 'N/A'
          });
        }
      });
    });
    return deliveries;
  }, [requests, employees, today]);

  const stats = [
    { id: 'total' as DetailType, label: 'Ativos Operacionais', value: activeAssets.length, icon: Layers, color: 'text-blue-700', bg: 'bg-blue-100' },
    { id: 'in-use' as DetailType, label: 'Em Uso', value: assets.filter(a => a.status === 'Em Uso').length, icon: ShieldCheck, color: 'text-emerald-700', bg: 'bg-emerald-100' },
    { id: 'maintenance' as DetailType, label: 'Em Manutenção', value: assets.filter(a => a.status === 'Manutenção').length, icon: Activity, color: 'text-amber-700', bg: 'bg-amber-100' },
    { id: 'retired' as DetailType, label: 'Baixados / Sucata', value: assets.filter(a => a.status === 'Baixado').length, icon: AlertTriangle, color: 'text-rose-700', bg: 'bg-rose-100' },
  ];

  const chartData = [
    { name: 'Desktop', qty: activeAssets.filter(a => a.type === 'Desktop').length },
    { name: 'Notebook', qty: activeAssets.filter(a => a.type === 'Notebook').length },
    { name: 'Monitor', qty: activeAssets.filter(a => a.type === 'Monitor').length },
    { name: 'Outros', qty: activeAssets.filter(a => !['Desktop', 'Notebook', 'Monitor'].includes(a.type)).length },
  ];

  const statusData = [
    { name: 'Disponível', value: activeAssets.filter(a => a.status === 'Disponível').length },
    { name: 'Em Uso', value: activeAssets.filter(a => a.status === 'Em Uso').length },
    { name: 'Manutenção', value: activeAssets.filter(a => a.status === 'Manutenção').length },
    { name: 'Pendente Doc', value: activeAssets.filter(a => a.status === 'Pendente Documentos').length },
  ];

  const assetsGroupedByEmployee = useMemo(() => {
    const inUseAssets = assets.filter(a => a.status === 'Em Uso' && a.assignedTo);
    const groups: Record<string, Asset[]> = {};

    inUseAssets.forEach(asset => {
      const empId = asset.assignedTo!;
      if (!groups[empId]) groups[empId] = [];
      groups[empId].push(asset);
    });

    return Object.entries(groups).map(([empId, items]) => ({
      employee: employees.find(e => e.id === empId),
      items
    }));
  }, [assets, employees]);

  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {todayDeliveries.length > 0 && (
        <div className="bg-white border-2 border-emerald-500 rounded-[2.5rem] p-8 shadow-xl shadow-emerald-50 overflow-hidden relative">
           <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-6 text-center md:text-left">
                 <div className="w-16 h-16 bg-emerald-500 rounded-[2rem] flex items-center justify-center text-white shadow-lg shadow-emerald-200 shrink-0 animate-bounce">
                    <Truck className="w-8 h-8" />
                 </div>
                 <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Entregas de Hoje</h3>
                    <p className="text-slate-600 font-semibold">Temos {todayDeliveries.length} {todayDeliveries.length === 1 ? 'equipamento chegando' : 'equipamentos chegando'} ao escritório hoje.</p>
                 </div>
              </div>
              <div className="flex flex-wrap gap-3">
                 {todayDeliveries.slice(0, 3).map((d, i) => (
                   <div key={i} className="bg-emerald-50 border border-emerald-200 px-4 py-3 rounded-2xl flex items-center gap-3">
                      <Package className="w-4 h-4 text-emerald-700" />
                      <div>
                        <p className="text-[10px] font-black uppercase text-emerald-700 leading-none">{String(d.item || 'Item')}</p>
                        <p className="text-xs font-bold text-slate-800">{String(d.employeeName || 'N/A')}</p>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div 
            key={idx} 
            onClick={() => setSelectedDetail(stat.id)}
            className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group cursor-pointer active:scale-95"
          >
            <div className="flex items-center justify-between mb-4">
              <div className={`${stat.bg} ${stat.color} p-4 rounded-2xl group-hover:bg-slate-900 group-hover:text-white transition-all`}>
                <stat.icon className="w-6 h-6" />
              </div>
              <span className="text-3xl font-black text-slate-900 tracking-tighter">{stat.value}</span>
            </div>
            <div className="flex items-center justify-between">
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{stat.label}</p>
              <ArrowRight className="w-4 h-4 text-slate-400 group-hover:text-blue-600 transform group-hover:translate-x-1 transition-all" />
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Ativos por Categoria (Ativos)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                <Tooltip 
                  cursor={{fill: '#f1f5f9'}}
                  contentStyle={{borderRadius: '16px', border: '1px solid #e2e8f0', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="qty" fill="#2563eb" radius={[8, 8, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Status Operacional</h3>
          <div className="h-72 flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={70}
                  outerRadius={100}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                   contentStyle={{borderRadius: '16px', border: '1px solid #e2e8f0', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex flex-col gap-3 ml-8">
              {statusData.map((entry, idx) => (
                <div key={idx} className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[idx % COLORS.length]}} />
                  <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{entry.name}</span>
                  <span className="text-xs font-black text-slate-900 ml-auto">{entry.value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {selectedDetail && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-xl">
                       {selectedDetail === 'total' && <Layers className="w-7 h-7" />}
                       {selectedDetail === 'in-use' && <ShieldCheck className="w-7 h-7" />}
                       {selectedDetail === 'maintenance' && <Activity className="w-7 h-7" />}
                       {selectedDetail === 'retired' && <AlertTriangle className="w-7 h-7" />}
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">
                          {selectedDetail === 'total' && 'Relatório de Ativos Operacionais'}
                          {selectedDetail === 'in-use' && 'Ativos Alocados'}
                          {selectedDetail === 'maintenance' && 'Centro de Manutenção'}
                          {selectedDetail === 'retired' && 'Arquivo de Baixas'}
                       </h3>
                       <p className="text-slate-600 text-sm font-black uppercase tracking-widest text-[10px]">Visão Analítica para Diretoria</p>
                    </div>
                 </div>
                 <button 
                  onClick={() => setSelectedDetail(null)}
                  className="p-3 hover:bg-slate-200 rounded-full transition-colors text-slate-500 hover:text-slate-900"
                 >
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-white">
                {selectedDetail === 'total' && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {chartData.map((item, idx) => (
                      <div key={idx} className="bg-slate-50 p-6 rounded-3xl border border-slate-200 flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all">
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-blue-100 text-blue-700 rounded-2xl flex items-center justify-center font-black">
                             {item.name.charAt(0)}
                          </div>
                          <div>
                            <p className="font-black text-slate-900">{item.name}</p>
                            <p className="text-xs text-slate-600 font-black uppercase tracking-widest">Categoria Ativa</p>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className="text-3xl font-black text-slate-900">{item.qty}</p>
                          <p className="text-[10px] font-black text-blue-700 uppercase">Unidades</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {selectedDetail === 'in-use' && (
                  <div className="space-y-6">
                    {assetsGroupedByEmployee.map((group, idx) => (
                      <div key={idx} className="bg-white border border-slate-200 rounded-[2.5rem] shadow-sm overflow-hidden">
                        <div className="bg-slate-50 p-6 border-b border-slate-200 flex items-center justify-between">
                          <div className="flex items-center gap-4">
                             <div className="w-12 h-12 bg-white rounded-full border border-slate-300 flex items-center justify-center text-slate-500">
                                <User className="w-6 h-6" />
                             </div>
                             <div>
                                <h4 className="font-black text-slate-900">{String(group.employee?.name || 'Não Vinculado')}</h4>
                                <p className="text-xs text-slate-600 font-black uppercase tracking-widest">{String(group.employee?.sector || 'Sem Setor')}</p>
                             </div>
                          </div>
                          <span className="bg-blue-700 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-100">
                            {group.items.length} {group.items.length === 1 ? 'Ativo' : 'Ativos'}
                          </span>
                        </div>
                        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                          {group.items.map(asset => (
                            <div key={asset.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-200 flex items-center gap-3">
                               <Package className="w-5 h-5 text-slate-600" />
                               <div>
                                  <p className="text-xs font-black text-slate-900 leading-none mb-1">{String(asset.type)}</p>
                                  <p className="text-[10px] text-slate-600 font-black uppercase">{String(asset.brand)} {String(asset.model)}</p>
                                  <p className="text-[9px] text-blue-700 font-mono font-bold mt-1">ID: {asset.id}</p>
                               </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {selectedDetail === 'maintenance' && (
                  <div className="space-y-4">
                    {assets.filter(a => a.status === 'Manutenção').map(asset => (
                      <div key={asset.id} className="bg-white p-6 rounded-3xl border-2 border-amber-200 shadow-sm flex flex-col md:flex-row gap-6 hover:border-amber-500 transition-colors">
                        <div className="flex items-center gap-4 md:w-1/3">
                           <div className="w-16 h-16 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-700 shrink-0">
                              <Activity className="w-8 h-8" />
                           </div>
                           <div>
                              <p className="font-black text-slate-900 text-lg">{String(asset.type)}</p>
                              <p className="text-sm text-slate-600 font-black uppercase tracking-widest leading-none mb-1">{String(asset.brand)} {String(asset.model)}</p>
                              <p className="text-[10px] font-mono font-bold text-slate-500">PATRIMÔNIO: {asset.id}</p>
                           </div>
                        </div>
                        <div className="flex-1 bg-amber-50/50 p-6 rounded-2xl border border-amber-200 relative">
                           <div className="absolute -top-3 left-4 bg-amber-700 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Laudo Técnico / Motivo</div>
                           <p className="text-sm text-slate-800 font-semibold italic leading-relaxed">
                             "{String(asset.observations || 'Nenhum motivo específico detalhado no cadastro de manutenção.')}"
                           </p>
                           <div className="mt-4 flex items-center gap-2 text-[10px] font-black uppercase text-amber-700 tracking-widest">
                             <User className="w-3 h-3" /> Responsável Anterior: {getEmployeeName(asset.assignedTo)}
                           </div>
                        </div>
                      </div>
                    ))}
                    {assets.filter(a => a.status === 'Manutenção').length === 0 && (
                      <div className="text-center py-20 bg-slate-50 rounded-[2.5rem] border border-dashed border-slate-300">
                         <Info className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                         <p className="text-slate-600 font-black uppercase tracking-widest">Nenhum equipamento em manutenção no momento.</p>
                      </div>
                    )}
                  </div>
                )}

                {selectedDetail === 'retired' && (
                  <div className="grid grid-cols-1 gap-4">
                    {assets.filter(a => a.status === 'Baixado').map(asset => (
                      <div key={asset.id} className="bg-white p-6 rounded-3xl border border-slate-300 flex items-center justify-between hover:bg-rose-50/30 transition-colors group">
                        <div className="flex items-center gap-6">
                           <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 group-hover:bg-rose-100 group-hover:text-rose-700 transition-all">
                              <Archive className="w-7 h-7" />
                           </div>
                           <div>
                              <div className="flex items-center gap-3">
                                <h4 className="text-lg font-black text-slate-900">{String(asset.type)}</h4>
                                <span className="bg-rose-100 text-rose-700 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border border-rose-200">Baixado</span>
                              </div>
                              <p className="text-sm text-slate-600 font-black uppercase tracking-tighter">{String(asset.brand)} {String(asset.model)} • {asset.id}</p>
                           </div>
                        </div>
                        <div className="max-w-md text-right">
                           <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-1">Motivo da Baixa</p>
                           <p className="text-sm text-slate-800 font-semibold leading-tight">
                             {String(asset.observations || 'Sucateamento técnico por obsolescência.')}
                           </p>
                        </div>
                      </div>
                    ))}
                    {assets.filter(a => a.status === 'Baixado').length === 0 && (
                      <div className="text-center py-20 bg-slate-50 rounded-[2.5rem] border border-dashed border-slate-300">
                         <Archive className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                         <p className="text-slate-600 font-black uppercase tracking-widest">Nenhum equipamento baixado no histórico.</p>
                      </div>
                    )}
                  </div>
                )}
              </div>

              <div className="p-8 border-t border-slate-200 bg-slate-50 flex items-center justify-between">
                 <p className="text-xs text-slate-600 font-bold italic">Dados sincronizados em tempo real com o banco de ativos.</p>
                 <button 
                  onClick={() => setSelectedDetail(null)}
                  className="bg-slate-900 hover:bg-black text-white px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-slate-200 transition-all"
                 >
                    Fechar Relatório
                 </button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
};

export default Dashboard;

