  ChevronRight,
  Info,
  Layers,
  ArrowRight,
  User,
  Settings2,
  ShoppingCart,
  Trash2,
  FileText,
  Zap,
  Loader2,
  History
} from 'lucide-react';
import { Asset, HistoryEntry, Employee, Department, AppNotification, EquipmentRequest, AssetType, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface MaintenanceManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  currentUser: UserAccount;
  onUpdateAsset: (asset: Asset) => Promise<void>;
  onAddNotification: (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => void;
  onAddRequest: (req: any) => Promise<void>;
}

const MaintenanceManager: React.FC<MaintenanceManagerProps> = ({ assets, employees, companies, currentUser, onUpdateAsset, onAddNotification, onAddRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [selectedAssetId, setSelectedAssetId] = useState('');
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);

  const [reason, setReason] = useState('');
  const [finalDiagnosis, setFinalDiagnosis] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPOForm, setShowPOForm] = useState(false);
  const [poType, setPoType] = useState<AssetType>('Mouse');
  const [validationError, setValidationError] = useState(false);

  const assetsInMaintenance = useMemo(() => 
    assets.filter(a => a.status === 'Manutenção')
  , [assets]);

  const availableForMaintenance = useMemo(() => 
    assets.filter(a => a.status !== 'Manutenção' && a.status !== 'Baixado')
  , [assets]);

  const filteredAvailable = availableForMaintenance.filter(a => 
    a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
    a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
    a.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleOpenMaintenance = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAssetId || !reason.trim()) return;

    const asset = assets.find(a => a.id === selectedAssetId);
    if (!asset) return;

    setIsSubmitting(true);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Entrada em manutenção: ${reason}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...asset,
        status: 'Manutenção',
        observations: reason,
        history: [...(asset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);
      setShowModal(false);
      setSelectedAssetId('');
      setReason('');
    } catch (error) {
      alert("Erro ao iniciar manutenção.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleConcludeMaintenance = async () => {
    if (!detailAsset) return;

    const diagnosis = finalDiagnosis.trim();
    if (!diagnosis) {
      setValidationError(true);
      return;
    }

    setIsSubmitting(true);
    setValidationError(false);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-CONC-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Manutenção concluída. Laudo: ${diagnosis}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Disponível',
        assignedTo: undefined, // Libera o colaborador anterior
        observations: `Reparo finalizado em ${new Date().toLocaleDateString()}: ${diagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);
      alert("Manutenção concluída com sucesso! O ativo está disponível para uso.");
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error: any) {
      alert("Falha ao concluir: " + (error.message || "Erro de rede"));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRetireAsset = async () => {
    if (!detailAsset) return;

    const diagnosis = finalDiagnosis.trim();
    if (!diagnosis) {
      setValidationError(true);
      return;
    }

    if (!window.confirm("CONFIRMAÇÃO CRÍTICA: Deseja realmente realizar a BAIXA PATRIMONIAL permanente deste ativo? Esta ação removerá o ativo de circulação.")) {
      return;
    }

    setIsSubmitting(true);
    setValidationError(false);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-BAIXA-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Status',
        description: `BAIXA PATRIMONIAL DEFINITIVA: ${diagnosis}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Baixado',
        assignedTo: undefined, // Crucial: limpar vínculo
        departmentId: detailAsset.departmentId, // Mantemos depto original p/ histórico
        observations: `ATIVO INATIVADO/BAIXADO EM ${new Date().toLocaleDateString()}: ${diagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      console.log("[Maintenance] Executando baixa para:", updatedAsset.id);
      await onUpdateAsset(updatedAsset);

      onAddNotification({
        title: 'Baixa de Patrimônio',
        message: `O ativo ${detailAsset.id} foi inativado permanentemente.`,
        type: 'alert',
        targetModule: 'assets'
      });

      alert(`Baixa patrimonial do ativo ${detailAsset.id} realizada com sucesso!`);
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error: any) {
      console.error("Erro na baixa:", error);
      alert("Erro ao processar baixa patrimonial: " + (error.message || "Verifique a conexão ou permissões."));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreatePurchaseOrder = async () => {
    if (!detailAsset) return;
    setIsSubmitting(true);
    try {
      // Cria uma requisição padronizada para o fluxo de compras
      await onAddRequest({
        requesterId: currentUser.id,
        employeeId: '', // Sem vínculo com funcionário específico, é peça de estoque/manutenção
        items: [poType],
        observation: `[MANUTENÇÃO] Aquisição de peça (${poType}) para reparo do ativo ${detailAsset.id}.\nDiagnóstico Atual: ${finalDiagnosis || detailAsset.observations}`,
        // ItemFulfillment com estrutura completa para entrar direto no fluxo de Cotação
        itemFulfillments: [{ 
          type: poType, 
          isPurchaseOrder: true, 
          purchaseStatus: 'Pendente',
          quotations: [
             { url: '', price: 0, deliveryPrediction: '' },
             { url: '', price: 0, deliveryPrediction: '' },
             { url: '', price: 0, deliveryPrediction: '' }
          ]
        }]
      });
      setShowPOForm(false);
      onAddNotification({
        title: 'Solicitação de Compra',
        message: `Pedido de compra iniciado para ${poType} (Ref: ${detailAsset.id}).`,
        type: 'info',
        targetModule: 'purchase-orders'
      });
      alert("Fluxo de compra iniciado com sucesso!\nAcompanhe a cotação no módulo 'Pedidos de Compra'.");
    } catch (e: any) {
      console.error(e);
      // Proteção contra erro [object Object] se a exceção não tiver message
      const errorMsg = e?.message || JSON.stringify(e) || "Erro desconhecido";
      alert("Erro ao iniciar fluxo de compra: " + errorMsg);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">Centro de Manutenção</h3>
          <p className="text-slate-500 font-medium italic">Gestão técnica e descarte de equipamentos.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-amber-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Wrench className="w-5 h-5" />
          Nova Entrada de Reparo
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assetsInMaintenance.map(asset => (
          <div 
            key={asset.id} 
            onClick={() => {
              if (isSubmitting) return;
              setDetailAsset(asset);
              setFinalDiagnosis(''); 
              setValidationError(false);
              setShowDetailModal(true);
            }}
            className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm hover:shadow-xl hover:border-amber-400 transition-all group flex flex-col cursor-pointer active:scale-95"
          >
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 group-hover:bg-amber-600 group-hover:text-white transition-all duration-500 shadow-sm">
                <Activity className="w-7 h-7" />
              </div>
              <div className="flex flex-col items-end">
                 <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-1 shadow-lg shadow-amber-100">
                    Em Reparo
                 </span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter font-mono">{asset.id}</p>
              </div>
            </div>

            <div className="space-y-1 mb-6">
              <h4 className="text-xl font-black text-slate-800 tracking-tight leading-none group-hover:text-amber-600 transition-colors">{asset.type}</h4>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{asset.brand} {asset.model}</p>
            </div>

            <div className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 mb-6 flex-1">
               <div className="flex items-center gap-2 text-amber-600 mb-2">
                  <Info className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Diagnóstico Inicial</span>
               </div>
               <p className="text-xs text-slate-600 font-medium leading-relaxed italic line-clamp-3">
                 "{asset.observations}"
               </p>
            </div>

            <div className="flex items-center justify-between text-amber-600 font-black text-[10px] uppercase tracking-widest pt-2 border-t border-amber-100">
               <span>Painel de Encerramento</span>
               <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </div>
          </div>
        ))}

        {assetsInMaintenance.length === 0 && (
          <div className="col-span-full py-32 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-center space-y-4">
             <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-sm">
                <Settings2 className="w-10 h-10 text-slate-200" />
             </div>
             <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Sem Ativos em Manutenção</p>
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-100 bg-amber-600 text-white flex items-center justify-between">
                 <h3 className="text-2xl font-black tracking-tight flex items-center gap-3">
                   <Wrench className="w-7 h-7" /> Entrada em Manutenção
                 </h3>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                 <div className="w-full lg:w-1/2 border-r border-slate-100 flex flex-col p-8 bg-slate-50/50 overflow-y-auto custom-scrollbar">
                    <div className="relative mb-6">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <input 
                         type="text"
                         placeholder="Buscar por Patrimônio..."
                         className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white outline-none font-bold shadow-sm"
                         value={searchTerm}
                         onChange={(e) => setSearchTerm(e.target.value)}
                       />
                    </div>
                    <div className="space-y-3">
                       {filteredAvailable.map(asset => (
                         <button 
                          key={asset.id}
                          type="button"
                          onClick={() => setSelectedAssetId(asset.id)}
                          className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between group ${
                            selectedAssetId === asset.id 
                              ? 'bg-amber-600 border-amber-600 text-white shadow-xl' 
                              : 'bg-white border-slate-200 text-slate-800 hover:border-amber-300'
                          }`}
                         >
                            <div className="text-left">
                               <p className="text-xs font-black uppercase tracking-tight">{asset.type}</p>
                               <p className={`text-[10px] font-bold ${selectedAssetId === asset.id ? 'text-amber-100' : 'text-slate-500'}`}>
                                 {asset.brand} {asset.model} • {asset.id}
                               </p>
                            </div>
                         </button>
                       ))}
                    </div>
                 </div>
                 <div className="flex-1 p-8 bg-white overflow-y-auto">
                    <form onSubmit={handleOpenMaintenance} className="space-y-8">
                       <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Diagnóstico Inicial</label>
                          <textarea 
                            className="w-full p-5 rounded-[2rem] border border-slate-200 bg-slate-50 outline-none resize-none h-40 font-medium text-slate-700"
                            placeholder="Descreva o problema observado..."
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            required
                          />
                       </div>
                       <button 
                        type="submit"
                        disabled={!selectedAssetId || isSubmitting}
                        className={`w-full py-5 rounded-[2rem] font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-3 ${
                          selectedAssetId && !isSubmitting ? 'bg-amber-600 hover:bg-amber-700 text-white' : 'bg-slate-100 text-slate-300'
                        }`}
                       >
                          {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <CheckCircle2 className="w-5 h-5" />}
                          {isSubmitting ? 'Iniciando...' : 'Confirmar Entrada'}
                       </button>
                    </form>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showDetailModal && detailAsset && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95">
              <div className="p-8 bg-slate-900 text-white flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-amber-600 rounded-2xl flex items-center justify-center">
                       <Settings2 className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Encerramento de Ordem Técnica</p>
                    </div>
                 </div>
                 <button onClick={() => setShowDetailModal(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                       <History className="w-4 h-4 text-amber-500" /> Diagnóstico Inicial de Entrada
                    </label>
                    <div className="w-full p-6 rounded-[2.5rem] bg-slate-50 border-2 border-slate-100 font-bold text-slate-500 italic">
                       "{detailAsset.observations}"
                    </div>
                 </div>

                 <div className="space-y-3">
                    <div className="flex justify-between items-center ml-1">
                      <label className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-colors ${validationError ? 'text-rose-500' : 'text-blue-600'}`}>
                         <FileText className="w-4 h-4" /> Laudo Técnico / Justificativa (Obrigatório)
                      </label>
                      {validationError && <span className="text-[9px] font-black text-rose-500 uppercase animate-pulse">Preenchimento Necessário</span>}
                    </div>
                    <textarea 
                      className={`w-full p-6 rounded-[2.5rem] bg-white border-2 outline-none font-bold text-slate-800 min-h-[160px] resize-none transition-all ${validationError ? 'border-rose-300 ring-2 ring-rose-100 shadow-lg shadow-rose-100' : 'border-slate-200 focus:border-blue-500'}`}
                      placeholder="Relate os procedimentos realizados ou o motivo técnico para a baixa patrimonial..."
                      value={finalDiagnosis}
                      onChange={(e) => {
                        setFinalDiagnosis(e.target.value);
                        if (e.target.value.trim()) setValidationError(false);
                      }}
                    />
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-slate-100">
                    <button 
                      type="button"
                      disabled={isSubmitting}
                      onClick={() => setShowPOForm(!showPOForm)}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-blue-600 hover:bg-blue-50/30 transition-all flex flex-col items-center justify-center gap-2 disabled:opacity-50"
                    >
                       <ShoppingCart className="w-5 h-5 text-blue-600" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-700">Solicitar Peças</span>
                    </button>

                    <button 
                      type="button"
                      onClick={handleRetireAsset}
                      disabled={isSubmitting}
                      className={`w-full p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-2 disabled:opacity-50 ${validationError ? 'border-rose-400 bg-rose-50 animate-bounce' : 'border-slate-100 hover:border-rose-600 hover:bg-rose-50/30'}`}
                    >
                       <Trash2 className={`w-5 h-5 ${validationError ? 'text-rose-600' : 'text-rose-500'}`} />
                       <span className={`text-[11px] font-black uppercase tracking-widest ${validationError ? 'text-rose-800' : 'text-rose-700'}`}>Baixa / Inativar</span>
                    </button>
                 </div>

                 {showPOForm && (
                    <div className="bg-blue-50 p-6 rounded-[2rem] border-2 border-blue-100 space-y-4 animate-in slide-in-from-top-2">
                       <select 
                          className="w-full p-4 rounded-xl bg-white border border-blue-200 font-bold outline-none"
                          value={poType}
                          onChange={(e) => setPoType(e.target.value as AssetType)}
                       >
                          {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                       </select>
                       <button 
                          type="button"
                          onClick={handleCreatePurchaseOrder}
                          disabled={isSubmitting}
                          className="w-full bg-blue-600 text-white font-black py-4 rounded-xl shadow-lg uppercase tracking-widest text-[10px] disabled:opacity-50"
                       >
                          Iniciar Fluxo de Compra
                       </button>
                       <p className="text-[9px] text-blue-700 text-center font-bold">O pedido seguirá para cotação no módulo de Compras.</p>
                    </div>
                 )}

                 <div className="pt-6">
                    <button 
                      type="button"
                      onClick={handleConcludeMaintenance}
                      disabled={isSubmitting}
                      className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-xl transition-all flex items-center justify-center gap-3 active:scale-95 disabled:bg-slate-400"
                    >
                       {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                       {isSubmitting ? 'Salvando...' : 'Concluir e Liberar p/ Uso'}
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default MaintenanceManager;

export type AssetType = string;

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; 
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

export interface AccountingAccount {
  id: string;
  code: string;
  name: string;
}

export interface AccountingClassification {
  id: string;
  name: string;
  code: string;
  accountId: string;
}

export interface AssetTypeConfig {
  id: string;
  name: string;
  classificationId?: string;
}

export interface Asset {
  id: string;
  serialNumber?: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; 
  isWireless?: boolean; 
  monitorInputs?: string[]; 
  isAbnt?: boolean; 
  hasNumericKeypad?: boolean; 
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; 
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; 
  purchaseValue?: number; // Novo campo para valor de aquisição
}

export interface Employee {
  id: string;
  departmentId: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
  isActive?: boolean;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance'
  | 'accounting';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string;
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'maintenance' | 'delivery' | 'alert';
  createdAt: string;
  targetModule?: AppModule;
  isRead?: boolean;
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId?: string | null; // Alterado para permitir nulo/undefined
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado' | 'Confronto';
  createdAt: string;
  type?: 'Padrao' | 'Divergencia';
}

export type AuditStatus = 'Bom' | 'Regular' | 'Ruim' | 'Não Encontrado';

export interface AuditEntry {
  assetId: string;
  status: AuditStatus;
  checkedAt: string;
  observation?: string;
}

export interface AuditSession {
  id: string;
  sector: string;
  createdAt: string;
  entries: AuditEntry[];
  isFinished: boolean;
  generatedRequestId?: string;
}

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import AccountingManager from './components/AccountingManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { 
  Asset, Employee, EquipmentRequest, UserAccount, 
  Department, AuditSession, AppNotification, AccountingAccount, 
  AccountingClassification, AssetTypeConfig 
} from './types';
import { db, supabase } from './services/supabase';
import { Loader2, Package, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [isOffline, setIsOffline] = useState(false);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Estados Contábeis
  const [accountingAccounts, setAccountingAccounts] = useState<AccountingAccount[]>([]);
  const [accountingClassifications, setAccountingClassifications] = useState<AccountingClassification[]>([]);
  const [assetTypeConfigs, setAssetTypeConfigs] = useState<AssetTypeConfig[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const results = await Promise.allSettled([
        db.departments.list(),
        db.assets.list(),
        db.employees.list(),
        db.requests.list(),
        db.auditSessions.list(),
        db.users.list(),
        db.notifications.list(),
        db.accountingAccounts.list(),
        db.accountingClassifications.list(),
        db.assetTypeConfigs.list()
      ]);

      const [
        depts, assts, emps, reqs, audits, userList, 
        notifs, accAccounts, accClass, assetConfigs
      ] = results.map(r => r.status === 'fulfilled' ? (r.value || []) : []);

      if (results.every(r => r.status === 'rejected')) setIsOffline(true);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);
      setAccountingAccounts(accAccounts);
      setAccountingClassifications(accClass);
      setAssetTypeConfigs(assetConfigs);

      const finalUsers = userList && userList.length > 0 ? [...userList] : [...MOCK_USERS];
      if (!finalUsers.find(u => u.username === 'admin')) {
        finalUsers.push(MOCK_USERS[0]);
      }
      setUsers(finalUsers);
      setNotifications(notifs);

    } catch (err: any) {
      console.error("Erro no carregamento:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    loadData(); 
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications' },
        (payload) => {
          const newNotif = payload.new as AppNotification;
          setNotifications(prev => {
            if (!prev) return [newNotif];
            if (prev.find(n => n.id === newNotif.id)) return prev;
            return [newNotif, ...prev].slice(0, 50);
          });
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => {
    const newNotif: AppNotification = {
      ...notif,
      id: `NTF-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      isRead: false
    };
    setNotifications(prev => [newNotif, ...(prev || [])].slice(0, 50));
    try { await db.notifications.upsert(newNotif); } catch (e) {}
  };

  const markNotificationAsRead = async (id: string) => {
    const target = notifications.find(n => n.id === id);
    if (!target) return;
    const updated = { ...target, isRead: true };
    setNotifications(prev => (prev || []).map(n => n.id === id ? updated : n));
    try { await db.notifications.upsert(updated); } catch (e) {}
  };

  const clearNotifications = async () => {
    setNotifications([]);
    try { await db.notifications.clearAll(); } catch (e) {}
  };

  const handleLogin = async (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules && user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    let finalId = assetData.id?.trim();
    if (!finalId) {
       const randomSuffix = Math.floor(1000 + Math.random() * 9000);
       finalId = `AST-${randomSuffix}`;
       while(assets.some(a => a.id === finalId)) {
         finalId = `AST-${Math.floor(1000 + Math.random() * 9000)}`;
       }
    }

    const newAsset: Asset = { 
      ...assetData, 
      id: finalId, 
      qrCode: `QR-${finalId}`,
      createdAt: new Date().toISOString(),
      history: assetData.history || [{
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: `Patrimônio registrado no sistema (ID Automático: ${!assetData.id ? 'Sim' : 'Não'}).`,
        performedBy: currentUser?.name || 'Sistema'
      }],
      observations: assetData.observations || ''
    };
    await db.assets.upsert(newAsset);
    setAssets(prev => [newAsset, ...(prev || [])]);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    const oldAsset = assets.find(a => a.id === updated.id);
    let finalAsset = { ...updated };

    // LÓGICA DE PROTEÇÃO DE STATUS CRÍTICO
    if (finalAsset.status === 'Baixado') {
      // Se for baixa, limpa obrigatoriamente vínculos para evitar erros de integridade e inconsistência visual
      finalAsset.assignedTo = undefined;
      // Mantemos o departmentId apenas se for necessário para histórico de custos, 
      // mas geralmente ativos baixados saem do centro de custo.
    } else if (finalAsset.status === 'Manutenção') {
      // Se estiver em manutenção, mantemos o status manual vindo do componente
    } else {
      // Lógica automática para outros estados
      if (finalAsset.assignedTo) {
        finalAsset.status = 'Em Uso';
        const emp = employees.find(e => e.id === finalAsset.assignedTo);
        if (emp) finalAsset.departmentId = emp.departmentId;
      } else if (finalAsset.status === 'Em Uso' || (oldAsset?.assignedTo && !finalAsset.assignedTo)) {
        finalAsset.status = 'Disponível';
      }
    }

    try {
      console.log(`[AssetUpdate] Persistindo ${finalAsset.id} com status ${finalAsset.status}`);
      await db.assets.upsert(finalAsset);
      setAssets(prev => {
        const next = (prev || []).map(a => a.id === finalAsset.id ? { ...finalAsset } : a);
        return [...next];
      });
    } catch (err: any) {
      console.error("Falha ao atualizar ativo no Supabase:", err);
      throw err;
    }
  };

  const handleRemoveAsset = async (id: string) => {
    await db.assets.remove(id);
    setAssets(prev => (prev || []).filter(a => a.id !== id));
  };

  const handleAddRequest = async (reqData: any): Promise<void> => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;

    // CORREÇÃO CRÍTICA: Se employeeId for string vazia, converte para null.
    // Isso evita o erro de chave estrangeira no banco de dados.
    const sanitizedData = { ...reqData };
    if (sanitizedData.employeeId === '') {
      sanitizedData.employeeId = null;
    }

    const newReq: EquipmentRequest = { ...sanitizedData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...(prev || [])]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => (prev || []).map(r => r.id === req.id ? req : r));

    if (req.status === 'Entregue' && req.employeeId) {
      const employee = employees.find(e => e.id === req.employeeId);
      if (!employee) return;

      const assetsToUpdate: Asset[] = [];

      req.itemFulfillments?.forEach(f => {
        if (f.linkedAssetId) {
          const asset = assets.find(a => a.id === f.linkedAssetId);
          if (asset) {
            assetsToUpdate.push({
              ...asset,
              status: 'Em Uso',
              assignedTo: employee.id,
              departmentId: employee.departmentId,
              history: [
                ...(asset.history || []),
                {
                  id: Math.random().toString(),
                  date: new Date().toISOString(),
                  type: 'Atribuição',
                  description: `Ativo entregue ao colaborador ${employee.name} via Requisição ${req.id}.`,
                  performedBy: currentUser?.name || 'Sistema'
                }
              ]
            });
          }
        }
      });

      if (assetsToUpdate.length > 0) {
        for (const asset of assetsToUpdate) {
          await db.assets.upsert(asset);
        }
        setAssets(prev => {
          const newAssets = [...prev];
          assetsToUpdate.forEach(updated => {
            const idx = newAssets.findIndex(a => a.id === updated.id);
            if (idx !== -1) newAssets[idx] = updated;
          });
          return newAssets;
        });

        addNotification({
          title: 'Patrimônio Atualizado',
          message: `${assetsToUpdate.length} item(ns) movidos para posse de ${employee.name}.`,
          type: 'delivery',
          targetModule: 'assets'
        });
      }
    }
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => (prev || []).filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => (prev || []).map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">AssetTrack Pro: Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = (employees || []).filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800 animate-bounce">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">O sistema está em modo de contingência offline (Local Storage).</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={activeEmployees} />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} assetTypeConfigs={assetTypeConfigs} classifications={accountingClassifications} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={async (id) => { 
                setEmployees(prev => {
                  const target = prev.find(e => e.id === id);
                  if (!target) return prev;
                  const updatedEmployee = { ...target, isActive: false };
                  db.employees.upsert(updatedEmployee);
                  return prev.map(e => e.id === id ? updatedEmployee : e);
                });
              }}
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
              assetTypeConfigs={assetTypeConfigs}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} assetTypeConfigs={assetTypeConfigs} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                await db.users.upsert(newU); 
                setUsers(prev => [...prev, newU]); 
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          case 'accounting':
            return <AccountingManager 
              accounts={accountingAccounts}
              classifications={accountingClassifications}
              assetTypes={assetTypeConfigs}
              onAddAccount={async (a) => { const newA = {...a, id: `ACC-${Date.now()}`}; await db.accountingAccounts.upsert(newA); setAccountingAccounts(prev => [...prev, newA]); }}
              onUpdateAccount={async (a) => { await db.accountingAccounts.upsert(a); setAccountingAccounts(prev => prev.map(old => old.id === a.id ? a : old)); }}
              onRemoveAccount={async (id) => { await db.accountingAccounts.remove(id); setAccountingAccounts(prev => prev.filter(a => a.id !== id)); }}
              onAddClassification={async (c) => { const newC = {...c, id: `CLS-${Date.now()}`}; await db.accountingClassifications.upsert(newC); setAccountingClassifications(prev => [...prev, newC]); }}
              onUpdateClassification={async (c) => { await db.accountingClassifications.upsert(c); setAccountingClassifications(prev => prev.map(old => old.id === c.id ? c : old)); }}
              onRemoveClassification={async (id) => { await db.accountingClassifications.remove(id); setAccountingClassifications(prev => prev.filter(c => c.id !== id)); }}
              onAddAssetType={async (t) => { const newT = {...t, id: `TYPE-${Date.now()}`}; await db.assetTypeConfigs.upsert(newT); setAssetTypeConfigs(prev => [...prev, newT]); }}
              onUpdateAssetType={async (t) => { await db.assetTypeConfigs.upsert(t); setAssetTypeConfigs(prev => prev.map(old => old.id === t.id ? t : old)); }}
              onRemoveAssetType={async (id) => { await db.assetTypeConfigs.remove(id); setAssetTypeConfigs(prev => prev.filter(t => t.id !== id)); }}
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  FileText, Plus, X, Clock, ChevronRight, CheckCircle, ShoppingCart, Link as LinkIcon, 
  Search, AlertCircle, User, Calendar, Package, Check, Ban, Truck, MessageSquare, 
  CheckSquare, Wrench, UserPlus, Loader2, ShieldCheck, Edit2, Trash2, Download, ImageIcon,
  Printer
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { EquipmentRequest, Employee, Asset, AssetType, UserAccount, AssetTypeConfig } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onRemoveRequest?: (id: string) => Promise<void>;
  assetTypeConfigs: AssetTypeConfig[];
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ 
  requests, 
  employees, 
  assets, 
  currentUser, 
  onAddRequest, 
  onUpdateStatus, 
  onUpdateRequest, 
  onRemoveRequest,
  assetTypeConfigs 
}) => {
  const [showModal, setShowModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id?: string | null) => employees.find(e => e.id === id);
  const getEmployeeName = (id?: string | null) => getEmployee(id)?.name || 'Desconhecido';

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const generateResponsibilityTerm = (req: EquipmentRequest) => {
    const employee = getEmployee(req.employeeId);
    if (!employee) return;

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();

    // Cabeçalho
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(16);
    doc.text('TERMO DE RESPONSABILIDADE E ENTREGA', pageWidth / 2, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Protocolo: ${req.id}`, pageWidth - 20, 30, { align: 'right' });
    doc.text(`Data: ${new Date(req.createdAt).toLocaleDateString('pt-BR')}`, pageWidth - 20, 35, { align: 'right' });

    // Dados do Colaborador
    doc.setFont('helvetica', 'bold');
    doc.text('1. IDENTIFICAÇÃO DO COLABORADOR', 20, 50);
    doc.line(20, 52, pageWidth - 20, 52);

    doc.setFont('helvetica', 'normal');
    doc.text(`Nome: ${employee.name}`, 20, 60);
    doc.text(`CPF: ${employee.cpf}`, 20, 65);
    doc.text(`Departamento: ${employee.sector} / ${employee.role}`, 20, 70);

    // Lista de Equipamentos
    doc.setFont('helvetica', 'bold');
    doc.text('2. EQUIPAMENTOS ENTREGUES', 20, 85);
    doc.line(20, 87, pageWidth - 20, 87);

    const tableData = (req.itemFulfillments || []).map(f => {
      const asset = assets.find(a => a.id === f.linkedAssetId);
      return [
        f.type,
        asset?.brand || 'N/A',
        asset?.model || 'N/A',
        asset?.id || 'Pendente',
        asset?.serialNumber || 'S/N'
      ];
    });

    (doc as any).autoTable({
      startY: 92,
      head: [['Tipo', 'Marca', 'Modelo', 'Patrimônio', 'Série']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillGray: 200, textColor: 0, fontStyle: 'bold' },
      styles: { fontSize: 9 }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;

    // Termos
    doc.setFont('helvetica', 'bold');
    doc.text('3. DECLARAÇÃO DE RESPONSABILIDADE', 20, finalY);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    const text = `Declaro ter recebido os equipamentos acima descritos em perfeito estado de conservação e funcionamento, comprometendo-me a utilizá-los exclusivamente para fins profissionais de interesse da empresa. Assumo total responsabilidade pela guarda, conservação e integridade dos mesmos, ciente de que danos causados por uso indevido ou negligência poderão ser objeto de ressarcimento conforme legislação vigente. Em caso de desligamento, comprometo-me a devolver os itens imediatamente ao setor de TI.`;
    const splitText = doc.splitTextToSize(text, pageWidth - 40);
    doc.text(splitText, 20, finalY + 7);

    // Assinaturas
    const sigY = finalY + 60;
    doc.line(20, sigY, 90, sigY);
    doc.text('Assinatura do Colaborador', 35, sigY + 5);

    doc.line(120, sigY, 190, sigY);
    doc.text('Responsável TI (Entrega)', 135, sigY + 5);

    doc.save(`Termo_Responsabilidade_${req.id}.pdf`);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0 || !newReq.employeeId) {
      alert("Preencha todos os campos.");
      return;
    }
    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({ type, isPurchaseOrder: false }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) { alert("Erro ao criar requisição."); }
    finally { setIsSubmitting(false); }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = { type: selectedRequest.items[index], linkedAssetId: assetId, isPurchaseOrder: false };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      const updated = { ...selectedRequest, status };
      await onUpdateRequest(updated);
      setSelectedRequest(updated);
    }
  };

  const handleRemove = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!onRemoveRequest) return;
    if (confirm("Tem certeza que deseja excluir permanentemente esta requisição?")) {
      try {
        await onRemoveRequest(id);
        if (selectedRequest?.id === id) setSelectedRequest(null);
      } catch (err) { alert("Falha ao excluir requisição."); }
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4 print:hidden">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : req.status === 'Entregue' ? <ShieldCheck className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <p className="font-black text-slate-900">{req.id}</p>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-4">
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border-indigo-200' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-800 border-emerald-200' : 'bg-rose-100 text-rose-800 border-rose-200'
               }`}>
                 {req.status}
               </span>
               <button onClick={(e) => handleRemove(e, req.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100">
                 <Trash2 className="w-5 h-5" />
               </button>
               <ChevronRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}

        {requests.length === 0 && (
          <div className="bg-white p-16 rounded-[2.5rem] border border-dashed border-slate-300 text-center space-y-4">
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação encontrada.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24 print:hidden">
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5" />
          <span>Nova Requisição</span>
        </button>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
                 <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição</h3>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</label>
                    <select className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold" value={newReq.employeeId || ''} onChange={e => setNewReq({...newReq, employeeId: e.target.value})} required>
                       <option value="">Selecione...</option>
                       {employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}
                    </select>
                 </div>
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Itens</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {(assetTypeConfigs.length > 0 ? assetTypeConfigs.map(t => t.name) : ASSET_TYPES).map(type => (
                         <button key={type} type="button" onClick={() => toggleItem(type as AssetType)} className={`p-3 rounded-xl border text-[10px] font-black uppercase ${newReq.items.includes(type as AssetType) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'}`}>
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>
                 <button type="submit" disabled={isSubmitting} className="w-full bg-blue-600 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs disabled:bg-slate-300">
                    {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "Abrir Requisição"}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-black text-slate-900">{selectedRequest.id}</h3>
                <p className="text-sm text-slate-600 font-bold">Destino: {getEmployeeName(selectedRequest.employeeId)}</p>
              </div>
              <div className="flex items-center gap-2">
                 <button onClick={(e) => handleRemove(e, selectedRequest.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors" title="Excluir Requisição">
                   <Trash2 className="w-5 h-5" />
                 </button>
                 <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-500"><X className="w-6 h-6" /></button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-6">
               {selectedRequest.items.map((itemType, idx) => {
                  const fulfillment = selectedRequest.itemFulfillments?.[idx];
                  const isLinked = !!fulfillment?.linkedAssetId;
                  return (
                    <div key={idx} className={`p-5 rounded-3xl border ${isLinked ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-slate-200'}`}>
                      <div className="flex items-center justify-between mb-4">
                        <span className="font-black text-slate-900">{itemType}</span>
                        {isLinked && <span className="text-[10px] font-black uppercase text-emerald-800">Vinculado: {fulfillment.linkedAssetId}</span>}
                      </div>
                      {!isLinked && selectedRequest.status !== 'Entregue' && (
                        <button onClick={() => setItemToLink({ index: idx, type: itemType })} className="w-full py-2 bg-slate-100 rounded-xl text-[10px] font-black uppercase hover:bg-blue-600 hover:text-white transition-all">
                          Vincular Ativo
                        </button>
                      )}
                      {itemToLink?.index === idx && (
                        <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300">
                           <div className="space-y-2">
                              {availableAssetsByType(itemType).map(asset => (
                                <button key={asset.id} onClick={() => handleLinkAsset(idx, asset.id)} className="w-full text-left p-3 bg-white border border-slate-300 rounded-xl hover:border-blue-600">
                                   <p className="text-xs font-black">{asset.id} - {asset.brand} {asset.model}</p>
                                </button>
                              ))}
                              {availableAssetsByType(itemType).length === 0 && <p className="text-[10px] font-black text-slate-400 text-center uppercase">Sem estoque disponível</p>}
                           </div>
                        </div>
                      )}
                    </div>
                  );
               })}
            </div>

            <div className="p-8 border-t border-slate-200 flex flex-col gap-3">
               {selectedRequest.status === 'Pendente' && <button onClick={() => handleStatusChange('Aprovado')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs">Aprovar Pedido</button>}
               {selectedRequest.status === 'Aprovado' && <button onClick={() => handleStatusChange('Preparando')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Iniciar Preparação</button>}
               {selectedRequest.status === 'Preparando' && (
                 <button 
                  onClick={() => {
                    const allLinked = selectedRequest.itemFulfillments?.every(f => f.linkedAssetId || f.isPurchaseOrder);
                    if (!allLinked) {
                      alert("Vincule todos os ativos antes de confirmar a entrega.");
                      return;
                    }
                    handleStatusChange('Entregue');
                  }} 
                  className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg shadow-emerald-100"
                 >
                   Confirmar Entrega
                 </button>
               )}
               {selectedRequest.status === 'Entregue' && (
                 <div className="space-y-3">
                   <div className="p-4 bg-emerald-50 border border-emerald-100 rounded-2xl flex items-center gap-3">
                     <CheckCircle className="w-5 h-5 text-emerald-600" />
                     <span className="text-xs font-black uppercase text-emerald-800 tracking-tight">Solicitação Finalizada</span>
                   </div>
                   <button 
                    onClick={() => generateResponsibilityTerm(selectedRequest)}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black uppercase text-xs flex items-center justify-center gap-2 shadow-lg transition-all"
                   >
                     <Printer className="w-5 h-5" />
                     Imprimir Termo de Entrega
                   </button>
                 </div>
               )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestsManager;

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  Search, 
  Check, 
  AlertCircle,
  CreditCard,
  FileText,
  Package,
  Truck,
  X,
  Link as LinkIcon,
  CheckSquare,
  Square,
  MoreHorizontal,
  ChevronRight,
  ShieldCheck,
  Zap,
  Tag,
  QrCode,
  DollarSign,
  Plus,
  ArrowRight,
  ExternalLink,
  Loader2,
  Clock
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation, Asset, HistoryEntry, AssetType, AssetTypeConfig } from '../types';
import { ASSET_TYPES } from '../constants';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onAssetCreated: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string; history?: HistoryEntry[] }) => Promise<void>;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  assetTypeConfigs: AssetTypeConfig[];
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ 
  requests, 
  employees, 
  onUpdateRequest, 
  onAssetCreated, 
  onAddRequest,
  assetTypeConfigs 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Todos');
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);
  const [showDirectOrderModal, setShowDirectOrderModal] = useState(false);
  const [showReceiptForm, setShowReceiptForm] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newDirectOrder, setNewDirectOrder] = useState({
    type: 'Notebook' as AssetType,
    observation: ''
  });

  const [receiptData, setReceiptData] = useState<Partial<Asset>>({
    brand: '',
    model: '',
    id: '',
    observations: '',
    purchaseValue: 0
  });

  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (employee?.name || 'Estoque').toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());
    const status = item.fulfillment.purchaseStatus || 'Pendente';
    const matchesStatus = statusFilter === 'Todos' || status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id?: string | null) => employees.find(e => e.id === id)?.name || 'Estoque TI (Reposição)';

  const handleUpdateQuotation = async (qIndex: number, field: keyof Quotation, value: any) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };
    const quotations = [...(item.quotations || [
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }
    ])];
    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = async (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Cotação Aprovada', 
      approvedQuotationIndex: qIndex 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleAuthorizeOrder = async () => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Pedido Autorizado' 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = async (requestId: string, fIndex: number) => {
    const req = requests.find(r => r.id === requestId);
    if (!req) return;
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIndex] = { ...newFulfillments[fIndex], purchaseStatus: 'Comprado' };
    await onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleOpenReceipt = () => {
    if (!currentFulfillment) return;

    // Regra: Capturar valor se NÃO for peça de reposição
    const isReplacementPart = currentFulfillment.type.toLowerCase().includes('peça') || 
                               currentFulfillment.type.toLowerCase().includes('reposição');

    let priceFromQuotation = 0;
    if (!isReplacementPart && currentFulfillment.approvedQuotationIndex !== undefined) {
      priceFromQuotation = currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex]?.price || 0;
    }

    setReceiptData({
      brand: '',
      model: '',
      id: '',
      observations: `Item recebido via Pedido de Compra referente à requisição ${currentRequest?.id}`,
      type: currentFulfillment.type,
      purchaseValue: priceFromQuotation
    });
    setShowReceiptForm(true);
  };

  const handleFinalizeAndCreateAsset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentRequest || activeSelection === null || !currentFulfillment) return;
    setIsSubmitting(true);

    try {
      await onAssetCreated({
        id: receiptData.id || undefined,
        brand: receiptData.brand || '',
        model: receiptData.model || '',
        type: currentFulfillment.type,
        departmentId: 'DEPT-1',
        status: currentRequest.employeeId ? 'Em Uso' : 'Disponível',
        assignedTo: currentRequest.employeeId || undefined,
        observations: receiptData.observations || '',
        purchaseValue: receiptData.purchaseValue || 0,
        photos: [],
        history: [
          {
            id: Math.random().toString(),
            date: new Date().toISOString(),
            type: 'Criação',
            description: `Tombamento via compra ref. ${currentRequest.id}. Valor registrado: R$ ${receiptData.purchaseValue?.toLocaleString('pt-BR')}`,
            performedBy: 'Sistema Financeiro'
          }
        ]
      });

      const newFulfillments = [...(currentRequest.itemFulfillments || [])];
      newFulfillments[activeSelection.fIndex] = { 
        ...newFulfillments[activeSelection.fIndex], 
        isDelivered: true, 
        linkedAssetId: receiptData.id || 'AUTO-GERADO'
      };

      await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });

      setShowReceiptForm(false);
      setActiveSelection(null);
    } catch (err) {
      alert("Erro ao finalizar tombamento.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreateDirectOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await onAddRequest({
        requesterId: '1',
        employeeId: '', 
        items: [newDirectOrder.type],
        observation: newDirectOrder.observation,
        itemFulfillments: [{
          type: newDirectOrder.type,
          isPurchaseOrder: true,
          purchaseStatus: 'Pendente',
          quotations: [
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' }
          ]
        }]
      });
      setShowDirectOrderModal(false);
      setNewDirectOrder({ type: 'Notebook', observation: '' });
    } catch (err) {
      alert("Erro ao criar pedido.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 flex-1 w-full">
          {[
            { label: 'Cotações', count: purchaseItems.filter(i => (i.fulfillment.purchaseStatus || 'Pendente') === 'Pendente').length, color: 'text-amber-600', bg: 'bg-amber-50' },
            { label: 'Autorização', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Cotação Aprovada').length, color: 'text-blue-600', bg: 'bg-blue-50' },
            { label: 'Autorizados', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pedido Autorizado').length, color: 'text-indigo-600', bg: 'bg-indigo-50' },
            { label: 'Em Trânsito', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length, color: 'text-emerald-600', bg: 'bg-emerald-50' },
          ].map((stat, i) => (
            <div key={i} className={`${stat.bg} p-5 rounded-[1.5rem] border border-slate-100 shadow-sm`}>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{stat.label}</p>
              <p className={`text-2xl font-black ${stat.color} tracking-tight`}>{stat.count}</p>
            </div>
          ))}
        </div>
        <button 
          onClick={() => setShowDirectOrderModal(true)}
          className="w-full lg:w-auto bg-slate-900 hover:bg-black text-white px-8 py-5 rounded-2xl font-black shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-[10px] transition-all"
        >
          <Plus className="w-5 h-5" /> Nova Ordem de Compra
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Protocolo</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipamento</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Destinatário</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Workflow</th>
                <th className="px-6 py-5 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item) => (
                <tr 
                  key={`${item.request.id}-${item.index}`} 
                  className="hover:bg-slate-50/50 transition-colors group cursor-pointer" 
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                >
                  <td className="px-6 py-6 font-mono text-xs font-bold text-slate-400">{item.request.id}</td>
                  <td className="px-6 py-6 font-bold text-slate-800">{item.fulfillment.type}</td>
                  <td className="px-6 py-6">
                    <span className="text-sm font-bold text-slate-700">{getEmployeeName(item.request.employeeId)}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                      (item.fulfillment.purchaseStatus || 'Pendente') === 'Pendente' ? 'bg-amber-50 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Cotação Aprovada' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                      item.fulfillment.purchaseStatus === 'Pedido Autorizado' ? 'bg-indigo-50 text-indigo-600 border-indigo-200' : 'bg-emerald-50 text-emerald-600 border-emerald-200'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
