  photos: string[];
  status: AssetStatus;
  assignedTo?: string; 
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; 
  purchaseValue?: number; // Novo campo para valor de aquisição
}

export interface Employee {
  id: string;
  departmentId: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
  isActive?: boolean;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance'
  | 'accounting';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string;
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'maintenance' | 'delivery' | 'alert';
