import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import AccountingManager from './components/AccountingManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { 
  Asset, Employee, EquipmentRequest, UserAccount, 
  Department, AuditSession, AppNotification, AccountingAccount, 
  AccountingClassification, AssetTypeConfig 
} from './types';
import { db, supabase } from './services/supabase';
import { Loader2, Package, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [isOffline, setIsOffline] = useState(false);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Estados Contábeis
  const [accountingAccounts, setAccountingAccounts] = useState<AccountingAccount[]>([]);
  const [accountingClassifications, setAccountingClassifications] = useState<AccountingClassification[]>([]);
  const [assetTypeConfigs, setAssetTypeConfigs] = useState<AssetTypeConfig[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const results = await Promise.allSettled([
        db.departments.list(),
        db.assets.list(),
        db.employees.list(),
        db.requests.list(),
        db.auditSessions.list(),
        db.users.list(),
        db.notifications.list(),
        db.accountingAccounts.list(),
        db.accountingClassifications.list(),
        db.assetTypeConfigs.list()
      ]);

      const [
        depts, assts, emps, reqs, audits, userList, 
        notifs, accAccounts, accClass, assetConfigs
      ] = results.map(r => r.status === 'fulfilled' ? (r.value || []) : []);

      if (results.every(r => r.status === 'rejected')) setIsOffline(true);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);
      setAccountingAccounts(accAccounts);
      setAccountingClassifications(accClass);
      setAssetTypeConfigs(assetConfigs);

      const finalUsers = userList && userList.length > 0 ? [...userList] : [...MOCK_USERS];
      if (!finalUsers.find(u => u.username === 'admin')) {
        finalUsers.push(MOCK_USERS[0]);
      }
      setUsers(finalUsers);
      setNotifications(notifs);

    } catch (err: any) {
      console.error("Erro no carregamento:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    loadData(); 
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications' },
        (payload) => {
          const newNotif = payload.new as AppNotification;
          setNotifications(prev => {
            if (!prev) return [newNotif];
            if (prev.find(n => n.id === newNotif.id)) return prev;
            return [newNotif, ...prev].slice(0, 50);
          });
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => {
    const newNotif: AppNotification = {
      ...notif,
      id: `NTF-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      isRead: false
    };
    setNotifications(prev => [newNotif, ...(prev || [])].slice(0, 50));
    try { await db.notifications.upsert(newNotif); } catch (e) {}
  };

  const markNotificationAsRead = async (id: string) => {
    const target = notifications.find(n => n.id === id);
    if (!target) return;
    const updated = { ...target, isRead: true };
    setNotifications(prev => (prev || []).map(n => n.id === id ? updated : n));
    try { await db.notifications.upsert(updated); } catch (e) {}
  };

  const clearNotifications = async () => {
    setNotifications([]);
    try { await db.notifications.clearAll(); } catch (e) {}
  };

  const handleLogin = async (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules && user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    let finalId = assetData.id?.trim();
    let finalTagId = assetData.tagId?.trim();

    if (!finalId) {
       const randomSuffix = Math.floor(1000 + Math.random() * 9000);
       finalId = `AST-${randomSuffix}`;
       while(assets.some(a => a.id === finalId)) {
         finalId = `AST-${Math.floor(1000 + Math.random() * 9000)}`;
       }
       // Se ID for automático, mantemos a etiqueta manual se existir, senão pode ficar vazia
    } else {
       // Se ID for manual, copiamos o ID para a etiqueta conforme requisito
       finalTagId = finalId;
    }

    const newAsset: Asset = { 
      ...assetData, 
      id: finalId, 
      tagId: finalTagId,
      qrCode: `QR-${finalId}`,
      createdAt: new Date().toISOString(),
      history: assetData.history || [{
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: `Patrimônio registrado no sistema (ID Automático: ${!assetData.id ? 'Sim' : 'Não'}). Etiqueta: ${finalTagId || 'N/A'}.`,
        performedBy: currentUser?.name || 'Sistema'
      }],
      observations: assetData.observations || ''
    };
    await db.assets.upsert(newAsset);
    setAssets(prev => [newAsset, ...(prev || [])]);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    const oldAsset = assets.find(a => a.id === updated.id);
    let finalAsset = { ...updated };

    // LÓGICA DE PROTEÇÃO DE STATUS CRÍTICO
    if (finalAsset.status === 'Baixado') {
      // Se for baixa, limpa obrigatoriamente vínculos para evitar erros de integridade e inconsistência visual
      finalAsset.assignedTo = undefined;
      // Mantemos o departmentId apenas se for necessário para histórico de custos, 
      // mas geralmente ativos baixados saem do centro de custo.
    } else if (finalAsset.status === 'Manutenção') {
      // Se estiver em manutenção, mantemos o status manual vindo do componente
    } else {
      // Lógica automática para outros estados
      if (finalAsset.assignedTo) {
        finalAsset.status = 'Em Uso';
        const emp = employees.find(e => e.id === finalAsset.assignedTo);
        if (emp) finalAsset.departmentId = emp.departmentId;
      } else if (finalAsset.status === 'Em Uso' || (oldAsset?.assignedTo && !finalAsset.assignedTo)) {
        finalAsset.status = 'Disponível';
      }
    }

    try {
      console.log(`[AssetUpdate] Persistindo ${finalAsset.id} com status ${finalAsset.status}`);
      await db.assets.upsert(finalAsset);
      setAssets(prev => {
        const next = (prev || []).map(a => a.id === finalAsset.id ? { ...finalAsset } : a);
        return [...next];
      });
    } catch (err: any) {
      console.error("Falha ao atualizar ativo no Supabase:", err);
      throw err;
    }
  };

  const handleRemoveAsset = async (id: string) => {
    await db.assets.remove(id);
    setAssets(prev => (prev || []).filter(a => a.id !== id));
  };

  const handleAddRequest = async (reqData: any): Promise<void> => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;

    // CORREÇÃO CRÍTICA: Se employeeId for string vazia, converte para null.
    // Isso evita o erro de chave estrangeira no banco de dados.
    const sanitizedData = { ...reqData };
    if (sanitizedData.employeeId === '') {
      sanitizedData.employeeId = null;
    }

    const newReq: EquipmentRequest = { ...sanitizedData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...(prev || [])]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => (prev || []).map(r => r.id === req.id ? req : r));

    if (req.status === 'Entregue' && req.employeeId) {
      const employee = employees.find(e => e.id === req.employeeId);
      if (!employee) return;

      const assetsToUpdate: Asset[] = [];

      req.itemFulfillments?.forEach(f => {
        if (f.linkedAssetId) {
          const asset = assets.find(a => a.id === f.linkedAssetId);
          if (asset) {
            assetsToUpdate.push({
              ...asset,
              status: 'Em Uso',
              assignedTo: employee.id,
              departmentId: employee.departmentId,
              history: [
                ...(asset.history || []),
                {
                  id: Math.random().toString(),
                  date: new Date().toISOString(),
                  type: 'Atribuição',
                  description: `Ativo entregue ao colaborador ${employee.name} via Requisição ${req.id}.`,
                  performedBy: currentUser?.name || 'Sistema'
                }
              ]
            });
          }
        }
      });

      if (assetsToUpdate.length > 0) {
        for (const asset of assetsToUpdate) {
          await db.assets.upsert(asset);
        }
        setAssets(prev => {
          const newAssets = [...prev];
          assetsToUpdate.forEach(updated => {
            const idx = newAssets.findIndex(a => a.id === updated.id);
            if (idx !== -1) newAssets[idx] = updated;
          });
          return newAssets;
        });

        addNotification({
          title: 'Patrimônio Atualizado',
          message: `${assetsToUpdate.length} item(ns) movidos para posse de ${employee.name}.`,
          type: 'delivery',
          targetModule: 'assets'
        });
      }
    }
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => (prev || []).filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => (prev || []).map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">AssetTrack Pro: Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = (employees || []).filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800 animate-bounce">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">O sistema está em modo de contingência offline (Local Storage).</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard 
              assets={assets} 
              requests={requests} 
              employees={employees} 
              assetTypeConfigs={assetTypeConfigs}
              classifications={accountingClassifications}
            />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} assetTypeConfigs={assetTypeConfigs} classifications={accountingClassifications} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={async (id) => { 
                setEmployees(prev => {
                  const target = prev.find(e => e.id === id);
                  if (!target) return prev;
                  const updatedEmployee = { ...target, isActive: false };
                  db.employees.upsert(updatedEmployee);
                  return prev.map(e => e.id === id ? updatedEmployee : e);
                });
              }}
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
              assetTypeConfigs={assetTypeConfigs}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} assetTypeConfigs={assetTypeConfigs} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                await db.users.upsert(newU); 
                setUsers(prev => [...prev, newU]); 
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          case 'accounting':
            return <AccountingManager 
              accounts={accountingAccounts}
              classifications={accountingClassifications}
              assetTypes={assetTypeConfigs}
              onAddAccount={async (a) => { const newA = {...a, id: `ACC-${Date.now()}`}; await db.accountingAccounts.upsert(newA); setAccountingAccounts(prev => [...prev, newA]); }}
              onUpdateAccount={async (a) => { await db.accountingAccounts.upsert(a); setAccountingAccounts(prev => prev.map(old => old.id === a.id ? a : old)); }}
              onRemoveAccount={async (id) => { await db.accountingAccounts.remove(id); setAccountingAccounts(prev => prev.filter(a => a.id !== id)); }}
              onAddClassification={async (c) => { const newC = {...c, id: `CLS-${Date.now()}`}; await db.accountingClassifications.upsert(newC); setAccountingClassifications(prev => [...prev, newC]); }}
              onUpdateClassification={async (c) => { await db.accountingClassifications.upsert(c); setAccountingClassifications(prev => prev.map(old => old.id === c.id ? c : old)); }}
              onRemoveClassification={async (id) => { await db.accountingClassifications.remove(id); setAccountingClassifications(prev => prev.filter(c => c.id !== id)); }}
              onAddAssetType={async (t) => { const newT = {...t, id: `TYPE-${Date.now()}`}; await db.assetTypeConfigs.upsert(newT); setAssetTypeConfigs(prev => [...prev, newT]); }}
              onUpdateAssetType={async (t) => { await db.assetTypeConfigs.upsert(t); setAssetTypeConfigs(prev => prev.map(old => old.id === t.id ? t : old)); }}
              onRemoveAssetType={async (id) => { await db.assetTypeConfigs.remove(id); setAssetTypeConfigs(prev => prev.filter(t => t.id !== id)); }}
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import AccountingManager from './components/AccountingManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { 
  Asset, Employee, EquipmentRequest, UserAccount, 
  Department, AuditSession, AppNotification, AccountingAccount, 
  AccountingClassification, AssetTypeConfig, HistoryEntry 
} from './types';
import { db, supabase } from './services/supabase';
import { Loader2, Package, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [isOffline, setIsOffline] = useState(false);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Estados Contábeis
  const [accountingAccounts, setAccountingAccounts] = useState<AccountingAccount[]>([]);
  const [accountingClassifications, setAccountingClassifications] = useState<AccountingClassification[]>([]);
  const [assetTypeConfigs, setAssetTypeConfigs] = useState<AssetTypeConfig[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const results = await Promise.allSettled([
        db.departments.list(),
        db.assets.list(),
        db.employees.list(),
        db.requests.list(),
        db.auditSessions.list(),
        db.users.list(),
        db.notifications.list(),
        db.accountingAccounts.list(),
        db.accountingClassifications.list(),
        db.assetTypeConfigs.list()
      ]);

      const [
        depts, assts, emps, reqs, audits, userList, 
        notifs, accAccounts, accClass, assetConfigs
      ] = results.map(r => r.status === 'fulfilled' ? (r.value || []) : []);

      if (results.every(r => r.status === 'rejected')) setIsOffline(true);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);
      setAccountingAccounts(accAccounts);
      setAccountingClassifications(accClass);
      setAssetTypeConfigs(assetConfigs);

      const finalUsers = userList && userList.length > 0 ? [...userList] : [...MOCK_USERS];
      if (!finalUsers.find(u => u.username === 'admin')) {
        finalUsers.push(MOCK_USERS[0]);
      }
      setUsers(finalUsers);
      setNotifications(notifs);

    } catch (err: any) {
      console.error("Erro no carregamento:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    loadData(); 
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications' },
        (payload) => {
          const newNotif = payload.new as AppNotification;
          setNotifications(prev => {
            if (!prev) return [newNotif];
            if (prev.find(n => n.id === newNotif.id)) return prev;
            return [newNotif, ...prev].slice(0, 50);
          });
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => {
    const newNotif: AppNotification = {
      ...notif,
      id: `NTF-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      isRead: false
    };
    setNotifications(prev => [newNotif, ...(prev || [])].slice(0, 50));
    try { await db.notifications.upsert(newNotif); } catch (e) {}
  };

  const markNotificationAsRead = async (id: string) => {
    const target = notifications.find(n => n.id === id);
    if (!target) return;
    const updated = { ...target, isRead: true };
    setNotifications(prev => (prev || []).map(n => n.id === id ? updated : n));
    try { await db.notifications.upsert(updated); } catch (e) {}
  };

  const clearNotifications = async () => {
    setNotifications([]);
    try { await db.notifications.clearAll(); } catch (e) {}
  };

  const handleLogin = async (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules && user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    let finalId = assetData.id?.trim();
    let finalTagId = assetData.tagId?.trim();

    if (!finalId) {
       const randomSuffix = Math.floor(1000 + Math.random() * 9000);
       finalId = `AST-${randomSuffix}`;
       while(assets.some(a => a.id === finalId)) {
         finalId = `AST-${Math.floor(1000 + Math.random() * 9000)}`;
       }
       // Se ID for automático, mantemos a etiqueta manual se existir, senão pode ficar vazia
    } else {
       // Se ID for manual, copiamos o ID para a etiqueta conforme requisito
       finalTagId = finalId;
    }

    const newAsset: Asset = { 
      ...assetData, 
      id: finalId, 
      tagId: finalTagId,
      qrCode: `QR-${finalId}`,
      createdAt: new Date().toISOString(),
      history: assetData.history || [{
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: `Patrimônio registrado no sistema (ID Automático: ${!assetData.id ? 'Sim' : 'Não'}). Etiqueta: ${finalTagId || 'N/A'}.`,
        performedBy: currentUser?.name || 'Sistema'
      }],
      observations: assetData.observations || ''
    };
    await db.assets.upsert(newAsset);
    setAssets(prev => [newAsset, ...(prev || [])]);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    const oldAsset = assets.find(a => a.id === updated.id);
    let finalAsset = { ...updated };

    // LÓGICA DE PROTEÇÃO DE STATUS CRÍTICO
    if (finalAsset.status === 'Baixado') {
      // Se for baixa, limpa obrigatoriamente vínculos para evitar erros de integridade e inconsistência visual
      finalAsset.assignedTo = undefined;
      // Mantemos o departmentId apenas se for necessário para histórico de custos, 
      // mas geralmente ativos baixados saem do centro de custo.
    } else if (finalAsset.status === 'Manutenção') {
      // Se estiver em manutenção, mantemos o status manual vindo do componente
    } else {
      // Lógica automática para outros estados
      if (finalAsset.assignedTo) {
        finalAsset.status = 'Em Uso';
        const emp = employees.find(e => e.id === finalAsset.assignedTo);
        if (emp) finalAsset.departmentId = emp.departmentId;
      } else if (finalAsset.status === 'Em Uso' || (oldAsset?.assignedTo && !finalAsset.assignedTo)) {
        finalAsset.status = 'Disponível';
      }
    }

    try {
      console.log(`[AssetUpdate] Persistindo ${finalAsset.id} com status ${finalAsset.status}`);
      await db.assets.upsert(finalAsset);
      setAssets(prev => {
        const next = (prev || []).map(a => a.id === finalAsset.id ? { ...finalAsset } : a);
        return [...next];
      });
    } catch (err: any) {
      console.error("Falha ao atualizar ativo no Supabase:", err);
      throw err;
    }
  };

  const handleRemoveAsset = async (id: string) => {
    await db.assets.remove(id);
    setAssets(prev => (prev || []).filter(a => a.id !== id));
  };

  // --- LÓGICA DE INATIVAÇÃO DE COLABORADOR E DESVINCULAÇÃO ---
  const handleRemoveEmployee = async (id: string) => {
    const target = employees.find(e => e.id === id);
    if (!target) return;

    // 1. Inativar Colaborador
    const updatedEmployee = { ...target, isActive: false };
    await db.employees.upsert(updatedEmployee);
    setEmployees(prev => prev.map(e => e.id === id ? updatedEmployee : e));

    // 2. Localizar Ativos Vinculados
    const linkedAssets = assets.filter(a => a.assignedTo === id);

    // 3. Desvincular Ativos e Retornar ao Estoque
    if (linkedAssets.length > 0) {
      const updatedAssets: Asset[] = [];

      for (const asset of linkedAssets) {
        const newHistoryEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Status',
          description: `Devolução Automática: Colaborador ${target.name} foi inativado.`,
          performedBy: currentUser?.name || 'Sistema'
        };

        const updatedAsset: Asset = {
          ...asset,
          assignedTo: undefined, // Remove o vínculo
          status: 'Disponível', // Retorna para estoque/disponível
          history: [...(asset.history || []), newHistoryEntry]
        };

        await db.assets.upsert(updatedAsset);
        updatedAssets.push(updatedAsset);
      }

      // Atualiza estado local dos ativos
      setAssets(prev => prev.map(a => {
        const updated = updatedAssets.find(u => u.id === a.id);
        return updated || a;
      }));

      addNotification({
        title: 'Colaborador Inativado',
        message: `${target.name} foi inativado. ${updatedAssets.length} ativos foram desvinculados e estão disponíveis.`,
        type: 'info',
        targetModule: 'assets'
      });
    }
  };

  const handleAddRequest = async (reqData: any): Promise<void> => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const sanitizedData = { ...reqData };
    if (sanitizedData.employeeId === '') {
      sanitizedData.employeeId = null;
    }

    const newReq: EquipmentRequest = { ...sanitizedData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...(prev || [])]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => (prev || []).map(r => r.id === req.id ? req : r));

    if (req.status === 'Entregue' && req.employeeId) {
      const employee = employees.find(e => e.id === req.employeeId);
      if (!employee) return;

      const assetsToUpdate: Asset[] = [];

      req.itemFulfillments?.forEach(f => {
        if (f.linkedAssetId) {
          const asset = assets.find(a => a.id === f.linkedAssetId);
          if (asset) {
            assetsToUpdate.push({
              ...asset,
              status: 'Em Uso',
              assignedTo: employee.id,
              departmentId: employee.departmentId,
              history: [
                ...(asset.history || []),
                {
                  id: Math.random().toString(),
                  date: new Date().toISOString(),
                  type: 'Atribuição',
                  description: `Ativo entregue ao colaborador ${employee.name} via Requisição ${req.id}.`,
                  performedBy: currentUser?.name || 'Sistema'
                }
              ]
            });
          }
        }
      });

      if (assetsToUpdate.length > 0) {
        for (const asset of assetsToUpdate) {
          await db.assets.upsert(asset);
        }
        setAssets(prev => {
          const newAssets = [...prev];
          assetsToUpdate.forEach(updated => {
            const idx = newAssets.findIndex(a => a.id === updated.id);
            if (idx !== -1) newAssets[idx] = updated;
          });
          return newAssets;
        });

        addNotification({
          title: 'Patrimônio Atualizado',
          message: `${assetsToUpdate.length} item(ns) movidos para posse de ${employee.name}.`,
          type: 'delivery',
          targetModule: 'assets'
        });
      }
    }
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => (prev || []).filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => (prev || []).map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">AssetTrack Pro: Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = (employees || []).filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800 animate-bounce">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">O sistema está em modo de contingência offline (Local Storage).</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard 
              assets={assets} 
              requests={requests} 
              employees={employees} // Passamos todos para resolver nomes, o filtro é interno
              assetTypeConfigs={assetTypeConfigs}
              classifications={accountingClassifications}
            />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} assetTypeConfigs={assetTypeConfigs} classifications={accountingClassifications} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={handleRemoveEmployee} // Usa a nova lógica de desvinculação
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
              assetTypeConfigs={assetTypeConfigs}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} assetTypeConfigs={assetTypeConfigs} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                await db.users.upsert(newU); 
                setUsers(prev => [...prev, newU]); 
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          case 'accounting':
            return <AccountingManager 
              accounts={accountingAccounts}
              classifications={accountingClassifications}
              assetTypes={assetTypeConfigs}
              onAddAccount={async (a) => { const newA = {...a, id: `ACC-${Date.now()}`}; await db.accountingAccounts.upsert(newA); setAccountingAccounts(prev => [...prev, newA]); }}
              onUpdateAccount={async (a) => { await db.accountingAccounts.upsert(a); setAccountingAccounts(prev => prev.map(old => old.id === a.id ? a : old)); }}
              onRemoveAccount={async (id) => { await db.accountingAccounts.remove(id); setAccountingAccounts(prev => prev.filter(a => a.id !== id)); }}
              onAddClassification={async (c) => { const newC = {...c, id: `CLS-${Date.now()}`}; await db.accountingClassifications.upsert(newC); setAccountingClassifications(prev => [...prev, newC]); }}
              onUpdateClassification={async (c) => { await db.accountingClassifications.upsert(c); setAccountingClassifications(prev => prev.map(old => old.id === c.id ? c : old)); }}
              onRemoveClassification={async (id) => { await db.accountingClassifications.remove(id); setAccountingClassifications(prev => prev.filter(c => c.id !== id)); }}
              onAddAssetType={async (t) => { const newT = {...t, id: `TYPE-${Date.now()}`}; await db.assetTypeConfigs.upsert(newT); setAssetTypeConfigs(prev => [...prev, newT]); }}
              onUpdateAssetType={async (t) => { await db.assetTypeConfigs.upsert(t); setAssetTypeConfigs(prev => prev.map(old => old.id === t.id ? t : old)); }}
              onRemoveAssetType={async (id) => { await db.assetTypeConfigs.remove(id); setAssetTypeConfigs(prev => prev.filter(t => t.id !== id)); }}
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { 
  ShieldCheck, 
  Activity, 
  AlertTriangle, 
  Layers,
  Truck,
  ArrowRight,
  Package,
  X,
  User,
  Archive,
  Info
} from 'lucide-react';
import { Asset, EquipmentRequest, Employee, AssetTypeConfig, AccountingClassification } from '../types';

interface DashboardProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
}

const COLORS = ['#2563eb', '#059669', '#d97706', '#dc2626', '#4f46e5'];

type DetailType = 'total' | 'in-use' | 'maintenance' | 'retired' | null;

const Dashboard: React.FC<DashboardProps> = ({ assets, requests, employees, assetTypeConfigs, classifications }) => {
  const [selectedDetail, setSelectedDetail] = useState<DetailType>(null);

  const today = new Date().toISOString().split('T')[0];

  // 1. Filtra ativos válidos: Normalização de texto (trim + lowercase) para evitar sumiço por Case Sensitive
  const validAssets = useMemo(() => {
    if (assetTypeConfigs.length === 0) return assets; 

    // Cria lista normalizada de tipos permitidos
    const validTypes = assetTypeConfigs.map(c => c.name.toLowerCase().trim());

    return assets.filter(a => {
      if (!a.type) return false;
      // Normaliza tipo do ativo para comparação
      return validTypes.includes(a.type.toLowerCase().trim());
    });
  }, [assets, assetTypeConfigs]);

  // 2. Filtra frota ativa (exclui baixados)
  const activeAssets = useMemo(() => validAssets.filter(a => a.status !== 'Baixado'), [validAssets]);

  const todayDeliveries = useMemo(() => {
    const deliveries: any[] = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach(f => {
        if (f.purchaseStatus === 'Comprado' && !f.isDelivered && f.deliveryForecastDate === today) {
          const emp = employees.find(e => e.id === req.employeeId);
          deliveries.push({
            id: req.id,
            item: f.type,
            employeeName: emp?.name || 'N/A',
            sector: emp?.sector || 'N/A'
          });
        }
      });
    });
    return deliveries;
  }, [requests, employees, today]);

  const stats = [
    { id: 'total' as DetailType, label: 'Ativos Operacionais', value: activeAssets.length, icon: Layers, color: 'text-blue-700', bg: 'bg-blue-100' },
    { id: 'in-use' as DetailType, label: 'Em Uso', value: validAssets.filter(a => a.status === 'Em Uso').length, icon: ShieldCheck, color: 'text-emerald-700', bg: 'bg-emerald-100' },
    { id: 'maintenance' as DetailType, label: 'Em Manutenção', value: validAssets.filter(a => a.status === 'Manutenção').length, icon: Activity, color: 'text-amber-700', bg: 'bg-amber-100' },
    { id: 'retired' as DetailType, label: 'Baixados / Sucata', value: validAssets.filter(a => a.status === 'Baixado').length, icon: AlertTriangle, color: 'text-rose-700', bg: 'bg-rose-100' },
  ];

  // Gera dados dinâmicos baseados na configuração contábil
  const chartData = useMemo(() => {
    return assetTypeConfigs.map(config => {
      // Comparação normalizada no count também
      const count = activeAssets.filter(a => a.type.toLowerCase().trim() === config.name.toLowerCase().trim()).length;
      const classification = classifications.find(c => c.id === config.classificationId);

      return {
        name: config.name,
        qty: count,
        classificationName: classification?.name || 'Sem Classificação'
      };
    })
    .filter(item => item.qty > 0)
    .sort((a, b) => b.qty - a.qty);
  }, [activeAssets, assetTypeConfigs, classifications]);

  const statusData = [
    { name: 'Disponível', value: activeAssets.filter(a => a.status === 'Disponível').length },
    { name: 'Em Uso', value: activeAssets.filter(a => a.status === 'Em Uso').length },
    { name: 'Manutenção', value: activeAssets.filter(a => a.status === 'Manutenção').length },
    { name: 'Pendente Doc', value: activeAssets.filter(a => a.status === 'Pendente Documentos').length },
  ];

  const assetsGroupedByEmployee = useMemo(() => {
    const inUseAssets = validAssets.filter(a => a.status === 'Em Uso' && a.assignedTo);
    const groups: Record<string, Asset[]> = {};

    inUseAssets.forEach(asset => {
      const empId = asset.assignedTo!;
      const emp = employees.find(e => e.id === empId);

      // FILTRO CRÍTICO: Só inclui no dashboard se o funcionário existir E estiver ATIVO
      if (emp && emp.isActive !== false) {
        if (!groups[empId]) groups[empId] = [];
        groups[empId].push(asset);
      }
    });

    return Object.entries(groups).map(([empId, items]) => ({
      employee: employees.find(e => e.id === empId),
      items
    }));
  }, [validAssets, employees]);

  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {todayDeliveries.length > 0 && (
        <div className="bg-white border-2 border-emerald-500 rounded-[2.5rem] p-8 shadow-xl shadow-emerald-50 overflow-hidden relative">
           <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-6 text-center md:text-left">
                 <div className="w-16 h-16 bg-emerald-500 rounded-[2rem] flex items-center justify-center text-white shadow-lg shadow-emerald-200 shrink-0 animate-bounce">
                    <Truck className="w-8 h-8" />
                 </div>
                 <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Entregas de Hoje</h3>
                    <p className="text-slate-600 font-semibold">Temos {todayDeliveries.length} {todayDeliveries.length === 1 ? 'equipamento chegando' : 'equipamentos chegando'} ao escritório hoje.</p>
                 </div>
              </div>
              <div className="flex flex-wrap gap-3">
                 {todayDeliveries.slice(0, 3).map((d, i) => (
                   <div key={i} className="bg-emerald-50 border border-emerald-200 px-4 py-3 rounded-2xl flex items-center gap-3">
                      <Package className="w-4 h-4 text-emerald-700" />
                      <div>
                        <p className="text-[10px] font-black uppercase text-emerald-700 leading-none">{String(d.item || 'Item')}</p>
                        <p className="text-xs font-bold text-slate-800">{String(d.employeeName || 'N/A')}</p>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div 
            key={idx} 
            onClick={() => setSelectedDetail(stat.id)}
            className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group cursor-pointer active:scale-95"
          >
            <div className="flex items-center justify-between mb-4">
              <div className={`${stat.bg} ${stat.color} p-4 rounded-2xl group-hover:bg-slate-900 group-hover:text-white transition-all`}>
                <stat.icon className="w-6 h-6" />
              </div>
              <span className="text-3xl font-black text-slate-900 tracking-tighter">{stat.value}</span>
            </div>
            <div className="flex items-center justify-between">
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{stat.label}</p>
              <ArrowRight className="w-4 h-4 text-slate-400 group-hover:text-blue-600 transform group-hover:translate-x-1 transition-all" />
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Ativos por Classificação Contábil (Cadastrados)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                <Tooltip 
                  cursor={{fill: '#f1f5f9'}}
                  contentStyle={{borderRadius: '16px', border: '1px solid #e2e8f0', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="qty" fill="#2563eb" radius={[8, 8, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Status Operacional</h3>
          <div className="h-72 flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={70}
                  outerRadius={100}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                   contentStyle={{borderRadius: '16px', border: '1px solid #e2e8f0', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex flex-col gap-3 ml-8">
              {statusData.map((entry, idx) => (
                <div key={idx} className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[idx % COLORS.length]}} />
                  <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{entry.name}</span>
                  <span className="text-xs font-black text-slate-900 ml-auto">{entry.value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {selectedDetail && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-xl">
                       {selectedDetail === 'total' && <Layers className="w-7 h-7" />}
                       {selectedDetail === 'in-use' && <ShieldCheck className="w-7 h-7" />}
                       {selectedDetail === 'maintenance' && <Activity className="w-7 h-7" />}
                       {selectedDetail === 'retired' && <AlertTriangle className="w-7 h-7" />}
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">
                          {selectedDetail === 'total' && 'Relatório de Ativos Operacionais'}
                          {selectedDetail === 'in-use' && 'Ativos Alocados'}
                          {selectedDetail === 'maintenance' && 'Centro de Manutenção'}
                          {selectedDetail === 'retired' && 'Arquivo de Baixas'}
                       </h3>
                       <p className="text-slate-600 text-sm font-black uppercase tracking-widest text-[10px]">Visão Analítica para Diretoria</p>
                    </div>
                 </div>
                 <button 
                  onClick={() => setSelectedDetail(null)}
                  className="p-3 hover:bg-slate-200 rounded-full transition-colors text-slate-500 hover:text-slate-900"
                 >
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-white">
                {selectedDetail === 'total' && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {chartData.map((item, idx) => (
                      <div key={idx} className="bg-slate-50 p-6 rounded-3xl border border-slate-200 flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all">
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-blue-100 text-blue-700 rounded-2xl flex items-center justify-center font-black">
                             {item.name.charAt(0)}
                          </div>
                          <div>
                            <p className="font-black text-slate-900">{item.name}</p>
                            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tight">{item.classificationName}</p>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className="text-3xl font-black text-slate-900">{item.qty}</p>
                          <p className="text-[10px] font-black text-blue-700 uppercase">Unidades</p>
                        </div>
                      </div>
                    ))}
                    {chartData.length === 0 && (
                      <div className="col-span-full py-10 text-center text-slate-400 font-bold uppercase text-xs">
                         Nenhum tipo de ativo corretamente configurado com inventário.
                      </div>
                    )}
                  </div>
                )}

                {selectedDetail === 'in-use' && (
                  <div className="space-y-6">
                    {assetsGroupedByEmployee.map((group, idx) => (
                      <div key={idx} className="bg-white border border-slate-200 rounded-[2.5rem] shadow-sm overflow-hidden">
                        <div className="bg-slate-50 p-6 border-b border-slate-200 flex items-center justify-between">
                          <div className="flex items-center gap-4">
                             <div className="w-12 h-12 bg-white rounded-full border border-slate-300 flex items-center justify-center text-slate-500">
                                <User className="w-6 h-6" />
                             </div>
                             <div>
                                <h4 className="font-black text-slate-900">{String(group.employee?.name || 'Não Vinculado')}</h4>
                                <p className="text-xs text-slate-600 font-black uppercase tracking-widest">{String(group.employee?.sector || 'Sem Setor')}</p>
                             </div>
                          </div>
                          <span className="bg-blue-700 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-100">
                            {group.items.length} {group.items.length === 1 ? 'Ativo' : 'Ativos'}
                          </span>
                        </div>
                        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                          {group.items.map(asset => (
                            <div key={asset.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-200 flex items-center gap-3">
                               <Package className="w-5 h-5 text-slate-600" />
                               <div>
                                  <p className="text-xs font-black text-slate-900 leading-none mb-1">{String(asset.type)}</p>
                                  <p className="text-[10px] text-slate-600 font-black uppercase">{String(asset.brand)} {String(asset.model)}</p>
                                  <p className="text-[9px] text-blue-700 font-mono font-bold mt-1">ID: {asset.id}</p>
                               </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                    {assetsGroupedByEmployee.length === 0 && (
                      <div className="text-center py-20 bg-slate-50 rounded-[2.5rem] border border-dashed border-slate-300">
                         <Info className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                         <p className="text-slate-600 font-black uppercase tracking-widest">Nenhum ativo alocado em uso no momento.</p>
                      </div>
                    )}
                  </div>
                )}

                {selectedDetail === 'maintenance' && (
                  <div className="space-y-4">
                    {validAssets.filter(a => a.status === 'Manutenção').map(asset => (
                      <div key={asset.id} className="bg-white p-6 rounded-3xl border-2 border-amber-200 shadow-sm flex flex-col md:flex-row gap-6 hover:border-amber-500 transition-colors">
                        <div className="flex items-center gap-4 md:w-1/3">
                           <div className="w-16 h-16 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-700 shrink-0">
                              <Activity className="w-8 h-8" />
                           </div>
                           <div>
                              <p className="font-black text-slate-900 text-lg">{String(asset.type)}</p>
                              <p className="text-sm text-slate-600 font-black uppercase tracking-widest leading-none mb-1">{String(asset.brand)} {String(asset.model)}</p>
                              <p className="text-[10px] font-mono font-bold text-slate-500">PATRIMÔNIO: {asset.id}</p>
                           </div>
                        </div>
                        <div className="flex-1 bg-amber-50/50 p-6 rounded-2xl border border-amber-200 relative">
                           <div className="absolute -top-3 left-4 bg-amber-700 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Laudo Técnico / Motivo</div>
                           <p className="text-sm text-slate-800 font-semibold italic leading-relaxed">
                             "{String(asset.observations || 'Nenhum motivo específico detalhado no cadastro de manutenção.')}"
                           </p>
                           <div className="mt-4 flex items-center gap-2 text-[10px] font-black uppercase text-amber-700 tracking-widest">
                             <User className="w-3 h-3" /> Responsável Anterior: {getEmployeeName(asset.assignedTo)}
                           </div>
                        </div>
                      </div>
                    ))}
                    {validAssets.filter(a => a.status === 'Manutenção').length === 0 && (
                      <div className="text-center py-20 bg-slate-50 rounded-[2.5rem] border border-dashed border-slate-300">
                         <Info className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                         <p className="text-slate-600 font-black uppercase tracking-widest">Nenhum equipamento em manutenção no momento.</p>
                      </div>
                    )}
                  </div>
                )}

                {selectedDetail === 'retired' && (
                  <div className="grid grid-cols-1 gap-4">
                    {validAssets.filter(a => a.status === 'Baixado').map(asset => (
                      <div key={asset.id} className="bg-white p-6 rounded-3xl border border-slate-300 flex items-center justify-between hover:bg-rose-50/30 transition-colors group">
                        <div className="flex items-center gap-6">
                           <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 group-hover:bg-rose-100 group-hover:text-rose-700 transition-all">
                              <Archive className="w-7 h-7" />
                           </div>
                           <div>
                              <div className="flex items-center gap-3">
                                <h4 className="text-lg font-black text-slate-900">{String(asset.type)}</h4>
                                <span className="bg-rose-100 text-rose-700 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border border-rose-200">Baixado</span>
                              </div>
                              <p className="text-sm text-slate-600 font-black uppercase tracking-tighter">{String(asset.brand)} {String(asset.model)} • {asset.id}</p>
                           </div>
                        </div>
                        <div className="max-w-md text-right">
                           <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-1">Motivo da Baixa</p>
                           <p className="text-sm text-slate-800 font-semibold leading-tight">
                             {String(asset.observations || 'Sucateamento técnico por obsolescência.')}
                           </p>
                        </div>
                      </div>
                    ))}
                    {validAssets.filter(a => a.status === 'Baixado').length === 0 && (
                      <div className="text-center py-20 bg-slate-50 rounded-[2.5rem] border border-dashed border-slate-300">
                         <Archive className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                         <p className="text-slate-600 font-black uppercase tracking-widest">Nenhum equipamento baixado no histórico.</p>
                      </div>
                    )}
                  </div>
                )}
              </div>

              <div className="p-8 border-t border-slate-200 bg-slate-50 flex items-center justify-between">
                 <p className="text-xs text-slate-600 font-bold italic">Dados sincronizados em tempo real com o banco de ativos.</p>
                 <button 
                  onClick={() => setSelectedDetail(null)}
                  className="bg-slate-900 hover:bg-black text-white px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-slate-200 transition-all"
                 >
                    Fechar Relatório
                 </button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import AccountingManager from './components/AccountingManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { 
  Asset, Employee, EquipmentRequest, UserAccount, 
  Department, AuditSession, AppNotification, AccountingAccount, 
  AccountingClassification, AssetTypeConfig, HistoryEntry 
} from './types';
import { db, supabase } from './services/supabase';
import { Loader2, Package, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [isOffline, setIsOffline] = useState(false);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Estados Contábeis
  const [accountingAccounts, setAccountingAccounts] = useState<AccountingAccount[]>([]);
  const [accountingClassifications, setAccountingClassifications] = useState<AccountingClassification[]>([]);
  const [assetTypeConfigs, setAssetTypeConfigs] = useState<AssetTypeConfig[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const results = await Promise.allSettled([
        db.departments.list(),
        db.assets.list(),
        db.employees.list(),
        db.requests.list(),
        db.auditSessions.list(),
        db.users.list(),
        db.notifications.list(),
        db.accountingAccounts.list(),
        db.accountingClassifications.list(),
        db.assetTypeConfigs.list()
      ]);

      const [
        depts, assts, emps, reqs, audits, userList, 
        notifs, accAccounts, accClass, assetConfigs
      ] = results.map(r => r.status === 'fulfilled' ? (r.value || []) : []);

      if (results.every(r => r.status === 'rejected')) setIsOffline(true);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);
      setAccountingAccounts(accAccounts);
      setAccountingClassifications(accClass);
      setAssetTypeConfigs(assetConfigs);

      const finalUsers = userList && userList.length > 0 ? [...userList] : [...MOCK_USERS];
      if (!finalUsers.find(u => u.username === 'admin')) {
        finalUsers.push(MOCK_USERS[0]);
      }
      setUsers(finalUsers);
      setNotifications(notifs);

    } catch (err: any) {
      console.error("Erro no carregamento:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    loadData(); 
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications' },
        (payload) => {
          const newNotif = payload.new as AppNotification;
          setNotifications(prev => {
            if (!prev) return [newNotif];
            if (prev.find(n => n.id === newNotif.id)) return prev;
            return [newNotif, ...prev].slice(0, 50);
          });
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => {
    const newNotif: AppNotification = {
      ...notif,
      id: `NTF-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      isRead: false
    };
    setNotifications(prev => [newNotif, ...(prev || [])].slice(0, 50));
    try { await db.notifications.upsert(newNotif); } catch (e) {}
  };

  const markNotificationAsRead = async (id: string) => {
    const target = notifications.find(n => n.id === id);
    if (!target) return;
    const updated = { ...target, isRead: true };
    setNotifications(prev => (prev || []).map(n => n.id === id ? updated : n));
    try { await db.notifications.upsert(updated); } catch (e) {}
  };

  const clearNotifications = async () => {
    setNotifications([]);
    try { await db.notifications.clearAll(); } catch (e) {}
  };

  const handleLogin = async (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules && user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    let finalId = assetData.id?.trim();
    let finalTagId = assetData.tagId?.trim();

    if (!finalId) {
       const randomSuffix = Math.floor(1000 + Math.random() * 9000);
       finalId = `AST-${randomSuffix}`;
       while(assets.some(a => a.id === finalId)) {
         finalId = `AST-${Math.floor(1000 + Math.random() * 9000)}`;
       }
    } else {
       finalTagId = finalId;
    }

    const newAsset: Asset = { 
      ...assetData, 
      id: finalId, 
      tagId: finalTagId,
      qrCode: `QR-${finalId}`,
      createdAt: new Date().toISOString(),
      history: assetData.history || [{
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: `Patrimônio registrado no sistema (ID Automático: ${!assetData.id ? 'Sim' : 'Não'}). Etiqueta: ${finalTagId || 'N/A'}.`,
        performedBy: currentUser?.name || 'Sistema'
      }],
      observations: assetData.observations || ''
    };
    await db.assets.upsert(newAsset);
    setAssets(prev => [newAsset, ...(prev || [])]);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    const oldAsset = assets.find(a => a.id === updated.id);
    let finalAsset = { ...updated };

    // --- LÓGICA DE DETECÇÃO DE MUDANÇA DE RESPONSÁVEL ---
    // Se houve alteração manual no campo assignedTo no AssetManager
    if (oldAsset && oldAsset.assignedTo !== finalAsset.assignedTo) {
       const newEmp = employees.find(e => e.id === finalAsset.assignedTo);
       const oldEmp = employees.find(e => e.id === oldAsset.assignedTo);

       const historyEntry: HistoryEntry = {
          id: `HIST-MOV-${Date.now()}`,
          date: new Date().toISOString(),
          type: 'Atribuição',
          description: finalAsset.assignedTo 
            ? `Movimentação Manual: Transferido de ${oldEmp?.name || 'Estoque/Outro'} para ${newEmp?.name}`
            : `Devolução Manual: Removido de ${oldEmp?.name} para Estoque.`,
          performedBy: currentUser?.name || 'Sistema'
       };

       // Adiciona ao histórico existente
       finalAsset.history = [...(finalAsset.history || []), historyEntry];

       // Se atribuído a alguém, atualiza o departamento do ativo para o do funcionário
       if (newEmp && newEmp.departmentId) {
          finalAsset.departmentId = newEmp.departmentId;
       }
    }

    // --- LÓGICA DE STATUS ---
    if (finalAsset.status === 'Baixado') {
      finalAsset.assignedTo = undefined;
    } else if (finalAsset.status === 'Manutenção') {
       // Mantém como está
    } else {
      // Automático: Se tem dono, é 'Em Uso'. Se não tem, é 'Disponível'.
      if (finalAsset.assignedTo) {
        finalAsset.status = 'Em Uso';
      } else {
        finalAsset.status = 'Disponível';
      }
    }

    try {
      console.log(`[AssetUpdate] Persistindo ${finalAsset.id} | Status: ${finalAsset.status} | Resp: ${finalAsset.assignedTo}`);
      await db.assets.upsert(finalAsset);
      setAssets(prev => {
        const next = (prev || []).map(a => a.id === finalAsset.id ? { ...finalAsset } : a);
        return [...next];
      });
    } catch (err: any) {
      console.error("Falha ao atualizar ativo no Supabase:", err);
      throw err;
    }
  };

  const handleRemoveAsset = async (id: string) => {
    await db.assets.remove(id);
    setAssets(prev => (prev || []).filter(a => a.id !== id));
  };

  // --- LÓGICA DE INATIVAÇÃO DE COLABORADOR E DESVINCULAÇÃO ---
  const handleRemoveEmployee = async (id: string) => {
    const target = employees.find(e => e.id === id);
    if (!target) return;

    // 1. Inativar Colaborador
    const updatedEmployee = { ...target, isActive: false };
    await db.employees.upsert(updatedEmployee);
    setEmployees(prev => prev.map(e => e.id === id ? updatedEmployee : e));

    // 2. Localizar Ativos Vinculados
    const linkedAssets = assets.filter(a => a.assignedTo === id);

    // 3. Desvincular Ativos e Retornar ao Estoque
    if (linkedAssets.length > 0) {
      const updatedAssets: Asset[] = [];

      for (const asset of linkedAssets) {
        const newHistoryEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Status',
          description: `Devolução Automática: Colaborador ${target.name} foi inativado.`,
          performedBy: currentUser?.name || 'Sistema'
        };

        const updatedAsset: Asset = {
          ...asset,
          assignedTo: undefined, // Remove o vínculo
          status: 'Disponível', // Retorna para estoque/disponível
          history: [...(asset.history || []), newHistoryEntry]
        };

        await db.assets.upsert(updatedAsset);
        updatedAssets.push(updatedAsset);
      }

      // Atualiza estado local dos ativos
      setAssets(prev => prev.map(a => {
        const updated = updatedAssets.find(u => u.id === a.id);
        return updated || a;
      }));

      addNotification({
        title: 'Colaborador Inativado',
        message: `${target.name} foi inativado. ${updatedAssets.length} ativos foram desvinculados e estão disponíveis.`,
        type: 'info',
        targetModule: 'assets'
      });
    }
  };

  const handleAddRequest = async (reqData: any): Promise<void> => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const sanitizedData = { ...reqData };
    if (sanitizedData.employeeId === '') {
      sanitizedData.employeeId = null;
    }

    const newReq: EquipmentRequest = { ...sanitizedData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...(prev || [])]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => (prev || []).map(r => r.id === req.id ? req : r));

    if (req.status === 'Entregue' && req.employeeId) {
      const employee = employees.find(e => e.id === req.employeeId);
      if (!employee) return;

      const assetsToUpdate: Asset[] = [];

      req.itemFulfillments?.forEach(f => {
        if (f.linkedAssetId) {
          const asset = assets.find(a => a.id === f.linkedAssetId);
          if (asset) {
            assetsToUpdate.push({
              ...asset,
              status: 'Em Uso',
              assignedTo: employee.id,
              departmentId: employee.departmentId,
              history: [
                ...(asset.history || []),
                {
                  id: Math.random().toString(),
                  date: new Date().toISOString(),
                  type: 'Atribuição',
                  description: `Ativo entregue ao colaborador ${employee.name} via Requisição ${req.id}.`,
                  performedBy: currentUser?.name || 'Sistema'
                }
              ]
            });
          }
        }
      });

      if (assetsToUpdate.length > 0) {
        for (const asset of assetsToUpdate) {
          await db.assets.upsert(asset);
        }
        setAssets(prev => {
          const newAssets = [...prev];
          assetsToUpdate.forEach(updated => {
            const idx = newAssets.findIndex(a => a.id === updated.id);
            if (idx !== -1) newAssets[idx] = updated;
          });
          return newAssets;
        });

        addNotification({
          title: 'Patrimônio Atualizado',
          message: `${assetsToUpdate.length} item(ns) movidos para posse de ${employee.name}.`,
          type: 'delivery',
          targetModule: 'assets'
        });
      }
    }
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => (prev || []).filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => (prev || []).map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">AssetTrack Pro: Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = (employees || []).filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800 animate-bounce">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">O sistema está em modo de contingência offline (Local Storage).</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard 
              assets={assets} 
              requests={requests} 
              employees={employees} // Passamos todos para resolver nomes, o filtro é interno
              assetTypeConfigs={assetTypeConfigs}
              classifications={accountingClassifications}
            />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} assetTypeConfigs={assetTypeConfigs} classifications={accountingClassifications} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={handleRemoveEmployee} // Usa a nova lógica de desvinculação
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
              assetTypeConfigs={assetTypeConfigs}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} assetTypeConfigs={assetTypeConfigs} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                await db.users.upsert(newU); 
                setUsers(prev => [...prev, newU]); 
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          case 'accounting':
            return <AccountingManager 
              accounts={accountingAccounts}
              classifications={accountingClassifications}
              assetTypes={assetTypeConfigs}
              onAddAccount={async (a) => { const newA = {...a, id: `ACC-${Date.now()}`}; await db.accountingAccounts.upsert(newA); setAccountingAccounts(prev => [...prev, newA]); }}
              onUpdateAccount={async (a) => { await db.accountingAccounts.upsert(a); setAccountingAccounts(prev => prev.map(old => old.id === a.id ? a : old)); }}
              onRemoveAccount={async (id) => { await db.accountingAccounts.remove(id); setAccountingAccounts(prev => prev.filter(a => a.id !== id)); }}
              onAddClassification={async (c) => { const newC = {...c, id: `CLS-${Date.now()}`}; await db.accountingClassifications.upsert(newC); setAccountingClassifications(prev => [...prev, newC]); }}
              onUpdateClassification={async (c) => { await db.accountingClassifications.upsert(c); setAccountingClassifications(prev => prev.map(old => old.id === c.id ? c : old)); }}
              onRemoveClassification={async (id) => { await db.accountingClassifications.remove(id); setAccountingClassifications(prev => prev.filter(c => c.id !== id)); }}
              onAddAssetType={async (t) => { const newT = {...t, id: `TYPE-${Date.now()}`}; await db.assetTypeConfigs.upsert(newT); setAssetTypeConfigs(prev => [...prev, newT]); }}
              onUpdateAssetType={async (t) => { await db.assetTypeConfigs.upsert(t); setAssetTypeConfigs(prev => prev.map(old => old.id === t.id ? t : old)); }}
              onRemoveAssetType={async (id) => { await db.assetTypeConfigs.remove(id); setAssetTypeConfigs(prev => prev.filter(t => t.id !== id)); }}
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, 
  Search, 
  Trash2,
  X,
  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
  ShieldCheck,
  FileSpreadsheet,
  PlusCircle,
  Save,
  MessageSquarePlus,
  AlertCircle,
  Loader2,
  Building2,
  Package,
  ArrowLeftRight,
  Camera,
  ImageIcon,
  ScanBarcode,
  Edit2,
  HardDrive,
  Microchip,
  Filter,
  Eye,
  EyeOff,
  Book,
  DollarSign
} from 'lucide-react';
import { Asset, AssetType, Employee, Department, HistoryEntry, AssetStatus, AssetTypeConfig, AccountingClassification } from '../types';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string }) => Promise<void>;
  onUpdate: (asset: Asset) => Promise<void>;
  onRemove: (id: string) => Promise<void>;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, assetTypeConfigs, classifications, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showRetired, setShowRetired] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Asset>>({
    id: '',
    tagId: '',
    type: 'Notebook',
    status: 'Disponível',
    brand: '',
    model: '',
    serialNumber: '',
    observations: '',
    photos: [],
    departmentId: '',
    assignedTo: '',
    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true,
    purchaseValue: 0
  });

  useEffect(() => {
    if (companies.length > 0 && !formData.departmentId && !editingAsset) {
      setFormData(prev => ({ ...prev, departmentId: companies[0].id }));
    }
  }, [companies, showForm, editingAsset]);

  // Sincronização automática: Se ID for preenchido manualmente, copia para tagId
  useEffect(() => {
    if (formData.id && formData.id.trim() !== '') {
      setFormData(prev => ({ ...prev, tagId: prev.id }));
    }
  }, [formData.id]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const getClassificationForType = (typeName: string) => {
    const config = assetTypeConfigs.find(t => t.name === typeName);
    if (!config) return null;
    return classifications.find(c => c.id === config.classificationId);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          photos: [...(prev.photos || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removePhoto = (index: number) => {
    setFormData(prev => ({
      ...prev,
      photos: prev.photos?.filter((_, i) => i !== index)
    }));
  };

  const openEditModal = (asset: Asset) => {
    setEditingAsset(asset);
    setFormData({ ...asset, assignedTo: asset.assignedTo || '' }); // Garante que assignedTo nunca seja undefined
    setShowForm(true);
    setDetailAsset(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (editingAsset) {
        await onUpdate({ ...editingAsset, ...formData } as Asset);
      } else {
        await onAdd(formData as any);
      }
      setShowForm(false);
      resetFormData();
    } catch (err: any) {
      alert(`Erro ao salvar: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  const resetFormData = () => {
    setFormData({ 
      id: '', tagId: '', type: assetTypeConfigs[0]?.name || 'Notebook', status: 'Disponível', brand: '', model: '', serialNumber: '', 
      observations: '', photos: [], departmentId: companies[0]?.id || '', assignedTo: '',
      ram: '', storage: '', processor: '', screenSize: '', caseModel: '',
      isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, purchaseValue: 0
    });
    setEditingAsset(null);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = 
      a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (a.tagId?.toLowerCase().includes(searchTerm.toLowerCase())) ||
      a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
      a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesVisibility = showRetired ? true : a.status !== 'Baixado';
    return matchesSearch && matchesVisibility;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Filtrar por ID, Etiqueta, marca ou modelo..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button 
            onClick={() => setShowRetired(!showRetired)} 
            className={`flex items-center gap-2 px-4 py-3 text-xs font-black border rounded-2xl transition-all uppercase tracking-widest ${
              showRetired ? 'bg-rose-50 border-rose-200 text-rose-700' : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            {showRetired ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
            {showRetired ? 'Ocultar Inativos' : 'Ver Inativos'}
          </button>
          <button 
            onClick={() => { resetFormData(); setShowForm(true); }} 
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs"
          >
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">ID / Etiqueta</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo / Classificação</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Responsável</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => {
                const classification = getClassificationForType(asset.type);
                return (
                  <tr 
                    key={asset.id} 
                    onClick={() => setDetailAsset(asset)}
                    className={`hover:bg-blue-50/50 transition-colors cursor-pointer group ${asset.status === 'Baixado' ? 'bg-slate-50/50 opacity-60 grayscale' : ''}`}
                  >
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex flex-col">
                        <span className="font-black text-slate-900">{asset.id}</span>
                        <span className="text-[10px] text-blue-600 font-bold uppercase tracking-tight">TAG: {asset.tagId || 'N/A'}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex flex-col">
                        <span className="text-xs font-bold text-slate-800">{asset.type}</span>
                        {classification && (
                          <div className="flex items-center gap-1 mt-1">
                            <Book className="w-2.5 h-2.5 text-blue-500" />
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{classification.name}</span>
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="font-bold text-slate-900">{asset.brand}</span>
                      <span className="text-sm text-slate-700 ml-2">{asset.model}</span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        <User className="w-3 h-3 text-slate-400" />
                        <span className="text-xs font-bold text-slate-600">{getEmployeeName(asset.assignedTo)}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${
                        asset.status === 'Disponível' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                        asset.status === 'Em Uso' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                        asset.status === 'Manutenção' ? 'bg-amber-50 text-amber-700 border-amber-200' : 
                        asset.status === 'Baixado' ? 'bg-rose-100 text-rose-700 border-rose-300' : 'bg-slate-50 text-slate-700'
                      }`}>
                        {asset.status === 'Baixado' ? 'INATIVO' : asset.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <button 
                        onClick={(e) => { e.stopPropagation(); openEditModal(asset); }} 
                        className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                       {editingAsset ? <Edit2 className="w-7 h-7" /> : <Plus className="w-7 h-7" />}
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">
                         {editingAsset ? 'Editar Ativo' : 'Novo Registro de Ativo'}
                       </h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Inventário Técnico Enterprise</p>
                    </div>
                 </div>
                 <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-200 rounded-full transition-all">
                    <X className="w-6 h-6 text-slate-400" />
                 </button>
              </div>

              <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Patrimonial Principal (Vazio = Auto)</label>
                       <input 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-mono font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                         value={formData.id} 
                         onChange={e => setFormData({...formData, id: e.target.value})} 
                         placeholder="Ex: AST-001 (Opcional)"
                       />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Etiqueta Patrimonial Física</label>
                       <input 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-mono font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                         value={formData.tagId} 
                         onChange={e => setFormData({...formData, tagId: e.target.value})} 
                         placeholder="Ex: 05421"
                         disabled={!!(formData.id && formData.id.trim() !== '')}
                         title={!!(formData.id && formData.id.trim() !== '') ? "A etiqueta é copiada automaticamente do ID se preenchido manualmente." : ""}
                       />
                       {!!(formData.id && formData.id.trim() !== '') && (
                         <p className="text-[9px] text-blue-600 font-bold uppercase tracking-tight ml-1 animate-pulse">Sincronizado com ID Principal</p>
                       )}
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Ativo</label>
                       <select 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                         value={formData.type}
                         onChange={e => setFormData({...formData, type: e.target.value as AssetType})}
                       >
                         {assetTypeConfigs.map(t => <option key={t.id} value={t.name}>{t.name}</option>)}
                         {assetTypeConfigs.length === 0 && <option value="Notebook">Notebook</option>}
                       </select>
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Responsável Atual</label>
                       <select 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                         value={formData.assignedTo || ''}
                         onChange={e => setFormData({...formData, assignedTo: e.target.value})}
                       >
                         <option value="">Disponível (Em Estoque)</option>
                         {employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}
                       </select>
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Marca</label>
                       <input 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                         value={formData.brand}
                         onChange={e => setFormData({...formData, brand: e.target.value})}
                         placeholder="Dell, LG, etc"
                         required
                       />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Modelo</label>
                       <input 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                         value={formData.model}
                         onChange={e => setFormData({...formData, model: e.target.value})}
                         placeholder="Latitude 5420, etc"
                         required
                       />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor de Aquisição (R$)</label>
                       <input 
                         type="number"
                         step="0.01"
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-emerald-50/30 font-bold outline-none focus:ring-2 focus:ring-emerald-600"
                         value={formData.purchaseValue}
                         onChange={e => setFormData({...formData, purchaseValue: parseFloat(e.target.value)})}
                         placeholder="0,00"
                       />
                    </div>
                 </div>

                 <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100 pb-2">Especificações Técnicas</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                       <div className="space-y-1.5">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Processador</label>
                          <input className="w-full p-3 rounded-xl border border-slate-200 font-bold text-xs" value={formData.processor} onChange={e => setFormData({...formData, processor: e.target.value})} placeholder="i7, Ryzen 5..." />
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Memória RAM</label>
                          <input className="w-full p-3 rounded-xl border border-slate-200 font-bold text-xs" value={formData.ram} onChange={e => setFormData({...formData, ram: e.target.value})} placeholder="8GB, 16GB..." />
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Armazenamento</label>
                          <input className="w-full p-3 rounded-xl border border-slate-200 font-bold text-xs" value={formData.storage} onChange={e => setFormData({...formData, storage: e.target.value})} placeholder="256GB SSD..." />
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Tela</label>
                          <input className="w-full p-3 rounded-xl border border-slate-200 font-bold text-xs" value={formData.screenSize} onChange={e => setFormData({...formData, screenSize: e.target.value})} placeholder='14", 24"...' />
                       </div>
                    </div>
                 </div>

                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações / Detalhes</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-medium outline-none focus:ring-2 focus:ring-blue-600 min-h-[120px]"
                      value={formData.observations}
                      onChange={e => setFormData({...formData, observations: e.target.value})}
                      placeholder="Histórico de uso, pequenos danos, etc..."
                    />
                 </div>

                 <div className="space-y-4">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Fotos do Ativo</label>
                    <div className="flex flex-wrap gap-4">
                       {(formData.photos || []).map((photo, idx) => (
                         <div key={idx} className="relative w-24 h-24 rounded-2xl overflow-hidden border-2 border-slate-200 group">
                            <img src={photo} className="w-full h-full object-cover" />
                            <button 
                              type="button"
                              onClick={() => removePhoto(idx)}
                              className="absolute inset-0 bg-rose-600/80 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all text-white"
                            >
                               <Trash2 className="w-5 h-5" />
                            </button>
                         </div>
                       ))}
                       <button 
                         type="button" 
                         onClick={() => fileInputRef.current?.click()}
                         className="w-24 h-24 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 hover:border-blue-600 hover:text-blue-600 transition-all"
                       >
                          <Camera className="w-6 h-6 mb-1" />
                          <span className="text-[8px] font-black uppercase tracking-widest">Adicionar</span>
                       </button>
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" multiple accept="image/*" onChange={handleFileChange} />
                 </div>
              </form>

              <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                 <button 
                   type="button" 
                   onClick={() => setShowForm(false)} 
                   className="px-8 py-4 font-black text-slate-400 uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors"
                 >
                   Cancelar
                 </button>
                 <button 
                   type="submit" 
                   onClick={handleSubmit}
                   disabled={isSaving}
                   className="px-12 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-100 flex items-center gap-2 hover:bg-blue-700 transition-all disabled:bg-slate-300 disabled:shadow-none"
                 >
                   {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                   {isSaving ? 'Salvando...' : 'Salvar Registro'}
                 </button>
              </div>
           </div>
        </div>
      )}

      {detailAsset && (
        <div className="fixed inset-0 z-[150] flex items-center justify-end p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl h-full md:h-auto md:max-h-[90vh] md:rounded-[3rem] shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className={`w-14 h-14 ${detailAsset.status === 'Baixado' ? 'bg-rose-600' : 'bg-blue-600'} rounded-2xl flex items-center justify-center text-white shadow-xl`}>
                       <Tag className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">
                         {detailAsset.status === 'Baixado' ? 'Patrimônio Inativo/Baixado' : `Status: ${detailAsset.status}`}
                       </p>
                    </div>
                 </div>
                 <button onClick={() => setDetailAsset(null)} className="p-2 hover:bg-slate-200 rounded-full transition-all">
                    <X className="w-6 h-6 text-slate-400" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Responsável Atual</p>
                       <p className="font-bold text-slate-800">{getEmployeeName(detailAsset.assignedTo)}</p>
                    </div>
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Departamento</p>
                       <p className="font-bold text-slate-800">{getDepartmentName(detailAsset.departmentId)}</p>
                    </div>
                    <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100 col-span-1 md:col-span-2">
                       <p className="text-[10px] font-black text-blue-400 uppercase mb-2 tracking-widest">Etiqueta Patrimonial Física</p>
                       <div className="flex items-center gap-3">
                          <ScanBarcode className="w-6 h-6 text-blue-600" />
                          <p className="text-xl font-black text-blue-900 tracking-tight">{detailAsset.tagId || 'NÃO TAGUEADO'}</p>
                       </div>
                    </div>
                 </div>

                 {detailAsset.purchaseValue ? (
                    <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100 flex items-center justify-between">
                       <div className="flex items-center gap-3">
                          <DollarSign className="w-6 h-6 text-emerald-600" />
                          <p className="text-[10px] font-black text-emerald-800 uppercase tracking-widest">Valor de Aquisição</p>
                       </div>
                       <p className="text-xl font-black text-emerald-700">R$ {detailAsset.purchaseValue.toLocaleString('pt-BR')}</p>
                    </div>
                 ) : null}

                 <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Dossiê de Ativo / Observações</p>
                    <p className="text-sm text-slate-700 font-medium whitespace-pre-wrap leading-relaxed">
                      {detailAsset.observations || 'Nenhum detalhe técnico registrado.'}
                    </p>
                 </div>

                 <div className="space-y-6">
                    <div className="flex items-center gap-2">
                       <History className="w-5 h-5 text-blue-600" />
                       <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Linha do Tempo</h4>
                    </div>
                    <div className="relative pl-8 space-y-6 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100">
                       {(detailAsset.history || []).slice().reverse().map((entry) => (
                         <div key={entry.id} className="relative">
                            <div className={`absolute -left-[30px] top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                               entry.type === 'Status' && entry.description.includes('BAIXA') ? 'bg-rose-600' : 'bg-slate-400'
                            }`}>
                               {entry.type === 'Status' && entry.description.includes('BAIXA') ? <Trash2 className="w-3 h-3 text-white" /> : <Clock className="w-3 h-3 text-white" />}
                            </div>
                            <div className="space-y-1">
                               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(entry.date).toLocaleDateString()}</p>
                               <p className="text-sm text-slate-800 font-bold leading-tight">{entry.description}</p>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>

              <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end">
                 <button onClick={() => setDetailAsset(null)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-black transition-colors shadow-lg">Fechar</button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

