  Plus, 
  Search, 
  Trash2,
  X,
  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
  ShieldCheck,
  FileSpreadsheet,
  PlusCircle,
  Save,
  MessageSquarePlus,
  AlertCircle,
  Loader2,
  Building2,
  Package,
  ArrowLeftRight,
  Camera,
  ImageIcon,
  ScanBarcode,
  Edit2,
  HardDrive,
  Microchip,
  Filter,
  Eye,
  EyeOff,
  Book,
  DollarSign
} from 'lucide-react';
import { Asset, AssetType, Employee, Department, HistoryEntry, AssetStatus, AssetTypeConfig, AccountingClassification } from '../types';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string }) => Promise<void>;
  onUpdate: (asset: Asset) => Promise<void>;
  onRemove: (id: string) => Promise<void>;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, assetTypeConfigs, classifications, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showRetired, setShowRetired] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Asset>>({
    id: '',
    tagId: '',
    type: 'Notebook',
    status: 'Disponível',
    brand: '',
    model: '',
    serialNumber: '',
    observations: '',
    photos: [],
    departmentId: '',
    assignedTo: '',
    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true,
    purchaseValue: undefined // Alterado de 0 para undefined para indicar opcional
  });

  useEffect(() => {
    if (companies.length > 0 && !formData.departmentId && !editingAsset) {
      setFormData(prev => ({ ...prev, departmentId: companies[0].id }));
    }
  }, [companies, showForm, editingAsset]);

  // Sincronização automática: Se ID for preenchido manualmente, copia para tagId
  useEffect(() => {
    if (formData.id && formData.id.trim() !== '') {
      setFormData(prev => ({ ...prev, tagId: prev.id }));
    }
  }, [formData.id]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const getClassificationForType = (typeName: string) => {
    const config = assetTypeConfigs.find(t => t.name === typeName);
    if (!config) return null;
    return classifications.find(c => c.id === config.classificationId);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          photos: [...(prev.photos || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removePhoto = (index: number) => {
    setFormData(prev => ({
      ...prev,
      photos: prev.photos?.filter((_, i) => i !== index)
    }));
  };

  const openEditModal = (asset: Asset) => {
    setEditingAsset(asset);
    setFormData({ ...asset, assignedTo: asset.assignedTo || '' }); // Garante que assignedTo nunca seja undefined
    setShowForm(true);
    setDetailAsset(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (editingAsset) {
        await onUpdate({ ...editingAsset, ...formData } as Asset);
      } else {
        await onAdd(formData as any);
      }
      setShowForm(false);
      resetFormData();
    } catch (err: any) {
      alert(`Erro ao salvar: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  const resetFormData = () => {
    setFormData({ 
      id: '', tagId: '', type: assetTypeConfigs[0]?.name || 'Notebook', status: 'Disponível', brand: '', model: '', serialNumber: '', 
      observations: '', photos: [], departmentId: companies[0]?.id || '', assignedTo: '',
      ram: '', storage: '', processor: '', screenSize: '', caseModel: '',
      isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, purchaseValue: undefined
    });
    setEditingAsset(null);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = 
      a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (a.tagId?.toLowerCase().includes(searchTerm.toLowerCase())) ||
      a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
      a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesVisibility = showRetired ? true : a.status !== 'Baixado';
    return matchesSearch && matchesVisibility;
  });

  return (
