                         placeholder="Ex: 05421"
                         disabled={!!(formData.id && formData.id.trim() !== '')}
                         title={!!(formData.id && formData.id.trim() !== '') ? "A etiqueta é copiada automaticamente do ID se preenchido manualmente." : ""}
                       />
                       {!!(formData.id && formData.id.trim() !== '') && (
