  const [formData, setFormData] = useState<Partial<Asset>>({
    id: '',
    tagId: '',
    type: 'Notebook',
    status: 'Disponível',
    brand: '',
    model: '',
    serialNumber: '',
    observations: '',
    photos: [],
    departmentId: '',
    assignedTo: '',
    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true,
    purchaseValue: undefined 
