-- SCRIPT DE MIGRAÇÃO E CORREÇÃO - ASSETTRACK PRO
-- ============================================================

-- 1. CORREÇÃO DE ESTRUTURA (Colunas Faltantes)
-- Adiciona colunas que podem estar faltando e gerando erro 204 ou erros de salvamento.

ALTER TABLE public.assets ADD COLUMN IF NOT EXISTS "purchaseValue" NUMERIC DEFAULT NULL;
ALTER TABLE public.assets ADD COLUMN IF NOT EXISTS "serialNumber" TEXT DEFAULT NULL;
ALTER TABLE public.assets ADD COLUMN IF NOT EXISTS "tagId" TEXT DEFAULT NULL;

-- Garante que assignedTo aceite NULL (para ativos sem dono/estoque)
ALTER TABLE public.assets ALTER COLUMN "assignedTo" DROP NOT NULL;

-- 2. CORREÇÃO DE POLÍTICAS DE SEGURANÇA (RLS - Row Level Security)
-- Este bloco remove as políticas genéricas "Public Access" que geram avisos
-- e cria uma política explícita "System Access" para a aplicação.

DO $$ 
DECLARE 
    t text;
BEGIN
    FOR t IN 
        SELECT table_name FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_type = 'BASE TABLE'
    LOOP
        -- Habilita RLS na tabela
        EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', t);

        -- Remove políticas antigas que podem estar causando conflito ou avisos
        EXECUTE format('DROP POLICY IF EXISTS "Public Access" ON public.%I', t);
        EXECUTE format('DROP POLICY IF EXISTS "Public Full Access" ON public.%I', t);
        EXECUTE format('DROP POLICY IF EXISTS "System Access" ON public.%I', t);

        -- Cria nova política permitindo acesso para a API do Supabase (anon) e usuários logados
        -- Isso mantém o app funcionando (pois o controle de acesso é feito no código React),
        -- mas define explicitamente quem tem acesso, organizando o banco.
        EXECUTE format('CREATE POLICY "System Access" ON public.%I FOR ALL TO anon, authenticated, service_role USING (true) WITH CHECK (true)', t);
    END LOOP;
END $$;

-- 3. ATUALIZAÇÃO DO CACHE DA API
-- Força o Supabase a reconhecer as novas colunas e políticas imediatamente.
NOTIFY pgrst, 'reload schema';

