  }
};

import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import { Download, Database, HardDrive, ShieldCheck, Activity, Upload, Loader2, FileSpreadsheet } from 'lucide-react';
import { Asset, EquipmentRequest, Employee, Department, HistoryEntry } from '../types';
import { db } from '../services/supabase';

interface SystemInfoManagerProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  departments: Department[];
}

const SystemInfoManager: React.FC<SystemInfoManagerProps> = ({ assets, requests, employees, departments }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // --- LÓGICA DE EXPORTAÇÃO (XLSX) ---
  const handleExportSystemData = () => {
    try {
      const wb = XLSX.utils.book_new();

      // 1. Aba de Ativos
      const assetData = assets.map(a => {
        const emp = employees.find(e => e.id === a.assignedTo);
        const dept = departments.find(d => d.id === a.departmentId);
        return {
          'ID Patrimonial': a.id,
          'Etiqueta (Tag)': a.tagId,
          'Tipo': a.type,
          'Marca': a.brand,
          'Modelo': a.model,
          'Número de Série': a.serialNumber,
          'Valor de Aquisição': a.purchaseValue || 0,
          'Status': a.status,
          'Responsável Atual': emp?.name || 'Estoque',
          'Departamento': dept?.name || 'Não Vinculado',
          'Processador': a.processor,
          'RAM': a.ram,
          'Armazenamento': a.storage,
          'Observações': a.observations,
          'Data Criação': new Date(a.createdAt).toLocaleDateString()
        };
      });
      const wsAssets = XLSX.utils.json_to_sheet(assetData);
      XLSX.utils.book_append_sheet(wb, wsAssets, "Inventário Ativos");

      // 2. Aba de Colaboradores
      const employeeData = employees.map(e => {
        const dept = departments.find(d => d.id === e.departmentId);
        const assetCount = assets.filter(a => a.assignedTo === e.id).length;
        return {
          'Nome': e.name,
          'CPF': e.cpf,
          'Cargo/Função': e.role,
          'Setor/Departamento': dept?.name || e.sector,
          'Status Cadastro': e.isActive === false ? 'Inativo' : 'Ativo',
          'Qtd Ativos em Posse': assetCount
        };
      });
      const wsEmployees = XLSX.utils.json_to_sheet(employeeData);
      XLSX.utils.book_append_sheet(wb, wsEmployees, "Colaboradores");

      // 3. Aba de Requisições
      const requestData = requests.map(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        return {
          'Protocolo': r.id,
          'Status': r.status,
          'Data': new Date(r.createdAt).toLocaleDateString(),
          'Solicitante (ID)': r.requesterId,
          'Beneficiário': emp?.name || 'Estoque/Outro',
          'Itens Solicitados': r.items.join(', '),
          'Observação': r.observation
        };
      });
      const wsRequests = XLSX.utils.json_to_sheet(requestData);
      XLSX.utils.book_append_sheet(wb, wsRequests, "Requisições");

      // 4. Aba de Departamentos
      const deptData = departments.map(d => ({
        'ID': d.id,
        'Nome Departamento': d.name,
        'Centro de Custo': d.costCenter,
        'Total Ativos Vinculados': assets.filter(a => a.departmentId === d.id).length
      }));
      const wsDepts = XLSX.utils.json_to_sheet(deptData);
      XLSX.utils.book_append_sheet(wb, wsDepts, "Departamentos");

      // Salva o arquivo
      XLSX.writeFile(wb, `AssetTrack_Export_Completo_${new Date().toISOString().slice(0,10)}.xlsx`);
    } catch (error) {
      console.error("Erro na exportação:", error);
      alert("Houve um erro ao gerar o arquivo Excel.");
    }
  };

  // --- LÓGICA DE IMPORTAÇÃO (XLSX) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();

    setIsImporting(true);

    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });

        // --- 1. IMPORTAR DEPARTAMENTOS ---
        let deptMap = new Map<string, string>(); // Nome -> ID
        const wsDepts = wb.Sheets["Departamentos"];
        if (wsDepts) {
          const data: any[] = XLSX.utils.sheet_to_json(wsDepts);
          for (const row of data) {
            const id = row['ID'] || `DEPT-${Math.floor(Math.random() * 100000)}`;
            const name = row['Nome Departamento'];
            if (name) {
              const dept: Department = {
                id,
                name,
                costCenter: row['Centro de Custo'] || '',
                createdAt: new Date().toISOString()
              };
              await db.departments.upsert(dept);
              deptMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com departamentos já existentes no sistema caso não estejam na planilha
        departments.forEach(d => deptMap.set(d.name, d.id));

        // --- 2. IMPORTAR COLABORADORES ---
        let empMap = new Map<string, string>(); // Nome -> ID
        const wsEmps = wb.Sheets["Colaboradores"];
        if (wsEmps) {
          const data: any[] = XLSX.utils.sheet_to_json(wsEmps);
          for (const row of data) {
            const cpf = row['CPF'];
            const name = row['Nome'];
            if (name && cpf) {
              // Tenta encontrar colaborador existente pelo CPF para manter o ID
              const existingEmp = employees.find(e => e.cpf === cpf);
              const id = existingEmp?.id || `EMP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

              // Busca ID do departamento pelo nome
              const deptName = row['Setor/Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const emp: Employee = {
                id,
                name,
                cpf,
                role: row['Cargo/Função'] || '',
                sector: deptName || 'Geral',
                departmentId,
                isActive: row['Status Cadastro'] !== 'Inativo'
              };
              await db.employees.upsert(emp);
              empMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com colaboradores já existentes
        employees.forEach(e => empMap.set(e.name, e.id));

        // --- 3. IMPORTAR ATIVOS ---
        const wsAssets = wb.Sheets["Inventário Ativos"];
        let importedAssetsCount = 0;
        if (wsAssets) {
          const data: any[] = XLSX.utils.sheet_to_json(wsAssets);
          for (const row of data) {
            const id = row['ID Patrimonial'];
            if (id) {
              // Resolver relacionamentos
              const empName = row['Responsável Atual'];
              const assignedTo = empMap.get(empName) || undefined; // undefined se não achar ou for "Estoque"

              const deptName = row['Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              // Manter histórico existente se for atualização, ou criar novo
              const existingAsset = assets.find(a => a.id === id);
              let history = existingAsset?.history || [];

              if (!existingAsset) {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}`,
                   date: new Date().toISOString(),
                   type: 'Criação',
                   description: 'Importado via Planilha Excel',
                   performedBy: 'Sistema de Importação'
                 });
              } else {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}-${Math.random()}`,
                   date: new Date().toISOString(),
                   type: 'Observação',
                   description: 'Dados atualizados via Importação em Lote',
                   performedBy: 'Sistema de Importação'
                 });
              }

              const asset: Asset = {
                id,
                tagId: row['Etiqueta (Tag)'] || id,
                type: row['Tipo'] || 'Outros',
                brand: row['Marca'] || '',
                model: row['Modelo'] || '',
                serialNumber: row['Número de Série'] || '',
                purchaseValue: Number(row['Valor de Aquisição']) || 0,
                status: row['Status'] || 'Disponível',
                assignedTo,
                departmentId,
                processor: row['Processador'] || '',
                ram: row['RAM'] || '',
                storage: row['Armazenamento'] || '',
                observations: row['Observações'] || '',
                createdAt: existingAsset?.createdAt || new Date().toISOString(),
                qrCode: existingAsset?.qrCode || `QR-${id}`,
                photos: existingAsset?.photos || [],
                history
              };

              await db.assets.upsert(asset);
              importedAssetsCount++;
            }
          }
        }

        alert(`Importação concluída com sucesso!\n\nDados Processados:\n- Departamentos Sincronizados\n- Colaboradores Sincronizados\n- ${importedAssetsCount} Ativos Processados\n\nRecarregue a página para visualizar todas as alterações.`);

        // Limpa o input
        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (error) {
        console.error("Erro na importação:", error);
        alert("Erro crítico ao processar o arquivo. Verifique se o formato segue o modelo de exportação padrão.");
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Card de Exportação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center shadow-inner z-10">
              <Download className="w-10 h-10 text-emerald-600" />
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Exportação de Dados</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Gere um arquivo Excel (.xlsx) completo para backup ou para editar dados em massa e reimportar.
              </p>
           </div>
           <button 
            onClick={handleExportSystemData}
            className="z-10 bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Baixar Planilha Modelo
          </button>
        </div>

        {/* Card de Importação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center shadow-inner z-10">
              {isImporting ? <Loader2 className="w-10 h-10 text-blue-600 animate-spin" /> : <Upload className="w-10 h-10 text-blue-600" />}
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Importação em Lote</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Carregue a planilha preenchida para atualizar ou criar múltiplos registros de Ativos e Colaboradores.
              </p>
           </div>

           <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
           />

           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isImporting}
            className={`z-10 px-10 py-4 rounded-2xl font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95 ${
              isImporting 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-100'
            }`}
          >
            {isImporting ? 'Processando...' : 'Carregar Planilha .XLSX'}
            {!isImporting && <FileSpreadsheet className="w-5 h-5" />}
          </button>
          {isImporting && <p className="text-[10px] font-bold text-blue-600 animate-pulse">Isso pode levar alguns segundos...</p>}
        </div>
      </div>

      {/* Card de Informações do Sistema */}
      <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8">
         <div className="space-y-6 w-full md:w-auto">
            <div className="flex items-center gap-4">
               <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                  <Database className="w-8 h-8 text-white" />
               </div>
               <div>
                  <h3 className="text-2xl font-black tracking-tight">Status do Banco de Dados</h3>
                  <p className="text-blue-200 text-sm font-bold uppercase tracking-widest">Conexão Segura</p>
               </div>
            </div>

            <div className="space-y-2 pt-2">
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <ShieldCheck className="w-4 h-4 text-emerald-500" /> PostgreSQL (Supabase)
               </div>
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <Activity className="w-4 h-4 text-blue-500" /> Replicação em Tempo Real
               </div>
            </div>
         </div>

         <div className="grid grid-cols-3 gap-8 w-full md:w-auto border-t md:border-t-0 md:border-l border-slate-700 pt-8 md:pt-0 md:pl-10">
            <div className="text-center">
               <span className="block text-3xl font-black">{assets.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Ativos</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{employees.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Pessoas</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{departments.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Setores</span>
            </div>
         </div>
      </div>

      {/* Rodapé Informativo */}
      <div className="text-center py-10 opacity-50">
         <p className="text-xs font-black uppercase tracking-widest text-slate-400">AssetTrack Pro Enterprise v2.6</p>
         <p className="text-[10px] text-slate-400 mt-1">Módulo de Importação/Exportação Avançado</p>
      </div>

    </div>
  );
};

export default SystemInfoManager;

import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import { Download, Database, HardDrive, ShieldCheck, Activity, Upload, Loader2, FileSpreadsheet } from 'lucide-react';
import { Asset, EquipmentRequest, Employee, Department, HistoryEntry, AssetTypeConfig, AccountingClassification } from '../types';
import { db } from '../services/supabase';

interface SystemInfoManagerProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  departments: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
}

const SystemInfoManager: React.FC<SystemInfoManagerProps> = ({ 
  assets, 
  requests, 
  employees, 
  departments,
  assetTypeConfigs,
  classifications
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // --- LÓGICA DE EXPORTAÇÃO (XLSX) ---
  const handleExportSystemData = () => {
    try {
      const wb = XLSX.utils.book_new();

      // 1. Aba de Ativos
      const assetData = assets.map(a => {
        const emp = employees.find(e => e.id === a.assignedTo);
        const dept = departments.find(d => d.id === a.departmentId);

        // Resolve Classificação Contábil
        const config = assetTypeConfigs.find(c => c.name.toLowerCase().trim() === a.type.toLowerCase().trim());
        const classification = classifications.find(c => c.id === config?.classificationId);

        return {
          'ID Patrimonial': a.id,
          'Etiqueta (Tag)': a.tagId,
          'Tipo': a.type,
          'Classificação Contábil': classification?.name || '', // Nova coluna para facilitar a vida do usuário
          'Marca': a.brand,
          'Modelo': a.model,
          'Número de Série': a.serialNumber,
          'Valor de Aquisição': a.purchaseValue || 0,
          'Status': a.status,
          'Responsável Atual': emp?.name || 'Estoque',
          'Departamento': dept?.name || 'Não Vinculado',
          'Processador': a.processor,
          'RAM': a.ram,
          'Armazenamento': a.storage,
          'Observações': a.observations,
          'Data Criação': new Date(a.createdAt).toLocaleDateString()
        };
      });
      const wsAssets = XLSX.utils.json_to_sheet(assetData);
      XLSX.utils.book_append_sheet(wb, wsAssets, "Inventário Ativos");

      // 2. Aba de Colaboradores
      const employeeData = employees.map(e => {
        const dept = departments.find(d => d.id === e.departmentId);
        const assetCount = assets.filter(a => a.assignedTo === e.id).length;
        return {
          'Nome': e.name,
          'CPF': e.cpf,
          'Cargo/Função': e.role,
          'Setor/Departamento': dept?.name || e.sector,
          'Status Cadastro': e.isActive === false ? 'Inativo' : 'Ativo',
          'Qtd Ativos em Posse': assetCount
        };
      });
      const wsEmployees = XLSX.utils.json_to_sheet(employeeData);
      XLSX.utils.book_append_sheet(wb, wsEmployees, "Colaboradores");

      // 3. Aba de Requisições
      const requestData = requests.map(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        return {
          'Protocolo': r.id,
          'Status': r.status,
          'Data': new Date(r.createdAt).toLocaleDateString(),
          'Solicitante (ID)': r.requesterId,
          'Beneficiário': emp?.name || 'Estoque/Outro',
          'Itens Solicitados': r.items.join(', '),
          'Observação': r.observation
        };
      });
      const wsRequests = XLSX.utils.json_to_sheet(requestData);
      XLSX.utils.book_append_sheet(wb, wsRequests, "Requisições");

      // 4. Aba de Departamentos
      const deptData = departments.map(d => ({
        'ID': d.id,
        'Nome Departamento': d.name,
        'Centro de Custo': d.costCenter,
        'Total Ativos Vinculados': assets.filter(a => a.departmentId === d.id).length
      }));
      const wsDepts = XLSX.utils.json_to_sheet(deptData);
      XLSX.utils.book_append_sheet(wb, wsDepts, "Departamentos");

      // Salva o arquivo
      XLSX.writeFile(wb, `AssetTrack_Export_Completo_${new Date().toISOString().slice(0,10)}.xlsx`);
    } catch (error) {
      console.error("Erro na exportação:", error);
      alert("Houve um erro ao gerar o arquivo Excel.");
    }
  };

  // --- LÓGICA DE IMPORTAÇÃO (XLSX) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();

    setIsImporting(true);

    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Maps para acesso rápido (normalizados para lowercase)
        const classificationMap = new Map(classifications.map(c => [c.name.toLowerCase().trim(), c.id]));
        const typeConfigMap = new Map(assetTypeConfigs.map(t => [t.name.toLowerCase().trim(), t]));

        // --- 1. IMPORTAR DEPARTAMENTOS ---
        let deptMap = new Map<string, string>(); // Nome -> ID
        const wsDepts = wb.Sheets["Departamentos"];
        if (wsDepts) {
          const data: any[] = XLSX.utils.sheet_to_json(wsDepts);
          for (const row of data) {
            const id = row['ID'] || `DEPT-${Math.floor(Math.random() * 100000)}`;
            const name = row['Nome Departamento'];
            if (name) {
              const dept: Department = {
                id,
                name,
                costCenter: row['Centro de Custo'] || '',
                createdAt: new Date().toISOString()
              };
              await db.departments.upsert(dept);
              deptMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com departamentos já existentes no sistema caso não estejam na planilha
        departments.forEach(d => deptMap.set(d.name, d.id));

        // --- 2. IMPORTAR COLABORADORES ---
        let empMap = new Map<string, string>(); // Nome -> ID
        const wsEmps = wb.Sheets["Colaboradores"];
        if (wsEmps) {
          const data: any[] = XLSX.utils.sheet_to_json(wsEmps);
          for (const row of data) {
            const cpf = row['CPF'];
            const name = row['Nome'];
            if (name && cpf) {
              // Tenta encontrar colaborador existente pelo CPF para manter o ID
              const existingEmp = employees.find(e => e.cpf === cpf);
              const id = existingEmp?.id || `EMP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

              // Busca ID do departamento pelo nome
              const deptName = row['Setor/Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const emp: Employee = {
                id,
                name,
                cpf,
                role: row['Cargo/Função'] || '',
                sector: deptName || 'Geral',
                departmentId,
                isActive: row['Status Cadastro'] !== 'Inativo'
              };
              await db.employees.upsert(emp);
              empMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com colaboradores já existentes
        employees.forEach(e => empMap.set(e.name, e.id));

        // --- 3. IMPORTAR ATIVOS ---
        const wsAssets = wb.Sheets["Inventário Ativos"];
        let importedAssetsCount = 0;
        if (wsAssets) {
          const data: any[] = XLSX.utils.sheet_to_json(wsAssets);
          for (const row of data) {
            const id = row['ID Patrimonial'];
            if (id) {
              // --- TRATAMENTO DE CLASSIFICAÇÃO CONTÁBIL ---
              const typeName = (row['Tipo'] || 'Outros').trim();
              const classificationName = (row['Classificação Contábil'] || '').trim();

              if (typeName) {
                const typeKey = typeName.toLowerCase();
                const existingConfig = typeConfigMap.get(typeKey);

                let classificationId = existingConfig?.classificationId;

                // Se a planilha tem classificação, tentamos achar o ID
                if (classificationName) {
                  const foundId = classificationMap.get(classificationName.toLowerCase());
                  if (foundId) classificationId = foundId;
                }

                // Cria ou Atualiza a configuração do Tipo de Ativo
                if (!existingConfig) {
                  const newConfig: AssetTypeConfig = {
                    id: `TYPE-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
                    name: typeName,
                    classificationId: classificationId
                  };
                  await db.assetTypeConfigs.upsert(newConfig);
                  typeConfigMap.set(typeKey, newConfig); // Atualiza mapa local
                } else if (classificationId && existingConfig.classificationId !== classificationId) {
                  // Se já existe mas a planilha trouxe uma classificação diferente, atualizamos
                  const updatedConfig = { ...existingConfig, classificationId };
                  await db.assetTypeConfigs.upsert(updatedConfig);
                  typeConfigMap.set(typeKey, updatedConfig);
                }
              }

              // --- TRATAMENTO DO ATIVO ---
              const empName = row['Responsável Atual'];
              const assignedTo = empMap.get(empName) || undefined; // undefined se não achar ou for "Estoque"

              const deptName = row['Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              // Manter histórico existente se for atualização, ou criar novo
              const existingAsset = assets.find(a => a.id === id);
              let history = existingAsset?.history || [];

              if (!existingAsset) {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}`,
                   date: new Date().toISOString(),
                   type: 'Criação',
                   description: 'Importado via Planilha Excel',
                   performedBy: 'Sistema de Importação'
                 });
              } else {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}-${Math.random()}`,
                   date: new Date().toISOString(),
                   type: 'Observação',
                   description: 'Dados atualizados via Importação em Lote',
                   performedBy: 'Sistema de Importação'
                 });
              }

              const asset: Asset = {
                id,
                tagId: row['Etiqueta (Tag)'] || id,
                type: typeName, // Usa o tipo tratado
                brand: row['Marca'] || '',
                model: row['Modelo'] || '',
                serialNumber: row['Número de Série'] || '',
                purchaseValue: Number(row['Valor de Aquisição']) || 0,
                status: row['Status'] || 'Disponível',
                assignedTo,
                departmentId,
                processor: row['Processador'] || '',
                ram: row['RAM'] || '',
                storage: row['Armazenamento'] || '',
                observations: row['Observações'] || '',
                createdAt: existingAsset?.createdAt || new Date().toISOString(),
                qrCode: existingAsset?.qrCode || `QR-${id}`,
                photos: existingAsset?.photos || [],
                history
              };

              await db.assets.upsert(asset);
              importedAssetsCount++;
            }
          }
        }

        alert(`Importação concluída com sucesso!\n\nDados Processados:\n- Departamentos Sincronizados\n- Colaboradores Sincronizados\n- ${importedAssetsCount} Ativos Processados\n- Tipos de Ativo & Classificações Atualizados\n\nRecarregue a página para visualizar todas as alterações.`);

        // Limpa o input
        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (error) {
        console.error("Erro na importação:", error);
        alert("Erro crítico ao processar o arquivo. Verifique se o formato segue o modelo de exportação padrão.");
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Card de Exportação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center shadow-inner z-10">
              <Download className="w-10 h-10 text-emerald-600" />
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Exportação de Dados</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Gere um arquivo Excel (.xlsx) completo para backup ou para editar dados em massa e reimportar.
              </p>
           </div>
           <button 
            onClick={handleExportSystemData}
            className="z-10 bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Baixar Planilha Modelo
          </button>
        </div>

        {/* Card de Importação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center shadow-inner z-10">
              {isImporting ? <Loader2 className="w-10 h-10 text-blue-600 animate-spin" /> : <Upload className="w-10 h-10 text-blue-600" />}
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Importação em Lote</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Carregue a planilha preenchida para atualizar ou criar múltiplos registros de Ativos e Colaboradores.
              </p>
           </div>

           <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
           />

           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isImporting}
            className={`z-10 px-10 py-4 rounded-2xl font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95 ${
              isImporting 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-100'
            }`}
          >
            {isImporting ? 'Processando...' : 'Carregar Planilha .XLSX'}
            {!isImporting && <FileSpreadsheet className="w-5 h-5" />}
          </button>
          {isImporting && <p className="text-[10px] font-bold text-blue-600 animate-pulse">Isso pode levar alguns segundos...</p>}
        </div>
      </div>

      {/* Card de Informações do Sistema */}
      <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8">
         <div className="space-y-6 w-full md:w-auto">
            <div className="flex items-center gap-4">
               <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                  <Database className="w-8 h-8 text-white" />
               </div>
               <div>
                  <h3 className="text-2xl font-black tracking-tight">Status do Banco de Dados</h3>
                  <p className="text-blue-200 text-sm font-bold uppercase tracking-widest">Conexão Segura</p>
               </div>
            </div>

            <div className="space-y-2 pt-2">
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <ShieldCheck className="w-4 h-4 text-emerald-500" /> PostgreSQL (Supabase)
               </div>
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <Activity className="w-4 h-4 text-blue-500" /> Replicação em Tempo Real
               </div>
            </div>
         </div>

         <div className="grid grid-cols-3 gap-8 w-full md:w-auto border-t md:border-t-0 md:border-l border-slate-700 pt-8 md:pt-0 md:pl-10">
            <div className="text-center">
               <span className="block text-3xl font-black">{assets.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Ativos</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{employees.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Pessoas</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{departments.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Setores</span>
            </div>
         </div>
      </div>

      {/* Rodapé Informativo */}
      <div className="text-center py-10 opacity-50">
         <p className="text-xs font-black uppercase tracking-widest text-slate-400">AssetTrack Pro Enterprise v2.6</p>
         <p className="text-[10px] text-slate-400 mt-1">Módulo de Importação/Exportação Avançado</p>
      </div>

    </div>
  );
};

export default SystemInfoManager;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import AccountingManager from './components/AccountingManager';
import SystemInfoManager from './components/SystemInfoManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { 
  Asset, Employee, EquipmentRequest, UserAccount, 
  Department, AuditSession, AppNotification, AccountingAccount, 
  AccountingClassification, AssetTypeConfig, HistoryEntry 
} from './types';
import { db, supabase } from './services/supabase';
import { Loader2, Package, WifiOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [isOffline, setIsOffline] = useState(false);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Estados Contábeis
  const [accountingAccounts, setAccountingAccounts] = useState<AccountingAccount[]>([]);
  const [accountingClassifications, setAccountingClassifications] = useState<AccountingClassification[]>([]);
  const [assetTypeConfigs, setAssetTypeConfigs] = useState<AssetTypeConfig[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const results = await Promise.allSettled([
        db.departments.list(),
        db.assets.list(),
        db.employees.list(),
        db.requests.list(),
        db.auditSessions.list(),
        db.users.list(),
        db.notifications.list(),
        db.accountingAccounts.list(),
        db.accountingClassifications.list(),
        db.assetTypeConfigs.list()
      ]);

      const [
        depts, assts, emps, reqs, audits, userList, 
        notifs, accAccounts, accClass, assetConfigs
      ] = results.map(r => r.status === 'fulfilled' ? (r.value || []) : []);

      if (results.every(r => r.status === 'rejected')) setIsOffline(true);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);
      setAccountingAccounts(accAccounts);
      setAccountingClassifications(accClass);
      setAssetTypeConfigs(assetConfigs);

      const finalUsers = userList && userList.length > 0 ? [...userList] : [...MOCK_USERS];
      if (!finalUsers.find(u => u.username === 'admin')) {
        finalUsers.push(MOCK_USERS[0]);
      }
      setUsers(finalUsers);
      setNotifications(notifs);

    } catch (err: any) {
      console.error("Erro no carregamento:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    loadData(); 
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications' },
        (payload) => {
          const newNotif = payload.new as AppNotification;
          setNotifications(prev => {
            if (!prev) return [newNotif];
            if (prev.find(n => n.id === newNotif.id)) return prev;
            return [newNotif, ...prev].slice(0, 50);
          });
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => {
    const newNotif: AppNotification = {
      ...notif,
      id: `NTF-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      isRead: false
    };
    setNotifications(prev => [newNotif, ...(prev || [])].slice(0, 50));
    try { await db.notifications.upsert(newNotif); } catch (e) {}
  };

  const markNotificationAsRead = async (id: string) => {
    const target = notifications.find(n => n.id === id);
    if (!target) return;
    const updated = { ...target, isRead: true };
    setNotifications(prev => (prev || []).map(n => n.id === id ? updated : n));
    try { await db.notifications.upsert(updated); } catch (e) {}
  };

  const clearNotifications = async () => {
    setNotifications([]);
    try { await db.notifications.clearAll(); } catch (e) {}
  };

  const handleLogin = async (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules && user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    let finalId = assetData.id?.trim();
    let finalTagId = assetData.tagId?.trim();

    if (!finalId) {
       const randomSuffix = Math.floor(1000 + Math.random() * 9000);
       finalId = `AST-${randomSuffix}`;
       while(assets.some(a => a.id === finalId)) {
         finalId = `AST-${Math.floor(1000 + Math.random() * 9000)}`;
       }
    } else {
       finalTagId = finalId;
    }

    // LÓGICA DE CORREÇÃO DE VÍNCULO NO CADASTRO
    // 1. Normaliza o assignedTo (garante que string vazia seja undefined)
    const assignedTo = assetData.assignedTo && assetData.assignedTo.trim() !== '' ? assetData.assignedTo : undefined;

    // 2. Define o status inicial baseado se tem dono ou não
    const initialStatus = assignedTo ? 'Em Uso' : 'Disponível';

    // 3. Constrói o histórico inicial
    const initialHistory: HistoryEntry[] = assetData.history || [];

    // Adiciona evento de criação
    if (initialHistory.length === 0) {
      initialHistory.push({
        id: `HIST-CREATE-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Criação',
        description: `Patrimônio registrado no sistema (ID: ${finalId}). Etiqueta: ${finalTagId || 'N/A'}.`,
        performedBy: currentUser?.name || 'Sistema'
      });
    }

    // Se já nasceu com dono, adiciona evento de atribuição
    if (assignedTo) {
      const empName = employees.find(e => e.id === assignedTo)?.name || 'Colaborador';
      initialHistory.push({
        id: `HIST-INIT-ASSIGN-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Atribuição',
        description: `Ativo vinculado a ${empName} no momento do cadastro.`,
        performedBy: currentUser?.name || 'Sistema'
      });
    }

    // 4. Se tiver dono, tenta pegar o departamento do dono automaticamente
    let departmentId = assetData.departmentId;
    if (assignedTo) {
       const emp = employees.find(e => e.id === assignedTo);
       if (emp && emp.departmentId) {
          departmentId = emp.departmentId;
       }
    }

    const newAsset: Asset = { 
      ...assetData, 
      id: finalId, 
      tagId: finalTagId,
      assignedTo: assignedTo, // Usa o valor normalizado
      status: initialStatus,  // Usa o status calculado
      departmentId: departmentId,
      qrCode: `QR-${finalId}`,
      createdAt: new Date().toISOString(),
      history: initialHistory,
      observations: assetData.observations || ''
    };

    await db.assets.upsert(newAsset);
    setAssets(prev => [newAsset, ...(prev || [])]);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    const oldAsset = assets.find(a => a.id === updated.id);
    let finalAsset = { ...updated };

    // Normaliza assignedTo: string vazia vira undefined para comparação consistente
    if (finalAsset.assignedTo === '') {
      finalAsset.assignedTo = undefined;
    }

    const oldAssigned = oldAsset?.assignedTo || undefined;
    const newAssigned = finalAsset.assignedTo || undefined;

    // --- LÓGICA DE DETECÇÃO DE MUDANÇA DE RESPONSÁVEL ---
    // Detecta mudança real entre undefined e IDs válidos
    if (oldAsset && oldAssigned !== newAssigned) {
       const newEmp = employees.find(e => e.id === newAssigned);
       const oldEmp = employees.find(e => e.id === oldAssigned);

       const historyEntry: HistoryEntry = {
          id: `HIST-MOV-${Date.now()}`,
          date: new Date().toISOString(),
          type: 'Atribuição',
          description: newAssigned 
            ? `Movimentação Manual: Transferido de ${oldEmp?.name || 'Estoque/Outro'} para ${newEmp?.name}`
            : `Devolução Manual: Removido de ${oldEmp?.name} para Estoque.`,
          performedBy: currentUser?.name || 'Sistema'
       };

       // Adiciona ao histórico existente
       finalAsset.history = [...(finalAsset.history || []), historyEntry];

       // Se atribuído a alguém, atualiza o departamento do ativo para o do funcionário
       if (newEmp && newEmp.departmentId) {
          finalAsset.departmentId = newEmp.departmentId;
       }
    }

    // --- LÓGICA DE STATUS ---
    if (finalAsset.status === 'Baixado') {
      finalAsset.assignedTo = undefined;
    } else if (finalAsset.status === 'Manutenção') {
       // Mantém como está
    } else {
      // Automático: Se tem dono, é 'Em Uso'. Se não tem, é 'Disponível'.
      if (finalAsset.assignedTo) {
        finalAsset.status = 'Em Uso';
      } else {
        finalAsset.status = 'Disponível';
      }
    }

    try {
      console.log(`[AssetUpdate] Persistindo ${finalAsset.id} | Status: ${finalAsset.status} | Resp: ${finalAsset.assignedTo}`);
      await db.assets.upsert(finalAsset);
      setAssets(prev => {
        const next = (prev || []).map(a => a.id === finalAsset.id ? { ...finalAsset } : a);
        return [...next];
      });
    } catch (err: any) {
      console.error("Falha ao atualizar ativo no Supabase:", err);
      throw err;
    }
  };

  const handleRemoveAsset = async (id: string) => {
    await db.assets.remove(id);
    setAssets(prev => (prev || []).filter(a => a.id !== id));
  };

  // --- LÓGICA DE INATIVAÇÃO DE COLABORADOR E DESVINCULAÇÃO ---
  const handleRemoveEmployee = async (id: string) => {
    const target = employees.find(e => e.id === id);
    if (!target) return;

    // 1. Inativar Colaborador
    const updatedEmployee = { ...target, isActive: false };
    await db.employees.upsert(updatedEmployee);
    setEmployees(prev => prev.map(e => e.id === id ? updatedEmployee : e));

    // 2. Localizar Ativos Vinculados
    const linkedAssets = assets.filter(a => a.assignedTo === id);

    // 3. Desvincular Ativos e Retornar ao Estoque
    if (linkedAssets.length > 0) {
      const updatedAssets: Asset[] = [];

      for (const asset of linkedAssets) {
        const newHistoryEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Status',
          description: `Devolução Automática: Colaborador ${target.name} foi inativado.`,
          performedBy: currentUser?.name || 'Sistema'
        };

        const updatedAsset: Asset = {
          ...asset,
          assignedTo: undefined, // Remove o vínculo
          status: 'Disponível', // Retorna para estoque/disponível
          history: [...(asset.history || []), newHistoryEntry]
        };

        await db.assets.upsert(updatedAsset);
        updatedAssets.push(updatedAsset);
      }

      // Atualiza estado local dos ativos
      setAssets(prev => prev.map(a => {
        const updated = updatedAssets.find(u => u.id === a.id);
        return updated || a;
      }));

      addNotification({
        title: 'Colaborador Inativado',
        message: `${target.name} foi inativado. ${updatedAssets.length} ativos foram desvinculados e estão disponíveis.`,
        type: 'info',
        targetModule: 'assets'
      });
    }
  };

  const handleAddRequest = async (reqData: any): Promise<void> => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const sanitizedData = { ...reqData };
    if (sanitizedData.employeeId === '') {
      sanitizedData.employeeId = null;
    }

    const newReq: EquipmentRequest = { ...sanitizedData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...(prev || [])]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => (prev || []).map(r => r.id === req.id ? req : r));

    if (req.status === 'Entregue' && req.employeeId) {
      const employee = employees.find(e => e.id === req.employeeId);
      if (!employee) return;

      const assetsToUpdate: Asset[] = [];

      req.itemFulfillments?.forEach(f => {
        if (f.linkedAssetId) {
          const asset = assets.find(a => a.id === f.linkedAssetId);
          if (asset) {
            assetsToUpdate.push({
              ...asset,
              status: 'Em Uso',
              assignedTo: employee.id,
              departmentId: employee.departmentId,
              history: [
                ...(asset.history || []),
                {
                  id: Math.random().toString(),
                  date: new Date().toISOString(),
                  type: 'Atribuição',
                  description: `Ativo entregue ao colaborador ${employee.name} via Requisição ${req.id}.`,
                  performedBy: currentUser?.name || 'Sistema'
                }
              ]
            });
          }
        }
      });

      if (assetsToUpdate.length > 0) {
        for (const asset of assetsToUpdate) {
          await db.assets.upsert(asset);
        }
        setAssets(prev => {
          const newAssets = [...prev];
          assetsToUpdate.forEach(updated => {
            const idx = newAssets.findIndex(a => a.id === updated.id);
            if (idx !== -1) newAssets[idx] = updated;
          });
          return newAssets;
        });

        addNotification({
          title: 'Patrimônio Atualizado',
          message: `${assetsToUpdate.length} item(ns) movidos para posse de ${employee.name}.`,
          type: 'delivery',
          targetModule: 'assets'
        });
      }
    }
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => (prev || []).filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => (prev || []).map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">AssetTrack Pro: Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = (employees || []).filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800 animate-bounce">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">O sistema está em modo de contingência offline (Local Storage).</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard 
              assets={assets} 
              requests={requests} 
              employees={employees} // Passamos todos para resolver nomes, o filtro é interno
              departments={departments} // Passamos departamentos para exportação
              assetTypeConfigs={assetTypeConfigs}
              classifications={accountingClassifications}
            />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} assetTypeConfigs={assetTypeConfigs} classifications={accountingClassifications} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={handleRemoveEmployee} // Usa a nova lógica de desvinculação
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
              assetTypeConfigs={assetTypeConfigs}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} assetTypeConfigs={assetTypeConfigs} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                await db.users.upsert(newU); 
                setUsers(prev => [...prev, newU]); 
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          case 'accounting':
            return <AccountingManager 
              accounts={accountingAccounts}
              classifications={accountingClassifications}
              assetTypes={assetTypeConfigs}
              onAddAccount={async (a) => { const newA = {...a, id: `ACC-${Date.now()}`}; await db.accountingAccounts.upsert(newA); setAccountingAccounts(prev => [...prev, newA]); }}
              onUpdateAccount={async (a) => { await db.accountingAccounts.upsert(a); setAccountingAccounts(prev => prev.map(old => old.id === a.id ? a : old)); }}
              onRemoveAccount={async (id) => { await db.accountingAccounts.remove(id); setAccountingAccounts(prev => prev.filter(a => a.id !== id)); }}
              onAddClassification={async (c) => { const newC = {...c, id: `CLS-${Date.now()}`}; await db.accountingClassifications.upsert(newC); setAccountingClassifications(prev => [...prev, newC]); }}
              onUpdateClassification={async (c) => { await db.accountingClassifications.upsert(c); setAccountingClassifications(prev => prev.map(old => old.id === c.id ? c : old)); }}
              onRemoveClassification={async (id) => { await db.accountingClassifications.remove(id); setAccountingClassifications(prev => prev.filter(c => c.id !== id)); }}
              onAddAssetType={async (t) => { const newT = {...t, id: `TYPE-${Date.now()}`}; await db.assetTypeConfigs.upsert(newT); setAssetTypeConfigs(prev => [...prev, newT]); }}
              onUpdateAssetType={async (t) => { await db.assetTypeConfigs.upsert(t); setAssetTypeConfigs(prev => prev.map(old => old.id === t.id ? t : old)); }}
              onRemoveAssetType={async (id) => { await db.assetTypeConfigs.remove(id); setAssetTypeConfigs(prev => prev.filter(t => t.id !== id)); }}
            />;
          case 'system-info':
            return <SystemInfoManager 
              assets={assets} 
              requests={requests} 
              employees={employees} 
              departments={departments}
              assetTypeConfigs={assetTypeConfigs} // Props adicionadas
              classifications={accountingClassifications} // Props adicionadas
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import { Download, Database, HardDrive, ShieldCheck, Activity, Upload, Loader2, FileSpreadsheet } from 'lucide-react';
import { Asset, EquipmentRequest, Employee, Department, HistoryEntry, AssetTypeConfig, AccountingClassification } from '../types';
import { db } from '../services/supabase';

interface SystemInfoManagerProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  departments: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
}

const SystemInfoManager: React.FC<SystemInfoManagerProps> = ({ 
  assets, 
  requests, 
  employees, 
  departments,
  assetTypeConfigs,
  classifications
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // --- LÓGICA DE EXPORTAÇÃO (XLSX) ---
  const handleExportSystemData = () => {
    try {
      const wb = XLSX.utils.book_new();

      // 1. Aba de Ativos
      const assetData = assets.map(a => {
        const emp = employees.find(e => e.id === a.assignedTo);
        const dept = departments.find(d => d.id === a.departmentId);

        // Resolve Classificação Contábil
        const config = assetTypeConfigs.find(c => c.name.toLowerCase().trim() === a.type.toLowerCase().trim());
        const classification = classifications.find(c => c.id === config?.classificationId);

        return {
          'ID Patrimonial': a.id,
          'Etiqueta (Tag)': a.tagId,
          'Tipo': a.type,
          'Classificação Contábil': classification?.name || '', // Nova coluna para facilitar a vida do usuário
          'Marca': a.brand,
          'Modelo': a.model,
          'Número de Série': a.serialNumber,
          'Valor de Aquisição': a.purchaseValue || 0,
          'Status': a.status,
          'Responsável Atual': emp?.name || 'Estoque',
          'Departamento': dept?.name || 'Não Vinculado',
          'Processador': a.processor,
          'RAM': a.ram,
          'Armazenamento': a.storage,
          'Observações': a.observations,
          'Data Criação': new Date(a.createdAt).toLocaleDateString()
        };
      });
      const wsAssets = XLSX.utils.json_to_sheet(assetData);
      XLSX.utils.book_append_sheet(wb, wsAssets, "Inventário Ativos");

      // 2. Aba de Colaboradores
      const employeeData = employees.map(e => {
        const dept = departments.find(d => d.id === e.departmentId);
        const assetCount = assets.filter(a => a.assignedTo === e.id).length;
        return {
          'Nome': e.name,
          'CPF': e.cpf,
          'Cargo/Função': e.role,
          'Setor/Departamento': dept?.name || e.sector,
          'Status Cadastro': e.isActive === false ? 'Inativo' : 'Ativo',
          'Qtd Ativos em Posse': assetCount
        };
      });
      const wsEmployees = XLSX.utils.json_to_sheet(employeeData);
      XLSX.utils.book_append_sheet(wb, wsEmployees, "Colaboradores");

      // 3. Aba de Requisições
      const requestData = requests.map(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        return {
          'Protocolo': r.id,
          'Status': r.status,
          'Data': new Date(r.createdAt).toLocaleDateString(),
          'Solicitante (ID)': r.requesterId,
          'Beneficiário': emp?.name || 'Estoque/Outro',
          'Itens Solicitados': r.items.join(', '),
          'Observação': r.observation
        };
      });
      const wsRequests = XLSX.utils.json_to_sheet(requestData);
      XLSX.utils.book_append_sheet(wb, wsRequests, "Requisições");

      // 4. Aba de Departamentos
      const deptData = departments.map(d => ({
        'ID': d.id,
        'Nome Departamento': d.name,
        'Centro de Custo': d.costCenter,
        'Total Ativos Vinculados': assets.filter(a => a.departmentId === d.id).length
      }));
      const wsDepts = XLSX.utils.json_to_sheet(deptData);
      XLSX.utils.book_append_sheet(wb, wsDepts, "Departamentos");

      // Salva o arquivo
      XLSX.writeFile(wb, `AssetTrack_Export_Completo_${new Date().toISOString().slice(0,10)}.xlsx`);
    } catch (error) {
      console.error("Erro na exportação:", error);
      alert("Houve um erro ao gerar o arquivo Excel.");
    }
  };

  // --- LÓGICA DE IMPORTAÇÃO (XLSX) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();

    setIsImporting(true);

    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Maps para acesso rápido (normalizados para lowercase)
        const classificationMap = new Map(classifications.map(c => [c.name.toLowerCase().trim(), c.id]));
        // Fix: Explicitly assert the type of the map entries to avoid inference as (string | AssetTypeConfig)[] which creates a Map<any, any> or Map<string | AssetTypeConfig, string | AssetTypeConfig> depending on lib version, leading to 'unknown' type for get() result in strict mode.
        const typeConfigMap = new Map(assetTypeConfigs.map(t => [t.name.toLowerCase().trim(), t] as [string, AssetTypeConfig]));

        // --- 1. IMPORTAR DEPARTAMENTOS ---
        let deptMap = new Map<string, string>(); // Nome -> ID
        const wsDepts = wb.Sheets["Departamentos"];
        if (wsDepts) {
          const data: any[] = XLSX.utils.sheet_to_json(wsDepts);
          for (const row of data) {
            const id = row['ID'] || `DEPT-${Math.floor(Math.random() * 100000)}`;
            const name = row['Nome Departamento'];
            if (name) {
              const dept: Department = {
                id,
                name,
                costCenter: row['Centro de Custo'] || '',
                createdAt: new Date().toISOString()
              };
              await db.departments.upsert(dept);
              deptMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com departamentos já existentes no sistema caso não estejam na planilha
        departments.forEach(d => deptMap.set(d.name, d.id));

        // --- 2. IMPORTAR COLABORADORES ---
        let empMap = new Map<string, string>(); // Nome -> ID
        const wsEmps = wb.Sheets["Colaboradores"];
        if (wsEmps) {
          const data: any[] = XLSX.utils.sheet_to_json(wsEmps);
          for (const row of data) {
            const cpf = row['CPF'];
            const name = row['Nome'];
            if (name && cpf) {
              // Tenta encontrar colaborador existente pelo CPF para manter o ID
              const existingEmp = employees.find(e => e.cpf === cpf);
              const id = existingEmp?.id || `EMP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

              // Busca ID do departamento pelo nome
              const deptName = row['Setor/Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const emp: Employee = {
                id,
                name,
                cpf,
                role: row['Cargo/Função'] || '',
                sector: deptName || 'Geral',
                departmentId,
                isActive: row['Status Cadastro'] !== 'Inativo'
              };
              await db.employees.upsert(emp);
              empMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com colaboradores já existentes
        employees.forEach(e => empMap.set(e.name, e.id));

        // --- 3. IMPORTAR ATIVOS ---
        const wsAssets = wb.Sheets["Inventário Ativos"];
        let importedAssetsCount = 0;
        if (wsAssets) {
          const data: any[] = XLSX.utils.sheet_to_json(wsAssets);
          for (const row of data) {
            const id = row['ID Patrimonial'];
            if (id) {
              // --- TRATAMENTO DE CLASSIFICAÇÃO CONTÁBIL ---
              const typeName = (row['Tipo'] || 'Outros').trim();
              const classificationName = (row['Classificação Contábil'] || '').trim();

              if (typeName) {
                const typeKey = typeName.toLowerCase();
                const existingConfig = typeConfigMap.get(typeKey);

                let classificationId = existingConfig?.classificationId;

                // Se a planilha tem classificação, tentamos achar o ID
                if (classificationName) {
                  const foundId = classificationMap.get(classificationName.toLowerCase());
                  if (foundId) classificationId = foundId;
                }

                // Cria ou Atualiza a configuração do Tipo de Ativo
                if (!existingConfig) {
                  const newConfig: AssetTypeConfig = {
                    id: `TYPE-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
                    name: typeName,
                    classificationId: classificationId
                  };
                  await db.assetTypeConfigs.upsert(newConfig);
                  typeConfigMap.set(typeKey, newConfig); // Atualiza mapa local
                } else if (classificationId && existingConfig.classificationId !== classificationId) {
                  // Se já existe mas a planilha trouxe uma classificação diferente, atualizamos
                  const updatedConfig = { ...existingConfig, classificationId };
                  await db.assetTypeConfigs.upsert(updatedConfig);
                  typeConfigMap.set(typeKey, updatedConfig);
                }
              }

              // --- TRATAMENTO DO ATIVO ---
              const empName = row['Responsável Atual'];
              const assignedTo = empMap.get(empName) || undefined; // undefined se não achar ou for "Estoque"

              const deptName = row['Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              // Manter histórico existente se for atualização, ou criar novo
              const existingAsset = assets.find(a => a.id === id);
              let history = existingAsset?.history || [];

              if (!existingAsset) {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}`,
                   date: new Date().toISOString(),
                   type: 'Criação',
                   description: 'Importado via Planilha Excel',
                   performedBy: 'Sistema de Importação'
                 });
              } else {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}-${Math.random()}`,
                   date: new Date().toISOString(),
                   type: 'Observação',
                   description: 'Dados atualizados via Importação em Lote',
                   performedBy: 'Sistema de Importação'
                 });
              }

              const asset: Asset = {
                id,
                tagId: row['Etiqueta (Tag)'] || id,
                type: typeName, // Usa o tipo tratado
                brand: row['Marca'] || '',
                model: row['Modelo'] || '',
                serialNumber: row['Número de Série'] || '',
                purchaseValue: Number(row['Valor de Aquisição']) || 0,
                status: row['Status'] || 'Disponível',
                assignedTo,
                departmentId,
                processor: row['Processador'] || '',
                ram: row['RAM'] || '',
                storage: row['Armazenamento'] || '',
                observations: row['Observações'] || '',
                createdAt: existingAsset?.createdAt || new Date().toISOString(),
                qrCode: existingAsset?.qrCode || `QR-${id}`,
                photos: existingAsset?.photos || [],
                history
              };

              await db.assets.upsert(asset);
              importedAssetsCount++;
            }
          }
        }

        alert(`Importação concluída com sucesso!\n\nDados Processados:\n- Departamentos Sincronizados\n- Colaboradores Sincronizados\n- ${importedAssetsCount} Ativos Processados\n- Tipos de Ativo & Classificações Atualizados\n\nRecarregue a página para visualizar todas as alterações.`);

        // Limpa o input
        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (error) {
        console.error("Erro na importação:", error);
        alert("Erro crítico ao processar o arquivo. Verifique se o formato segue o modelo de exportação padrão.");
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Card de Exportação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center shadow-inner z-10">
              <Download className="w-10 h-10 text-emerald-600" />
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Exportação de Dados</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Gere um arquivo Excel (.xlsx) completo para backup ou para editar dados em massa e reimportar.
              </p>
           </div>
           <button 
            onClick={handleExportSystemData}
            className="z-10 bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Baixar Planilha Modelo
          </button>
        </div>

        {/* Card de Importação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center shadow-inner z-10">
              {isImporting ? <Loader2 className="w-10 h-10 text-blue-600 animate-spin" /> : <Upload className="w-10 h-10 text-blue-600" />}
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Importação em Lote</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Carregue a planilha preenchida para atualizar ou criar múltiplos registros de Ativos e Colaboradores.
              </p>
           </div>

           <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
           />

           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isImporting}
            className={`z-10 px-10 py-4 rounded-2xl font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95 ${
              isImporting 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-100'
            }`}
          >
            {isImporting ? 'Processando...' : 'Carregar Planilha .XLSX'}
            {!isImporting && <FileSpreadsheet className="w-5 h-5" />}
          </button>
          {isImporting && <p className="text-[10px] font-bold text-blue-600 animate-pulse">Isso pode levar alguns segundos...</p>}
        </div>
      </div>

      {/* Card de Informações do Sistema */}
      <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8">
         <div className="space-y-6 w-full md:w-auto">
            <div className="flex items-center gap-4">
               <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                  <Database className="w-8 h-8 text-white" />
               </div>
               <div>
                  <h3 className="text-2xl font-black tracking-tight">Status do Banco de Dados</h3>
                  <p className="text-blue-200 text-sm font-bold uppercase tracking-widest">Conexão Segura</p>
               </div>
            </div>

            <div className="space-y-2 pt-2">
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <ShieldCheck className="w-4 h-4 text-emerald-500" /> PostgreSQL (Supabase)
               </div>
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <Activity className="w-4 h-4 text-blue-500" /> Replicação em Tempo Real
               </div>
            </div>
         </div>

         <div className="grid grid-cols-3 gap-8 w-full md:w-auto border-t md:border-t-0 md:border-l border-slate-700 pt-8 md:pt-0 md:pl-10">
            <div className="text-center">
               <span className="block text-3xl font-black">{assets.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Ativos</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{employees.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Pessoas</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{departments.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Setores</span>
            </div>
         </div>
      </div>

      {/* Rodapé Informativo */}
      <div className="text-center py-10 opacity-50">
         <p className="text-xs font-black uppercase tracking-widest text-slate-400">AssetTrack Pro Enterprise v2.6</p>
         <p className="text-[10px] text-slate-400 mt-1">Módulo de Importação/Exportação Avançado</p>
      </div>

    </div>
  );
};

export default SystemInfoManager;

import React, { useState, useMemo } from 'react';
import { 
  Calculator, 
  Book, 
  Layers, 
  Plus, 
  Search, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  ArrowRight,
  ShieldCheck,
  Briefcase,
  Tag,
  DollarSign,
  Loader2,
  FolderOpen,
  CornerDownRight,
  FileText
} from 'lucide-react';
import { AccountingAccount, AccountingClassification, AssetTypeConfig } from '../types';

interface AccountingManagerProps {
  accounts: AccountingAccount[];
  classifications: AccountingClassification[];
  assetTypes: AssetTypeConfig[];
  onAddAccount: (acc: Omit<AccountingAccount, 'id'>) => Promise<void>;
  onUpdateAccount: (acc: AccountingAccount) => Promise<void>;
  onRemoveAccount: (id: string) => Promise<void>;
  onAddClassification: (cls: Omit<AccountingClassification, 'id'>) => Promise<void>;
  onUpdateClassification: (cls: AccountingClassification) => Promise<void>;
  onRemoveClassification: (id: string) => Promise<void>;
  onAddAssetType: (type: Omit<AssetTypeConfig, 'id'>) => Promise<void>;
  onUpdateAssetType: (type: AssetTypeConfig) => Promise<void>;
  onRemoveAssetType: (id: string) => Promise<void>;
}

const AccountingManager: React.FC<AccountingManagerProps> = ({
  accounts, classifications, assetTypes,
  onAddAccount, onUpdateAccount, onRemoveAccount,
  onAddClassification, onUpdateClassification, onRemoveClassification,
  onAddAssetType, onUpdateAssetType, onRemoveAssetType
}) => {
  const [activeTab, setActiveTab] = useState<'structure' | 'asset-types'>('structure');
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState<'account' | 'classification' | 'asset-type'>('account');
  const [editingItem, setEditingItem] = useState<any>(null);
  const [selectedParentAccountId, setSelectedParentAccountId] = useState<string>('');
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form states
  const [formData, setFormData] = useState<any>({});

  // --- FILTROS ---
  const filteredAccounts = useMemo(() => {
    return accounts.filter(a => 
      a.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      a.code.includes(searchTerm)
    ).sort((a, b) => a.code.localeCompare(b.code));
  }, [accounts, searchTerm]);

  const filteredAssetTypes = useMemo(() => {
    return assetTypes.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    ).sort((a, b) => a.name.localeCompare(b.name));
  }, [assetTypes, searchTerm]);

  // --- AÇÕES DE ABERTURA DE MODAL ---

  const handleOpenAccountForm = (account: AccountingAccount | null = null) => {
    setFormType('account');
    setEditingItem(account);
    setFormData(account || { code: '', name: '' });
    setShowForm(true);
  };

  const handleOpenClassificationForm = (parentAccountId: string, classification: AccountingClassification | null = null) => {
    setFormType('classification');
    setEditingItem(classification);
    setSelectedParentAccountId(parentAccountId);
    setFormData(classification || { name: '', code: '', accountId: parentAccountId });
    setShowForm(true);
  };

  const handleOpenAssetTypeForm = (type: AssetTypeConfig | null = null) => {
    setFormType('asset-type');
    setEditingItem(type);
    setFormData(type || { name: '', classificationId: '' });
    setShowForm(true);
  };

  // --- SUBMISSÃO ---

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (formType === 'account') {
        if (editingItem) await onUpdateAccount(formData);
        else await onAddAccount(formData);
      } else if (formType === 'classification') {
        // Garante que o accountId está correto
        const payload = { ...formData, accountId: selectedParentAccountId };
        if (editingItem) await onUpdateClassification(payload);
        else await onAddClassification(payload);
      } else if (formType === 'asset-type') {
        if (editingItem) await onUpdateAssetType(formData);
        else await onAddAssetType(formData);
      }
      setShowForm(false);
      setEditingItem(null);
    } catch (err: any) {
      console.error("Erro Contabil:", err);
      alert(`Falha ao salvar: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string, type: 'account' | 'classification' | 'asset-type') => {
    const msg = type === 'account' 
      ? 'ATENÇÃO: Excluir uma Conta Contábil excluirá também todas as Classificações vinculadas a ela.\nDeseja continuar?' 
      : 'Deseja realmente excluir este registro?';

    if (!confirm(msg)) return;

    try {
      if (type === 'account') await onRemoveAccount(id);
      else if (type === 'classification') await onRemoveClassification(id);
      else await onRemoveAssetType(id);
    } catch (err: any) {
      alert(`Erro ao excluir: ${err.message}`);
    }
  };

  const getClassificationName = (id: string) => classifications.find(c => c.id === id)?.name || 'Não Classificado';
  const getClassificationCode = (id: string) => classifications.find(c => c.id === id)?.code || '';

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* TABS E HEADER */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div className="bg-white rounded-[2rem] p-1.5 border border-slate-100 shadow-sm flex gap-1 w-full md:w-auto">
              <button 
                onClick={() => setActiveTab('structure')}
                className={`px-6 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${
                  activeTab === 'structure' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'
                }`}
              >
                <FolderOpen className="w-4 h-4" /> Estrutura Contábil
              </button>
              <button 
                onClick={() => setActiveTab('asset-types')}
                className={`px-6 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${
                  activeTab === 'asset-types' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'
                }`}
              >
                <Layers className="w-4 h-4" /> Mapeamento de Ativos
              </button>
           </div>

           <div className="flex items-center gap-3 w-full md:w-auto">
              <div className="relative flex-1 md:flex-none">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                 <input 
                   className="w-full md:w-64 pl-9 pr-4 py-3 rounded-2xl border border-slate-200 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none"
                   placeholder={activeTab === 'structure' ? "Buscar conta ou código..." : "Buscar tipo de ativo..."}
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                 />
              </div>
              <button 
                onClick={() => activeTab === 'structure' ? handleOpenAccountForm() : handleOpenAssetTypeForm()}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95 uppercase text-[10px] tracking-widest whitespace-nowrap"
              >
                <Plus className="w-4 h-4" /> 
                {activeTab === 'structure' ? 'Nova Conta Pai' : 'Novo Tipo'}
              </button>
           </div>
        </div>
      </div>

      {/* CONTEÚDO PRINCIPAL */}
      {activeTab === 'structure' && (
        <div className="space-y-6">
           {filteredAccounts.map(account => {
             const accountClassifications = classifications.filter(c => c.accountId === account.id).sort((a, b) => a.code.localeCompare(b.code));

             return (
               <div key={account.id} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-all">
                  {/* HEADER DA CONTA (PAI) */}
                  <div className="bg-slate-50 p-6 flex flex-col md:flex-row items-start md:items-center justify-between border-b border-slate-100 gap-4">
                     <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-white border border-slate-200 rounded-2xl flex items-center justify-center text-blue-600 font-bold shadow-sm">
                           <Book className="w-6 h-6" />
                        </div>
                        <div>
                           <div className="flex items-center gap-2">
                              <span className="bg-blue-100 text-blue-700 px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest">{account.code}</span>
                              <h4 className="text-lg font-black text-slate-800">{account.name}</h4>
                           </div>
                           <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Conta Contábil Principal</p>
                        </div>
                     </div>
                     <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleOpenClassificationForm(account.id)}
                          className="px-4 py-2 bg-white border border-emerald-200 text-emerald-700 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-50 transition-colors flex items-center gap-2"
                        >
                           <Plus className="w-3 h-3" /> Adicionar Classificação
                        </button>
                        <button onClick={() => handleOpenAccountForm(account)} className="p-2 hover:bg-white rounded-xl text-slate-400 hover:text-blue-600 transition-colors">
                           <Edit2 className="w-4 h-4" />
                        </button>
                        <button onClick={() => handleDelete(account.id, 'account')} className="p-2 hover:bg-white rounded-xl text-slate-400 hover:text-rose-600 transition-colors">
                           <Trash2 className="w-4 h-4" />
                        </button>
                     </div>
                  </div>

                  {/* LISTA DE CLASSIFICAÇÕES (FILHOS) */}
                  <div className="p-4 bg-white">
                     {accountClassifications.length > 0 ? (
                       <div className="grid grid-cols-1 gap-2">
                          {accountClassifications.map(cls => (
                            <div key={cls.id} className="flex items-center justify-between p-4 rounded-2xl hover:bg-slate-50 border border-transparent hover:border-slate-100 transition-all group ml-8 relative">
                               <div className="absolute left-[-20px] top-1/2 -translate-y-1/2">
                                  <CornerDownRight className="w-5 h-5 text-slate-300" />
                               </div>
                               <div className="flex items-center gap-4">
                                  <div className="bg-slate-100 text-slate-600 px-3 py-1.5 rounded-lg text-xs font-mono font-bold">
                                     {cls.code}
                                  </div>
                                  <span className="font-bold text-slate-700">{cls.name}</span>
                               </div>
                               <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={() => handleOpenClassificationForm(account.id, cls)} className="p-2 text-slate-400 hover:text-blue-600">
                                     <Edit2 className="w-4 h-4" />
                                  </button>
                                  <button onClick={() => handleDelete(cls.id, 'classification')} className="p-2 text-slate-400 hover:text-rose-600">
                                     <Trash2 className="w-4 h-4" />
                                  </button>
                               </div>
                            </div>
                          ))}
                       </div>
                     ) : (
                       <div className="py-8 text-center ml-8 border-l-2 border-slate-100 border-dashed">
                          <p className="text-[10px] font-black uppercase text-slate-300 tracking-widest">Nenhuma classificação vinculada</p>
                       </div>
                     )}
                  </div>
               </div>
             );
           })}

           {filteredAccounts.length === 0 && (
             <div className="text-center py-20 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200">
                <FolderOpen className="w-12 h-12 mx-auto text-slate-300 mb-4" />
                <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Nenhuma conta contábil encontrada</p>
             </div>
           )}
        </div>
      )}

      {activeTab === 'asset-types' && (
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
           <div className="p-8 border-b border-slate-100 bg-slate-50/50">
              <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                 <Tag className="w-5 h-5 text-blue-600" /> Vínculo de Nomenclatura x Contabilidade
              </h3>
              <p className="text-xs text-slate-500 mt-1">Defina como cada nome de equipamento (ex: "Macbook Pro") deve ser classificado contabilmente.</p>
           </div>
           <table className="w-full text-left">
              <thead className="bg-white border-b border-slate-100">
                 <tr>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome do Tipo (Sistema)</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Classificação Contábil</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                 {filteredAssetTypes.map(type => (
                   <tr key={type.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-8 py-5">
                         <span className="font-black text-slate-800">{type.name}</span>
                      </td>
                      <td className="px-8 py-5">
                         {type.classificationId ? (
                           <div className="flex items-center gap-2">
                              <span className="bg-blue-50 text-blue-700 px-2 py-0.5 rounded text-[10px] font-bold font-mono">
                                 {getClassificationCode(type.classificationId)}
                              </span>
                              <span className="text-sm font-medium text-slate-600">{getClassificationName(type.classificationId)}</span>
                           </div>
                         ) : (
                           <span className="text-xs text-rose-500 font-bold bg-rose-50 px-3 py-1 rounded-full">Pendente</span>
                         )}
                      </td>
                      <td className="px-8 py-5 text-right">
                         <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => handleOpenAssetTypeForm(type)} className="p-2 text-slate-400 hover:text-blue-600">
                               <Edit2 className="w-4 h-4" />
                            </button>
                            <button onClick={() => handleDelete(type.id, 'asset-type')} className="p-2 text-slate-400 hover:text-rose-600">
                               <Trash2 className="w-4 h-4" />
                            </button>
                         </div>
                      </td>
                   </tr>
                 ))}
                 {filteredAssetTypes.length === 0 && (
                   <tr>
                      <td colSpan={3} className="py-16 text-center text-slate-400 font-bold uppercase text-xs">Nenhum tipo cadastrado.</td>
                   </tr>
                 )}
              </tbody>
           </table>
        </div>
      )}

      {/* FORM MODAL */}
      {showForm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-900 text-white flex items-center justify-between">
              <h3 className="text-xl font-black uppercase tracking-tight">
                {editingItem ? 'Editar' : 'Adicionar'} {
                  formType === 'account' ? 'Conta Pai' : 
                  formType === 'classification' ? 'Classificação' : 'Tipo de Ativo'
                }
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 space-y-6">

              {formType === 'account' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Ativo Imobilizado" />
                  </div>
                </>
              )}

              {formType === 'classification' && (
                <>
                  <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 mb-4">
                     <p className="text-[10px] font-black uppercase text-blue-600 tracking-widest mb-1">Vinculado à Conta Pai:</p>
                     <p className="font-bold text-blue-900">{accounts.find(a => a.id === selectedParentAccountId)?.name || 'Erro de Vínculo'}</p>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código da Classificação</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01.005" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Classificação</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Equipamentos de Processamento de Dados" />
                  </div>
                </>
              )}

              {formType === 'asset-type' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Comum (Tipo)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Notebook, Monitor, Teclado..." />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Vincular à Classificação</label>
                    <select 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                      value={formData.classificationId} 
                      onChange={e => setFormData({...formData, classificationId: e.target.value})} 
                      required
                    >
                      <option value="">Selecione...</option>
                      {accounts.map(account => (
                        <optgroup key={account.id} label={account.name}>
                           {classifications.filter(c => c.accountId === account.id).map(c => (
                             <option key={c.id} value={c.id}>{c.code} - {c.name}</option>
                           ))}
                        </optgroup>
                      ))}
                    </select>
                  </div>
                </>
              )}

              <div className="flex gap-3 pt-6 border-t border-slate-100">
                <button type="button" disabled={isSaving} onClick={() => setShowForm(false)} className="flex-1 py-4 font-bold text-slate-400 hover:bg-slate-50 rounded-2xl transition-colors">Cancelar</button>
                <button 
                  type="submit" 
                  disabled={isSaving}
                  className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-100 flex items-center justify-center gap-2 transition-all"
                >
                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
                  {isSaving ? 'Salvando...' : 'Confirmar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AccountingManager;

import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import { Download, Database, HardDrive, ShieldCheck, Activity, Upload, Loader2, FileSpreadsheet } from 'lucide-react';
import { Asset, EquipmentRequest, Employee, Department, HistoryEntry, AssetTypeConfig, AccountingClassification } from '../types';
import { db } from '../services/supabase';

interface SystemInfoManagerProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  departments: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  classifications: AccountingClassification[];
}

const SystemInfoManager: React.FC<SystemInfoManagerProps> = ({ 
  assets, 
  requests, 
  employees, 
  departments,
  assetTypeConfigs,
  classifications
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // --- LÓGICA DE EXPORTAÇÃO (XLSX) ---
  const handleExportSystemData = () => {
    try {
      const wb = XLSX.utils.book_new();

      // 1. Aba de Ativos
      const assetData = assets.map(a => {
        const emp = employees.find(e => e.id === a.assignedTo);
        const dept = departments.find(d => d.id === a.departmentId);

        // Resolve Classificação Contábil
        const config = assetTypeConfigs.find(c => c.name.toLowerCase().trim() === a.type.toLowerCase().trim());
        const classification = classifications.find(c => c.id === config?.classificationId);

        return {
          'ID Patrimonial': a.id,
          'Etiqueta (Tag)': a.tagId,
          'Tipo': a.type,
          'Classificação Contábil': classification?.name || '', // Nova coluna para facilitar a vida do usuário
          'Marca': a.brand,
          'Modelo': a.model,
          'Número de Série': a.serialNumber,
          'Valor de Aquisição': a.purchaseValue || 0,
          'Status': a.status,
          'Responsável Atual': emp?.name || 'Estoque',
          'Departamento': dept?.name || 'Não Vinculado',
          'Processador': a.processor,
          'RAM': a.ram,
          'Armazenamento': a.storage,
          'Observações': a.observations,
          'Data Criação': new Date(a.createdAt).toLocaleDateString()
        };
      });
      const wsAssets = XLSX.utils.json_to_sheet(assetData);
      XLSX.utils.book_append_sheet(wb, wsAssets, "Inventário Ativos");

      // 2. Aba de Colaboradores
      const employeeData = employees.map(e => {
        const dept = departments.find(d => d.id === e.departmentId);
        const assetCount = assets.filter(a => a.assignedTo === e.id).length;
        return {
          'Nome': e.name,
          'CPF': e.cpf,
          'Cargo/Função': e.role,
          'Setor/Departamento': dept?.name || e.sector,
          'Status Cadastro': e.isActive === false ? 'Inativo' : 'Ativo',
          'Qtd Ativos em Posse': assetCount
        };
      });
      const wsEmployees = XLSX.utils.json_to_sheet(employeeData);
      XLSX.utils.book_append_sheet(wb, wsEmployees, "Colaboradores");

      // 3. Aba de Requisições
      const requestData = requests.map(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        return {
          'Protocolo': r.id,
          'Status': r.status,
          'Data': new Date(r.createdAt).toLocaleDateString(),
          'Solicitante (ID)': r.requesterId,
          'Beneficiário': emp?.name || 'Estoque/Outro',
          'Itens Solicitados': r.items.join(', '),
          'Observação': r.observation
        };
      });
      const wsRequests = XLSX.utils.json_to_sheet(requestData);
      XLSX.utils.book_append_sheet(wb, wsRequests, "Requisições");

      // 4. Aba de Departamentos
      const deptData = departments.map(d => ({
        'ID': d.id,
        'Nome Departamento': d.name,
        'Centro de Custo': d.costCenter,
        'Total Ativos Vinculados': assets.filter(a => a.departmentId === d.id).length
      }));
      const wsDepts = XLSX.utils.json_to_sheet(deptData);
      XLSX.utils.book_append_sheet(wb, wsDepts, "Departamentos");

      // Salva o arquivo
      XLSX.writeFile(wb, `AssetTrack_Export_Completo_${new Date().toISOString().slice(0,10)}.xlsx`);
    } catch (error) {
      console.error("Erro na exportação:", error);
      alert("Houve um erro ao gerar o arquivo Excel.");
    }
  };

  // --- LÓGICA DE IMPORTAÇÃO (XLSX) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();

    setIsImporting(true);

    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Maps para acesso rápido (normalizados para lowercase)
        const classificationMap = new Map<string, string>(classifications.map(c => [c.name.toLowerCase().trim(), c.id]));
        // Explicitly type the Map to ensure get() returns AssetTypeConfig | undefined
        const typeConfigMap = new Map<string, AssetTypeConfig>(assetTypeConfigs.map(t => [t.name.toLowerCase().trim(), t]));

        // --- 1. IMPORTAR DEPARTAMENTOS ---
        let deptMap = new Map<string, string>(); // Nome -> ID
        const wsDepts = wb.Sheets["Departamentos"];
        if (wsDepts) {
          const data: any[] = XLSX.utils.sheet_to_json(wsDepts);
          for (const row of data) {
            const id = row['ID'] || `DEPT-${Math.floor(Math.random() * 100000)}`;
            const name = row['Nome Departamento'];
            if (name) {
              const dept: Department = {
                id,
                name,
                costCenter: row['Centro de Custo'] || '',
                createdAt: new Date().toISOString()
              };
              await db.departments.upsert(dept);
              deptMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com departamentos já existentes no sistema caso não estejam na planilha
        departments.forEach(d => deptMap.set(d.name, d.id));

        // --- 2. IMPORTAR COLABORADORES ---
        let empMap = new Map<string, string>(); // Nome -> ID
        const wsEmps = wb.Sheets["Colaboradores"];
        if (wsEmps) {
          const data: any[] = XLSX.utils.sheet_to_json(wsEmps);
          for (const row of data) {
            const cpf = row['CPF'];
            const name = row['Nome'];
            if (name && cpf) {
              // Tenta encontrar colaborador existente pelo CPF para manter o ID
              const existingEmp = employees.find(e => e.cpf === cpf);
              const id = existingEmp?.id || `EMP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

              // Busca ID do departamento pelo nome
              const deptName = row['Setor/Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const emp: Employee = {
                id,
                name,
                cpf,
                role: row['Cargo/Função'] || '',
                sector: deptName || 'Geral',
                departmentId,
                isActive: row['Status Cadastro'] !== 'Inativo'
              };
              await db.employees.upsert(emp);
              empMap.set(name, id);
            }
          }
        }
        // Atualiza mapa com colaboradores já existentes
        employees.forEach(e => empMap.set(e.name, e.id));

        // --- 3. IMPORTAR ATIVOS ---
        const wsAssets = wb.Sheets["Inventário Ativos"];
        let importedAssetsCount = 0;
        if (wsAssets) {
          const data: any[] = XLSX.utils.sheet_to_json(wsAssets);
          for (const row of data) {
            const id = row['ID Patrimonial'];
            if (id) {
              // --- TRATAMENTO DE CLASSIFICAÇÃO CONTÁBIL ---
              const typeName = (row['Tipo'] || 'Outros').trim();
              const classificationName = (row['Classificação Contábil'] || '').trim();

              if (typeName) {
                const typeKey = typeName.toLowerCase();
                const existingConfig = typeConfigMap.get(typeKey);

                let classificationId = existingConfig?.classificationId;

                // Se a planilha tem classificação, tentamos achar o ID
                if (classificationName) {
                  const foundId = classificationMap.get(classificationName.toLowerCase());
                  if (foundId) classificationId = foundId;
                }

                // Cria ou Atualiza a configuração do Tipo de Ativo
                if (!existingConfig) {
                  const newConfig: AssetTypeConfig = {
                    id: `TYPE-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
                    name: typeName,
                    classificationId: classificationId
                  };
                  await db.assetTypeConfigs.upsert(newConfig);
                  typeConfigMap.set(typeKey, newConfig); // Atualiza mapa local
                } else if (classificationId && existingConfig && existingConfig.classificationId !== classificationId) {
                  // Se já existe mas a planilha trouxe uma classificação diferente, atualizamos
                  const updatedConfig: AssetTypeConfig = { ...existingConfig, classificationId };
                  await db.assetTypeConfigs.upsert(updatedConfig);
                  typeConfigMap.set(typeKey, updatedConfig);
                }
              }

              // --- TRATAMENTO DO ATIVO ---
              const empName = row['Responsável Atual'];
              const assignedTo = empMap.get(empName) || undefined; // undefined se não achar ou for "Estoque"

              const deptName = row['Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              // Manter histórico existente se for atualização, ou criar novo
              const existingAsset = assets.find(a => a.id === id);
              let history = existingAsset?.history || [];

              if (!existingAsset) {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}`,
                   date: new Date().toISOString(),
                   type: 'Criação',
                   description: 'Importado via Planilha Excel',
                   performedBy: 'Sistema de Importação'
                 });
              } else {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}-${Math.random()}`,
                   date: new Date().toISOString(),
                   type: 'Observação',
                   description: 'Dados atualizados via Importação em Lote',
                   performedBy: 'Sistema de Importação'
                 });
              }

              const asset: Asset = {
                id,
                tagId: row['Etiqueta (Tag)'] || id,
                type: typeName, // Usa o tipo tratado
                brand: row['Marca'] || '',
                model: row['Modelo'] || '',
                serialNumber: row['Número de Série'] || '',
                purchaseValue: Number(row['Valor de Aquisição']) || 0,
                status: row['Status'] || 'Disponível',
                assignedTo,
                departmentId,
                processor: row['Processador'] || '',
                ram: row['RAM'] || '',
                storage: row['Armazenamento'] || '',
                observations: row['Observações'] || '',
                createdAt: existingAsset?.createdAt || new Date().toISOString(),
                qrCode: existingAsset?.qrCode || `QR-${id}`,
                photos: existingAsset?.photos || [],
                history
              };

              await db.assets.upsert(asset);
              importedAssetsCount++;
            }
          }
        }

        alert(`Importação concluída com sucesso!\n\nDados Processados:\n- Departamentos Sincronizados\n- Colaboradores Sincronizados\n- ${importedAssetsCount} Ativos Processados\n- Tipos de Ativo & Classificações Atualizados\n\nRecarregue a página para visualizar todas as alterações.`);

        // Limpa o input
        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (error) {
        console.error("Erro na importação:", error);
        alert("Erro crítico ao processar o arquivo. Verifique se o formato segue o modelo de exportação padrão.");
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Card de Exportação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center shadow-inner z-10">
              <Download className="w-10 h-10 text-emerald-600" />
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Exportação de Dados</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Gere um arquivo Excel (.xlsx) completo para backup ou para editar dados em massa e reimportar.
              </p>
           </div>
           <button 
            onClick={handleExportSystemData}
            className="z-10 bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Baixar Planilha Modelo
          </button>
        </div>

        {/* Card de Importação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />

           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center shadow-inner z-10">
              {isImporting ? <Loader2 className="w-10 h-10 text-blue-600 animate-spin" /> : <Upload className="w-10 h-10 text-blue-600" />}
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Importação em Lote</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Carregue a planilha preenchida para atualizar ou criar múltiplos registros de Ativos e Colaboradores.
              </p>
           </div>

           <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
           />

           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isImporting}
            className={`z-10 px-10 py-4 rounded-2xl font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95 ${
              isImporting 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-100'
            }`}
          >
            {isImporting ? 'Processando...' : 'Carregar Planilha .XLSX'}
            {!isImporting && <FileSpreadsheet className="w-5 h-5" />}
          </button>
          {isImporting && <p className="text-[10px] font-bold text-blue-600 animate-pulse">Isso pode levar alguns segundos...</p>}
        </div>
      </div>

      {/* Card de Informações do Sistema */}
      <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8">
         <div className="space-y-6 w-full md:w-auto">
            <div className="flex items-center gap-4">
               <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                  <Database className="w-8 h-8 text-white" />
               </div>
               <div>
                  <h3 className="text-2xl font-black tracking-tight">Status do Banco de Dados</h3>
                  <p className="text-blue-200 text-sm font-bold uppercase tracking-widest">Conexão Segura</p>
               </div>
            </div>

            <div className="space-y-2 pt-2">
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <ShieldCheck className="w-4 h-4 text-emerald-500" /> PostgreSQL (Supabase)
               </div>
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <Activity className="w-4 h-4 text-blue-500" /> Replicação em Tempo Real
               </div>
            </div>
         </div>

         <div className="grid grid-cols-3 gap-8 w-full md:w-auto border-t md:border-t-0 md:border-l border-slate-700 pt-8 md:pt-0 md:pl-10">
            <div className="text-center">
               <span className="block text-3xl font-black">{assets.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Ativos</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{employees.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Pessoas</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{departments.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Setores</span>
            </div>
         </div>
      </div>

      {/* Rodapé Informativo */}
      <div className="text-center py-10 opacity-50">
         <p className="text-xs font-black uppercase tracking-widest text-slate-400">AssetTrack Pro Enterprise v2.6</p>
         <p className="text-[10px] text-slate-400 mt-1">Módulo de Importação/Exportação Avançado</p>
      </div>

    </div>
  );
};

