                  <div className="bg-slate-50 p-6 flex flex-col md:flex-row items-start md:items-center justify-between border-b border-slate-100 gap-4">
                     <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-white border border-slate-200 rounded-2xl flex items-center justify-center text-blue-600 font-bold shadow-sm">
                           <Book className="w-6 h-6" />
                        </div>
                        <div>
                           <div className="flex items-center gap-2">
                              <span className="bg-blue-100 text-blue-700 px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest">{account.code}</span>
                              <h4 className="text-lg font-black text-slate-800">{account.name}</h4>
                           </div>
                           <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Conta Pai (Agrupamento)</p>
                        </div>
                     </div>
                     <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleOpenClassificationForm(account.id)}
                          className="px-4 py-2 bg-white border border-emerald-200 text-emerald-700 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-50 transition-colors flex items-center gap-2"
                        >
                           <Plus className="w-3 h-3" /> Adicionar Conta Analítica
                        </button>
                        <button onClick={() => handleOpenAccountForm(account)} className="p-2 hover:bg-white rounded-xl text-slate-400 hover:text-blue-600 transition-colors">
                           <Edit2 className="w-4 h-4" />
                        </button>
                        <button onClick={() => handleDelete(account.id, 'account')} className="p-2 hover:bg-white rounded-xl text-slate-400 hover:text-rose-600 transition-colors">
                           <Trash2 className="w-4 h-4" />
                        </button>
                     </div>
                  </div>

                  {/* LISTA DE CLASSIFICAÇÕES (FILHOS) - FORMATO TABELA PROFISSIONAL */}
                  <div className="p-4 bg-white">
                     {accountClassifications.length > 0 ? (
                       <div className="overflow-x-auto">
                         <table className="w-full text-left">
                           <thead>
                             <tr className="border-b border-slate-100">
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Código</th>
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Conta</th>
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Natureza</th>
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Deprecia</th>
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Centro Custo</th>
                               <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                             </tr>
                           </thead>
                           <tbody className="divide-y divide-slate-50">
                             {accountClassifications.map(cls => (
                               <tr key={cls.id} className="hover:bg-slate-50/50 transition-colors group">
                                 <td className="px-4 py-3">
                                   <div className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-[10px] font-mono font-bold inline-block">
                                      {cls.code}
                                   </div>
                                 </td>
                                 <td className="px-4 py-3 font-bold text-slate-700 text-sm">{cls.name}</td>
                                 <td className="px-4 py-3">
                                   <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${
                                     cls.type === 'Ativo' ? 'bg-emerald-50 text-emerald-700' : 
                                     cls.type === 'Despesa' ? 'bg-rose-50 text-rose-700' : 'bg-slate-100 text-slate-600'
                                   }`}>
                                     {cls.type || 'Ativo'}
                                   </span>
                                 </td>
                                 <td className="px-4 py-3 text-center">
                                   <span className={`text-[10px] font-bold uppercase ${cls.depreciates !== false ? 'text-blue-600' : 'text-slate-400'}`}>
                                     {cls.depreciates !== false ? 'Sim' : 'Não'}
                                   </span>
                                 </td>
                                 <td className="px-4 py-3 font-mono text-xs font-bold text-slate-600">
                                    {cls.costCenter || '-'}
                                 </td>
                                 <td className="px-4 py-3 text-right">
                                    <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
