                            <button onClick={() => handleOpenAssetTypeForm(type)} className="p-2 text-slate-400 hover:text-blue-600">
                               <Edit2 className="w-4 h-4" />
                            </button>
                            <button onClick={() => handleDelete(type.id, 'asset-type')} className="p-2 text-slate-400 hover:text-rose-600">
                               <Trash2 className="w-4 h-4" />
                            </button>
                         </div>
                      </td>
                   </tr>
                 ))}
                 {filteredAssetTypes.length === 0 && (
                   <tr>
                      <td colSpan={3} className="py-16 text-center text-slate-400 font-bold uppercase text-xs">Nenhum tipo cadastrado.</td>
                   </tr>
                 )}
              </tbody>
           </table>
        </div>
      )}

      {/* FORM MODAL */}
      {showForm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-900 text-white flex items-center justify-between">
              <h3 className="text-xl font-black uppercase tracking-tight">
                {editingItem ? 'Editar' : 'Adicionar'} {
                  formType === 'account' ? 'Conta Pai' : 
                  formType === 'classification' ? 'Conta Analítica' : 'Tipo de Equipamento'
                }
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 space-y-6">

              {formType === 'account' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Conta (Grupo)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Ativo Imobilizado" />
                  </div>
                </>
              )}

              {formType === 'classification' && (
                <>
                  <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 mb-4">
                     <p className="text-[10px] font-black uppercase text-blue-600 tracking-widest mb-1">Vinculado à Conta Pai:</p>
                     <p className="font-bold text-blue-900">{accounts.find(a => a.id === selectedParentAccountId)?.name || 'Erro de Vínculo'}</p>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01.005" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome da Conta (Item)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Equip. Informática" />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Natureza / Tipo</label>
                      <select 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                        value={formData.type || 'Ativo'}
                        onChange={e => setFormData({...formData, type: e.target.value})}
                      >
                        <option value="Ativo">Ativo</option>
                        <option value="Despesa">Despesa</option>
                        <option value="Custo">Custo</option>
                        <option value="Outros">Outros</option>
                      </select>
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Centro Custo</label>
                      <select 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                        value={formData.costCenter || ''} 
                        onChange={e => setFormData({...formData, costCenter: e.target.value})}
                      >
                        <option value="">Selecione...</option>
                        {departments.map(d => (
                          <option key={d.id} value={d.costCenter || d.name}>
                            {d.name} {d.costCenter ? `(${d.costCenter})` : ''}
                          </option>
                        ))}
                      </select>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                     <input 
                       type="checkbox" 
                       id="checkDeprecia"
                       className="w-5 h-5 text-blue-600 rounded focus:ring-blue-500 border-gray-300"
                       checked={formData.depreciates !== false}
                       onChange={e => setFormData({...formData, depreciates: e.target.checked})}
                     />
                     <label htmlFor="checkDeprecia" className="text-sm font-bold text-slate-700 cursor-pointer">
                        Este item sofre depreciação?
                     </label>
                  </div>
                </>
              )}

              {formType === 'asset-type' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Comum (Equipamento)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Macbook, Dell G15..." />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Vincular à Conta Contábil</label>
                    <select 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                      value={formData.classificationId} 
                      onChange={e => setFormData({...formData, classificationId: e.target.value})} 
                      required
                    >
                      <option value="">Selecione...</option>
                      {accounts.map(account => (
                        <optgroup key={account.id} label={account.name}>
                           {classifications.filter(c => c.accountId === account.id).map(c => (
                             <option key={c.id} value={c.id}>{c.code} - {c.name}</option>
                           ))}
                        </optgroup>
                      ))}
                    </select>
                  </div>
                </>
              )}

              <div className="flex gap-3 pt-6 border-t border-slate-100">
                <button type="button" disabled={isSaving} onClick={() => setShowForm(false)} className="flex-1 py-4 font-bold text-slate-400 hover:bg-slate-50 rounded-2xl transition-colors">Cancelar</button>
                <button 
                  type="submit" 
                  disabled={isSaving}
                  className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-100 flex items-center justify-center gap-2 transition-all"
                >
                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
                  {isSaving ? 'Salvando...' : 'Confirmar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AccountingManager;

export type AssetType = string;

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; 
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

// Estrutura Unificada
export interface AccountingAccount {
  id: string;
  code: string; // Número da Conta
  name: string; // Classificação Contábil
  costCenter?: string;
  type?: 'Ativo' | 'Despesa' | 'Custo' | 'Outros';
  depreciates?: boolean;
}

export interface AssetTypeConfig {
  id: string;
  name: string;
  accountId?: string; // Vínculo direto com a conta
}

export interface Asset {
  id: string;
  tagId?: string; // Novo campo: Etiqueta patrimonial física
  serialNumber?: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; 
  isWireless?: boolean; 
  monitorInputs?: string[]; 
  isAbnt?: boolean; 
  hasNumericKeypad?: boolean; 
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; 
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; 
  purchaseValue?: number; // Novo campo para valor de aquisição
}

export interface Employee {
  id: string;
  departmentId: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
  isActive?: boolean;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance'
  | 'accounting'
  | 'system-info';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string;
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'maintenance' | 'delivery' | 'alert';
  createdAt: string;
  targetModule?: AppModule;
  isRead?: boolean;
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado' | 'Reprovado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId?: string | null; // Alterado para permitir nulo/undefined
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado' | 'Confronto';
  createdAt: string;
  type?: 'Padrao' | 'Divergencia';
}

export type AuditStatus = 'Bom' | 'Regular' | 'Ruim' | 'Não Encontrado';

export interface AuditEntry {
  assetId: string;
  status: AuditStatus;
  checkedAt: string;
  observation?: string;
}

export interface AuditSession {
  id: string;
  sector: string;
  createdAt: string;
  entries: AuditEntry[];
  isFinished: boolean;
  generatedRequestId?: string;
}

import React, { useState, useMemo } from 'react';
import { 
  Book, 
  Layers, 
  Plus, 
  Search, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Tag,
  Loader2,
  FolderOpen
} from 'lucide-react';
import { AccountingAccount, AssetTypeConfig, Department } from '../types';

interface AccountingManagerProps {
  accounts: AccountingAccount[];
  assetTypes: AssetTypeConfig[];
  departments: Department[]; 
  onAddAccount: (acc: Omit<AccountingAccount, 'id'>) => Promise<void>;
  onUpdateAccount: (acc: AccountingAccount) => Promise<void>;
  onRemoveAccount: (id: string) => Promise<void>;
  onAddAssetType: (type: Omit<AssetTypeConfig, 'id'>) => Promise<void>;
  onUpdateAssetType: (type: AssetTypeConfig) => Promise<void>;
  onRemoveAssetType: (id: string) => Promise<void>;
}

const AccountingManager: React.FC<AccountingManagerProps> = ({
  accounts, assetTypes, departments,
  onAddAccount, onUpdateAccount, onRemoveAccount,
  onAddAssetType, onUpdateAssetType, onRemoveAssetType
}) => {
  const [activeTab, setActiveTab] = useState<'accounts' | 'asset-types'>('accounts');
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState<'account' | 'asset-type'>('account');
  const [editingItem, setEditingItem] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form states
  const [formData, setFormData] = useState<any>({});

  // --- FILTROS ---
  const filteredAccounts = useMemo(() => {
    return accounts.filter(a => 
      a.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      a.code.includes(searchTerm)
    ).sort((a, b) => a.code.localeCompare(b.code));
  }, [accounts, searchTerm]);

  const filteredAssetTypes = useMemo(() => {
    return assetTypes.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    ).sort((a, b) => a.name.localeCompare(b.name));
  }, [assetTypes, searchTerm]);

  // --- AÇÕES ---

  const handleOpenAccountForm = (account: AccountingAccount | null = null) => {
    setFormType('account');
    setEditingItem(account);
    setFormData(account || { 
      code: '', 
      name: '', 
      type: 'Ativo', 
      depreciates: true, 
      costCenter: '' 
    });
    setShowForm(true);
  };

  const handleOpenAssetTypeForm = (type: AssetTypeConfig | null = null) => {
    setFormType('asset-type');
    setEditingItem(type);
    setFormData(type || { name: '', accountId: '' });
    setShowForm(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (formType === 'account') {
        if (editingItem) await onUpdateAccount(formData);
        else await onAddAccount(formData);
      } else if (formType === 'asset-type') {
        if (editingItem) await onUpdateAssetType(formData);
        else await onAddAssetType(formData);
      }
      setShowForm(false);
      setEditingItem(null);
    } catch (err: any) {
      alert(`Falha ao salvar: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string, type: 'account' | 'asset-type') => {
    if (!confirm('Deseja realmente excluir este registro?')) return;
    try {
      if (type === 'account') await onRemoveAccount(id);
      else await onRemoveAssetType(id);
    } catch (err: any) {
      alert(`Erro ao excluir: ${err.message}`);
    }
