                       }`}>
                         {acc.type || 'Ativo'}
                       </span>
                     </td>
                     <td className="px-6 py-4 text-center">
                       <span className={`text-[10px] font-bold uppercase ${acc.depreciates !== false ? 'text-blue-600' : 'text-slate-400'}`}>
