  ArrowRight
} from 'lucide-react';
import { AccountingAccount, AssetTypeConfig, Department } from '../types';

interface AccountingManagerProps {
  accounts: AccountingAccount[];
  assetTypes: AssetTypeConfig[];
  departments: Department[]; 
  onAddAccount: (acc: Omit<AccountingAccount, 'id'>) => Promise<void>;
  onUpdateAccount: (acc: AccountingAccount) => Promise<void>;
  onRemoveAccount: (id: string) => Promise<void>;
  onAddAssetType: (type: Omit<AssetTypeConfig, 'id'>) => Promise<void>;
  onUpdateAssetType: (type: AssetTypeConfig) => Promise<void>;
  onRemoveAssetType: (id: string) => Promise<void>;
}

const AccountingManager: React.FC<AccountingManagerProps> = ({
  accounts, assetTypes, departments,
  onAddAccount, onUpdateAccount, onRemoveAccount,
  onAddAssetType, onUpdateAssetType, onRemoveAssetType
}) => {
  const [activeTab, setActiveTab] = useState<'accounts' | 'asset-types'>('accounts');
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState<'account' | 'asset-type'>('account');
  const [editingItem, setEditingItem] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form states
  const [formData, setFormData] = useState<any>({});

  // --- FILTROS ---
  const filteredAccounts = useMemo(() => {
    return accounts.filter(a => 
      a.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      a.code.includes(searchTerm)
    ).sort((a, b) => a.code.localeCompare(b.code));
  }, [accounts, searchTerm]);

  const filteredAssetTypes = useMemo(() => {
    return assetTypes.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    ).sort((a, b) => a.name.localeCompare(b.name));
  }, [assetTypes, searchTerm]);

  // --- AGRUPAMENTO POR CONTA (PARA A VIEW DE CARDS) ---
  const groupedAssetTypes = useMemo(() => {
    const groups: Record<string, AssetTypeConfig[]> = {};

    // Inicializa grupos para todas as contas (para mostrar cards vazios também)
    accounts.forEach(acc => {
      groups[acc.id] = [];
    });

    // Grupo especial para sem vínculo
    groups['unlinked'] = [];

    filteredAssetTypes.forEach(type => {
      if (type.accountId && groups[type.accountId]) {
        groups[type.accountId].push(type);
      } else {
        groups['unlinked'].push(type);
      }
    });

    return groups;
  }, [accounts, filteredAssetTypes]);

  // --- AÇÕES ---

  const handleOpenAccountForm = (account: AccountingAccount | null = null) => {
    setFormType('account');
    setEditingItem(account);
    setFormData(account ? {
      id: account.id,
      code: account.code,
      name: account.name,
      type: account.type,
      costCenter: account.costCenter
    } : { 
      code: '', 
      name: '', 
      type: 'Ativo', 
      costCenter: '' 
    });
    setShowForm(true);
  };

  const handleOpenAssetTypeForm = (type: AssetTypeConfig | null = null, preSelectedAccountId?: string) => {
    setFormType('asset-type');
    setEditingItem(type);
    setFormData(type ? { 
        id: type.id, 
        name: type.name, 
        accountId: type.accountId 
    } : { 
        name: '', 
        accountId: preSelectedAccountId || '' 
    });
    setShowForm(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (formType === 'account') {
        if (editingItem) await onUpdateAccount(formData);
        else await onAddAccount(formData);
      } else if (formType === 'asset-type') {
        if (editingItem) await onUpdateAssetType(formData);
        else await onAddAssetType(formData);
      }
      setShowForm(false);
      setEditingItem(null);
    } catch (err: any) {
      alert(`Falha ao salvar: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string, type: 'account' | 'asset-type') => {
    if (!confirm('Deseja realmente excluir este registro?')) return;
    try {
      if (type === 'account') await onRemoveAccount(id);
      else await onRemoveAssetType(id);
    } catch (err: any) {
      alert(`Erro ao excluir: ${err.message}`);
    }
  };

  const getAccountName = (id: string) => {
    const acc = accounts.find(a => a.id === id);
    return acc ? `${acc.code} - ${acc.name}` : 'Não Vinculado';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* HEADER E TABS */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div className="bg-white rounded-[2rem] p-1.5 border border-slate-100 shadow-sm flex gap-1 w-full md:w-auto">
              <button 
                onClick={() => setActiveTab('accounts')}
                className={`px-6 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${
                  activeTab === 'accounts' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'
                }`}
              >
                <Book className="w-4 h-4" /> Plano de Contas
              </button>
              <button 
                onClick={() => setActiveTab('asset-types')}
                className={`px-6 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${
                  activeTab === 'asset-types' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'
                }`}
              >
                <Layers className="w-4 h-4" /> Mapeamento de Tipos
              </button>
           </div>

           <div className="flex items-center gap-3 w-full md:w-auto">
              <div className="relative flex-1 md:flex-none">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                 <input 
                   className="w-full md:w-64 pl-9 pr-4 py-3 rounded-2xl border border-slate-200 text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none"
                   placeholder={activeTab === 'accounts' ? "Buscar conta..." : "Buscar equipamento..."}
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                 />
              </div>
              <button 
                onClick={() => activeTab === 'accounts' ? handleOpenAccountForm() : handleOpenAssetTypeForm()}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95 uppercase text-[10px] tracking-widest whitespace-nowrap"
              >
                <Plus className="w-4 h-4" /> 
                {activeTab === 'accounts' ? 'Nova Conta' : 'Novo Tipo'}
              </button>
           </div>
        </div>
      </div>

      {/* CONTEÚDO: CONTAS */}
      {activeTab === 'accounts' && (
        <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead>
                 <tr className="border-b border-slate-100 bg-slate-50/50">
                   <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest">Código</th>
                   <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest">Classificação (Nome)</th>
                   <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest">Natureza</th>
                   <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest">Centro Custo</th>
                   <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-50">
                 {filteredAccounts.map(acc => (
                   <tr key={acc.id} className="hover:bg-slate-50/50 transition-colors group">
                     <td className="px-6 py-4">
                       <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-[10px] font-mono font-bold">
                          {acc.code}
                       </span>
                     </td>
                     <td className="px-6 py-4 font-bold text-slate-700 text-sm">{acc.name}</td>
                     <td className="px-6 py-4">
                       <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${
                         acc.type === 'Ativo' ? 'bg-emerald-50 text-emerald-700' : 
                         acc.type === 'Despesa' ? 'bg-rose-50 text-rose-700' : 'bg-slate-100 text-slate-600'
                       }`}>
                         {acc.type || 'Ativo'}
                       </span>
                     </td>
                     <td className="px-6 py-4 font-mono text-xs font-bold text-slate-600">
                        {acc.costCenter || '-'}
                     </td>
                     <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                           <button onClick={() => handleOpenAccountForm(acc)} className="p-2 text-slate-400 hover:text-blue-600 rounded-xl hover:bg-slate-100 transition-colors">
                              <Edit2 className="w-4 h-4" />
                           </button>
                           <button onClick={() => handleDelete(acc.id, 'account')} className="p-2 text-slate-400 hover:text-rose-600 rounded-xl hover:bg-slate-100 transition-colors">
                              <Trash2 className="w-4 h-4" />
                           </button>
                        </div>
                     </td>
                   </tr>
                 ))}
                 {filteredAccounts.length === 0 && (
                   <tr>
                      <td colSpan={6} className="py-20 text-center">
                        <FolderOpen className="w-12 h-12 mx-auto text-slate-300 mb-4" />
                        <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Nenhuma conta cadastrada</p>
                      </td>
                   </tr>
                 )}
               </tbody>
             </table>
           </div>
        </div>
      )}

      {/* CONTEÚDO: MAPEAMENTO (VIEW DE CARDS) */}
      {activeTab === 'asset-types' && (
        <div className="space-y-8">

           {/* Card de Itens Sem Vínculo (Só aparece se houver) */}
           {groupedAssetTypes['unlinked'] && groupedAssetTypes['unlinked'].length > 0 && (
             <div className="bg-rose-50 border-2 border-rose-100 rounded-[2.5rem] p-6 shadow-lg shadow-rose-50 animate-in slide-in-from-top-2">
                <div className="flex items-center gap-3 mb-4">
                   <div className="w-10 h-10 bg-rose-200 rounded-xl flex items-center justify-center text-rose-700">
                      <AlertCircle className="w-5 h-5" />
                   </div>
                   <div>
                      <h4 className="text-lg font-black text-rose-800">Sem Vínculo Contábil</h4>
                      <p className="text-[10px] font-bold text-rose-600 uppercase tracking-widest">Estes itens precisam ser classificados</p>
                   </div>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                   {groupedAssetTypes['unlinked'].map(type => (
                     <div key={type.id} className="bg-white p-3 rounded-2xl border border-rose-200 flex justify-between items-center group shadow-sm hover:shadow-md transition-all">
                        <span className="font-bold text-slate-700 text-sm">{type.name}</span>
                        <div className="flex gap-1">
                           <button onClick={() => handleOpenAssetTypeForm(type)} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-blue-600 transition-colors">
                              <Edit2 className="w-3.5 h-3.5" />
                           </button>
                           <button onClick={() => handleDelete(type.id, 'asset-type')} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-rose-600 transition-colors">
                              <Trash2 className="w-3.5 h-3.5" />
                           </button>
                        </div>
                     </div>
                   ))}
                </div>
             </div>
           )}

           {/* Grid de Contas */}
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {filteredAccounts.map(account => (
                <div key={account.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col overflow-hidden hover:shadow-lg transition-all group h-full">
                   {/* Header do Card (Conta) */}
                   <div className="p-6 bg-slate-50 border-b border-slate-100 flex justify-between items-center group-hover:bg-slate-100/80 transition-colors">
                      <div className="flex items-center gap-3">
                         <span className="bg-blue-600 text-white px-2.5 py-1 rounded-lg text-[10px] font-mono font-bold shadow-md shadow-blue-200">
                            {account.code}
                         </span>
                         <div>
                            <h4 className="font-black text-slate-800 leading-tight">{account.name}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{account.type} • {groupedAssetTypes[account.id]?.length || 0} Tipos</p>
                         </div>
                      </div>
                      <button 
                        onClick={() => handleOpenAssetTypeForm(null, account.id)}
                        className="p-2 bg-white border border-slate-200 rounded-xl text-blue-600 hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                        title="Adicionar tipo nesta conta"
                      >
                         <Plus className="w-4 h-4" />
                      </button>
                   </div>

                   {/* Lista de Tipos */}
                   <div className="p-6 flex-1 bg-white">
                      {groupedAssetTypes[account.id]?.length > 0 ? (
                        <div className="space-y-2">
                           {groupedAssetTypes[account.id].map(type => (
                             <div key={type.id} className="flex items-center justify-between p-3 rounded-2xl border border-slate-100 hover:border-blue-200 hover:bg-blue-50/30 transition-all group/item">
                                <div className="flex items-center gap-2">
                                   <div className="w-1.5 h-1.5 rounded-full bg-slate-300 group-hover/item:bg-blue-500 transition-colors" />
                                   <span className="text-sm font-bold text-slate-700">{type.name}</span>
                                </div>
                                <div className="flex gap-1 opacity-0 group-hover/item:opacity-100 transition-opacity">
                                   <button onClick={() => handleOpenAssetTypeForm(type)} className="p-1.5 hover:bg-white rounded-lg text-slate-400 hover:text-blue-600 transition-colors">
                                      <Edit2 className="w-3.5 h-3.5" />
                                   </button>
                                   <button onClick={() => handleDelete(type.id, 'asset-type')} className="p-1.5 hover:bg-white rounded-lg text-slate-400 hover:text-rose-600 transition-colors">
                                      <Trash2 className="w-3.5 h-3.5" />
                                   </button>
                                </div>
                             </div>
                           ))}
                        </div>
                      ) : (
                        <div className="h-full flex flex-col items-center justify-center py-8 text-center opacity-40">
                           <FolderOpen className="w-8 h-8 text-slate-300 mb-2" />
                           <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Nenhum tipo vinculado</p>
                        </div>
                      )}
                   </div>
                </div>
              ))}

              {filteredAccounts.length === 0 && (
                 <div className="col-span-full py-20 text-center text-slate-400 font-bold uppercase text-xs">
                    Nenhuma conta encontrada para o filtro atual.
                 </div>
              )}
           </div>
        </div>
      )}

      {/* FORM MODAL */}
      {showForm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-900 text-white flex items-center justify-between">
              <h3 className="text-xl font-black uppercase tracking-tight">
                {editingItem ? 'Editar' : 'Adicionar'} {formType === 'account' ? 'Conta Contábil' : 'Tipo de Equipamento'}
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 space-y-6">

              {formType === 'account' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Código da Conta</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} required placeholder="Ex: 1.01.05" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Classificação (Nome)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Equipamentos de Informática" />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Natureza</label>
                      <select 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600"
                        value={formData.type || 'Ativo'}
                        onChange={e => setFormData({...formData, type: e.target.value})}
                      >
                        <option value="Ativo">Ativo</option>
                        <option value="Despesa">Despesa</option>
                        <option value="Custo">Custo</option>
                        <option value="Outros">Outros</option>
                      </select>
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Centro de Custo</label>
                      <select 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                        value={formData.costCenter || ''} 
                        onChange={e => setFormData({...formData, costCenter: e.target.value})}
                      >
                        <option value="">Selecione...</option>
                        {departments.map(d => (
                          <option key={d.id} value={d.costCenter || d.name}>
                            {d.name} {d.costCenter ? `(${d.costCenter})` : ''}
                          </option>
                        ))}
                      </select>
                    </div>
                  </div>
                </>
              )}

              {formType === 'asset-type' && (
                <>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Comum (Equipamento)</label>
                    <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-blue-600" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required placeholder="Ex: Macbook, Dell G15..." />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Vincular à Conta Contábil</label>
                    <select 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-blue-600" 
                      value={formData.accountId || ''} 
                      onChange={e => setFormData({...formData, accountId: e.target.value})} 
                      required
                    >
                      <option value="">Selecione a Conta...</option>
                      {accounts.map(acc => (
                        <option key={acc.id} value={acc.id}>{acc.code} - {acc.name}</option>
                      ))}
                    </select>
                  </div>
                </>
              )}

              <div className="flex gap-3 pt-6 border-t border-slate-100">
                <button type="button" disabled={isSaving} onClick={() => setShowForm(false)} className="flex-1 py-4 font-bold text-slate-400 hover:bg-slate-50 rounded-2xl transition-colors">Cancelar</button>
                <button 
                  type="submit" 
                  disabled={isSaving}
                  className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-100 flex items-center justify-center gap-2 transition-all"
                >
                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
                  {isSaving ? 'Salvando...' : 'Confirmar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AccountingManager;

export type AssetType = string;

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; 
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

// Estrutura Unificada
export interface AccountingAccount {
  id: string;
  code: string; // Número da Conta
  name: string; // Classificação Contábil
  costCenter?: string;
  type?: 'Ativo' | 'Despesa' | 'Custo' | 'Outros';
}

export interface AssetTypeConfig {
  id: string;
  name: string;
  accountId?: string; // Vínculo direto com a conta
}

export interface Asset {
  id: string;
  tagId?: string; // Novo campo: Etiqueta patrimonial física
  serialNumber?: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; 
  isWireless?: boolean; 
  monitorInputs?: string[]; 
  isAbnt?: boolean; 
  hasNumericKeypad?: boolean; 
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; 
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; 
  purchaseValue?: number; // Novo campo para valor de aquisição
}

export interface Employee {
  id: string;
  departmentId: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
  isActive?: boolean;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance'
  | 'accounting'
  | 'system-info';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string;
}

export interface AppNotification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'maintenance' | 'delivery' | 'alert';
  createdAt: string;
  targetModule?: AppModule;
  isRead?: boolean;
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado' | 'Reprovado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId?: string | null; // Alterado para permitir nulo/undefined
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado' | 'Confronto';
  createdAt: string;
  type?: 'Padrao' | 'Divergencia';
}

export type AuditStatus = 'Bom' | 'Regular' | 'Ruim' | 'Não Encontrado';

export interface AuditEntry {
  assetId: string;
  status: AuditStatus;
  checkedAt: string;
  observation?: string;
}

export interface AuditSession {
  id: string;
  sector: string;
  createdAt: string;
  entries: AuditEntry[];
  isFinished: boolean;
  generatedRequestId?: string;
}

// Configurações de Integração
export interface SystemIntegrationConfig {
  telegramBotToken?: string;
  telegramChatId?: string;
}

import { Asset, UserAccount } from '../types';

const TELEGRAM_API_BASE = 'https://api.telegram.org/bot';

const getConfigs = () => {
  try {
    const stored = localStorage.getItem('assettrack_integrations');
    return stored ? JSON.parse(stored) : null;
  } catch {
    return null;
  }
};

export const sendMaintenanceAlert = async (asset: Asset, reason: string, user: UserAccount) => {
  const configs = getConfigs();

  if (!configs?.telegramBotToken || !configs?.telegramChatId) {
    console.warn('Telegram não configurado. Notificação ignorada.');
    return;
  }

  const message = `
🚨 *NOVA SOLICITAÇÃO DE REPARO* 🚨

📦 *Ativo:* ${asset.type} ${asset.brand} ${asset.model}
🆔 *ID:* \`${asset.id}\`
🏷️ *Tag:* ${asset.tagId || 'N/A'}

👤 *Solicitante:* ${user.name} (${user.sector})
📝 *Motivo:*
_${reason}_

📅 *Data:* ${new Date().toLocaleDateString('pt-BR')} às ${new Date().toLocaleTimeString('pt-BR')}
  `.trim();

  try {
    const response = await fetch(`${TELEGRAM_API_BASE}${configs.telegramBotToken}/sendMessage`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        chat_id: configs.telegramChatId,
        text: message,
        parse_mode: 'Markdown',
      }),
    });

    if (!response.ok) {
      console.error('Falha ao enviar Telegram:', await response.text());
    }
  } catch (error) {
    console.error('Erro de rede Telegram:', error);
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { Download, Database, ShieldCheck, Activity, Upload, Loader2, FileSpreadsheet, Trash2, AlertTriangle, MessageSquare, Save, CheckCircle2 } from 'lucide-react';
import { Asset, EquipmentRequest, Employee, Department, AssetTypeConfig, AccountingAccount, UserAccount, SystemIntegrationConfig } from '../types';
import { db } from '../services/supabase';

interface SystemInfoManagerProps {
  assets: Asset[];
  requests: EquipmentRequest[];
  employees: Employee[];
  departments: Department[];
  assetTypeConfigs: AssetTypeConfig[];
  accounts: AccountingAccount[];
  currentUser: UserAccount;
}

const SystemInfoManager: React.FC<SystemInfoManagerProps> = ({ 
  assets, 
  requests, 
  employees, 
  departments,
  assetTypeConfigs,
  accounts,
  currentUser
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [isClearing, setIsClearing] = useState(false);

  // Integrações
  const [telegramConfig, setTelegramConfig] = useState<SystemIntegrationConfig>({
    telegramBotToken: '',
    telegramChatId: ''
  });
  const [showConfigSuccess, setShowConfigSuccess] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem('assettrack_integrations');
    if (stored) {
      setTelegramConfig(JSON.parse(stored));
    }
  }, []);

  const handleSaveIntegrations = () => {
    localStorage.setItem('assettrack_integrations', JSON.stringify(telegramConfig));
    setShowConfigSuccess(true);
    setTimeout(() => setShowConfigSuccess(false), 3000);
  };

  // --- LÓGICA DE EXPORTAÇÃO (XLSX) ---
  const handleExportSystemData = () => {
    try {
      const wb = XLSX.utils.book_new();

      // 1. Aba de Ativos
      const assetData = assets.map(a => {
        const emp = employees.find(e => e.id === a.assignedTo);
        const dept = departments.find(d => d.id === a.departmentId);

        // Resolve Classificação Contábil
        const config = assetTypeConfigs.find(c => c.name.toLowerCase().trim() === a.type.toLowerCase().trim());
        const account = accounts.find(c => c.id === config?.accountId);

        return {
          'ID Patrimonial': a.id,
          'Etiqueta (Tag)': a.tagId,
          'Tipo': a.type,
          'Código da Conta': account?.code || '', // Adicionado: Código Contábil
          'Classificação Contábil (Nome)': account?.name || '',
          'Class. Tipo': account?.type || 'Ativo',
          'Centro Custo Class.': account?.costCenter || '',
          'Marca': a.brand,
          'Modelo': a.model,
          'Número de Série': a.serialNumber,
          'Valor de Aquisição': a.purchaseValue || 0,
          'Status': a.status,
          'Responsável Atual': emp?.name || 'Estoque',
          'Departamento': dept?.name || 'Não Vinculado',
          'Processador': a.processor,
          'RAM': a.ram,
          'Armazenamento': a.storage,
          'Observações': a.observations,
          'Data Criação': new Date(a.createdAt).toLocaleDateString()
        };
      });
      const wsAssets = XLSX.utils.json_to_sheet(assetData);
      XLSX.utils.book_append_sheet(wb, wsAssets, "Inventário Ativos");

      // 2. Aba de Colaboradores
      const employeeData = employees.map(e => {
        const dept = departments.find(d => d.id === e.departmentId);
        const assetCount = assets.filter(a => a.assignedTo === e.id).length;
        return {
          'Nome': e.name,
          'CPF': e.cpf,
          'Cargo/Função': e.role,
          'Setor/Departamento': dept?.name || e.sector,
          'Status Cadastro': e.isActive === false ? 'Inativo' : 'Ativo',
          'Qtd Ativos em Posse': assetCount
        };
      });
      const wsEmployees = XLSX.utils.json_to_sheet(employeeData);
      XLSX.utils.book_append_sheet(wb, wsEmployees, "Colaboradores");

      // 3. Aba de Requisições
      const requestData = requests.map(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        return {
          'Protocolo': r.id,
          'Status': r.status,
          'Data': new Date(r.createdAt).toLocaleDateString(),
          'Solicitante (ID)': r.requesterId,
          'Beneficiário': emp?.name || 'Estoque/Outro',
          'Itens Solicitados': r.items.join(', '),
          'Observação': r.observation
        };
      });
      const wsRequests = XLSX.utils.json_to_sheet(requestData);
      XLSX.utils.book_append_sheet(wb, wsRequests, "Requisições");

      // 4. Aba de Departamentos
      const deptData = departments.map(d => ({
        'ID': d.id,
        'Nome Departamento': d.name,
        'Centro de Custo': d.costCenter,
        'Total Ativos Vinculados': assets.filter(a => a.departmentId === d.id).length
      }));
      const wsDepts = XLSX.utils.json_to_sheet(deptData);
      XLSX.utils.book_append_sheet(wb, wsDepts, "Departamentos");

      // Salva o arquivo
      XLSX.writeFile(wb, `AssetTrack_Export_Completo_${new Date().toISOString().slice(0,10)}.xlsx`);
    } catch (error) {
      console.error("Erro na exportação:", error);
      alert("Houve um erro ao gerar o arquivo Excel.");
    }
  };

  // --- LÓGICA DE IMPORTAÇÃO (XLSX) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();

    setIsImporting(true);

    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Maps para acesso rápido
        const accountNameMap = new Map<string, string>(accounts.map(c => [c.name.toLowerCase().trim(), c.id]));
        const accountCodeMap = new Map<string, string>(accounts.map(c => [c.code.trim(), c.id])); // Mapa por Código
        const typeConfigMap = new Map<string, AssetTypeConfig>(assetTypeConfigs.map(t => [t.name.toLowerCase().trim(), t]));

        // Helper para converter valor monetário string (pt-BR) para number
        const parseCurrency = (val: any): number => {
          if (typeof val === 'number') return val;
          if (typeof val === 'string') {
            let s = val.replace('R$', '').trim();
            // Lógica simples: se tem virgula e ponto, assume formato 1.000,00
            // Se só tem virgula, assume decimal (1000,00)
            if (s.includes(',') && s.includes('.')) {
              s = s.replace(/\./g, '').replace(',', '.');
            } else if (s.includes(',')) {
              s = s.replace(',', '.');
            }
            return parseFloat(s) || 0;
          }
          return 0;
        };

        // --- 1. IMPORTAR DEPARTAMENTOS ---
        let deptMap = new Map<string, string>(); 
        const wsDepts = wb.Sheets["Departamentos"];
        if (wsDepts) {
          // raw: false força leitura como string (texto exibido), preservando formatação
          const data: any[] = XLSX.utils.sheet_to_json(wsDepts, { raw: false });
          for (const row of data) {
            const id = row['ID'] || `DEPT-${Math.floor(Math.random() * 100000)}`;
            const name = row['Nome Departamento'];
            if (name) {
              const dept: Department = {
                id,
                name,
                costCenter: row['Centro de Custo'] || '',
                createdAt: new Date().toISOString()
              };
              await db.departments.upsert(dept);
              deptMap.set(name, id);
            }
          }
        }
        departments.forEach(d => deptMap.set(d.name, d.id));

        // --- 2. IMPORTAR COLABORADORES ---
        let empMap = new Map<string, string>(); 
        const wsEmps = wb.Sheets["Colaboradores"];
        if (wsEmps) {
          const data: any[] = XLSX.utils.sheet_to_json(wsEmps, { raw: false });
          for (const row of data) {
            const cpf = row['CPF'];
            const name = row['Nome'];
            if (name && cpf) {
              const existingEmp = employees.find(e => e.cpf === cpf);
              const id = existingEmp?.id || `EMP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

              const deptName = row['Setor/Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const emp: Employee = {
                id,
                name,
                cpf,
                role: row['Cargo/Função'] || '',
                sector: deptName || 'Geral',
                departmentId,
                isActive: row['Status Cadastro'] !== 'Inativo'
              };
              await db.employees.upsert(emp);
              empMap.set(name, id);
            }
          }
        }
        employees.forEach(e => empMap.set(e.name, e.id));

        // --- 3. IMPORTAR ATIVOS ---
        const wsAssets = wb.Sheets["Inventário Ativos"];
        let importedAssetsCount = 0;
        if (wsAssets) {
          // raw: false garante que 'Código da Conta' seja lido como Texto ("001" permanece "001")
          const data: any[] = XLSX.utils.sheet_to_json(wsAssets, { raw: false });
          for (const row of data) {
            const id = row['ID Patrimonial'];
            if (id) {
              // --- TRATAMENTO DE CLASSIFICAÇÃO CONTÁBIL ---
              const typeName = (row['Tipo'] || 'Outros').trim();
              const classificationName = (row['Classificação Contábil (Nome)'] || '').trim();
              const classificationCode = (row['Código da Conta'] ? String(row['Código da Conta']) : '').trim();

              let accountId: string | undefined = undefined;

              // 1. Tenta resolver ou criar a Conta Contábil (Plano de Contas)
              if (classificationCode && classificationName) {
                 if (accountCodeMap.has(classificationCode)) {
                    accountId = accountCodeMap.get(classificationCode);
                 } else {
                    // CRIA NOVA CONTA SE NÃO EXISTIR NA BASE
                    const newAccountId = `ACC-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
                    const newAccount: AccountingAccount = {
                       id: newAccountId,
                       code: classificationCode,
                       name: classificationName,
                       type: (row['Class. Tipo'] || 'Ativo') as any,
                       costCenter: row['Centro Custo Class.'] || ''
                    };
                    await db.accountingAccounts.upsert(newAccount);

                    // Atualiza mapas locais para que as próximas linhas usem a conta criada
                    accountCodeMap.set(classificationCode, newAccountId);
                    accountId = newAccountId;
                 }
              } else if (classificationCode) {
                 // Se só tem código, tenta achar na base
                 accountId = accountCodeMap.get(classificationCode);
              } else if (classificationName) {
                 // Se só tem nome, tenta achar na base
                 accountId = accountNameMap.get(classificationName.toLowerCase());
              }

              // 2. Atualiza/Cria Configuração do Tipo de Ativo e Vínculo
              if (typeName) {
                const typeKey = typeName.toLowerCase();
                const existingConfig = typeConfigMap.get(typeKey);

                // Se já existe config, mas achamos um accountId novo via planilha, atualizamos
                // Se não existe, criamos um novo Tipo de Ativo

                if (!existingConfig) {
                  const newConfig: AssetTypeConfig = {
                    id: `TYPE-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
                    name: typeName,
                    accountId: accountId
                  };
                  await db.assetTypeConfigs.upsert(newConfig);
                  typeConfigMap.set(typeKey, newConfig); 
                } else if (accountId && existingConfig.accountId !== accountId) {
                  // Atualiza vínculo se mudou na planilha
                  const updatedConfig: AssetTypeConfig = { ...existingConfig, accountId };
                  await db.assetTypeConfigs.upsert(updatedConfig);
                  typeConfigMap.set(typeKey, updatedConfig);
                }
              }

              // --- TRATAMENTO DO ATIVO ---
              const empName = row['Responsável Atual'];
              const assignedTo = empMap.get(empName) || undefined; 

              const deptName = row['Departamento'];
              const departmentId = deptMap.get(deptName) || '';

              const purchaseVal = parseCurrency(row['Valor de Aquisição']);

              const existingAsset = assets.find(a => a.id === id);
              let history = existingAsset?.history || [];

              if (!existingAsset) {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}`,
                   date: new Date().toISOString(),
                   type: 'Criação',
                   description: 'Importado via Planilha Excel',
                   performedBy: 'Sistema de Importação'
                 });
              } else {
                 history.push({
                   id: `HIST-IMPORT-${Date.now()}-${Math.random()}`,
                   date: new Date().toISOString(),
                   type: 'Observação',
                   description: 'Dados atualizados via Importação em Lote',
                   performedBy: 'Sistema de Importação'
                 });
              }

              const asset: Asset = {
                id,
                tagId: row['Etiqueta (Tag)'] || id,
                type: typeName,
                brand: row['Marca'] || '',
                model: row['Modelo'] || '',
                serialNumber: row['Número de Série'] || '',
                purchaseValue: purchaseVal,
                status: row['Status'] || 'Disponível',
                assignedTo,
                departmentId,
                processor: row['Processador'] || '',
                ram: row['RAM'] || '',
                storage: row['Armazenamento'] || '',
                observations: row['Observações'] || '',
                createdAt: existingAsset?.createdAt || new Date().toISOString(),
                qrCode: existingAsset?.qrCode || `QR-${id}`,
                photos: existingAsset?.photos || [],
                history
              };

              await db.assets.upsert(asset);
              importedAssetsCount++;
            }
          }
        }

        alert(`Importação concluída com sucesso!\n\nDados Processados:\n- Departamentos Sincronizados\n- Colaboradores Sincronizados\n- ${importedAssetsCount} Ativos Processados\n- Tipos de Ativo & Contas Atualizados\n\nRecarregue a página para visualizar todas as alterações.`);

        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (error) {
        console.error("Erro na importação:", error);
        alert("Erro crítico ao processar o arquivo. Verifique se o formato segue o modelo de exportação padrão.");
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  // --- LÓGICA DE LIMPEZA TOTAL ---
  const handleClearDatabase = async () => {
    if (!confirm("ATENÇÃO: TEM CERTEZA QUE DESEJA APAGAR TODOS OS DADOS?\n\nEssa ação é irreversível e excluirá todos os ativos, colaboradores, departamentos e histórico do sistema.")) {
      return;
    }

    // Segunda confirmação para evitar acidentes
    if (!confirm("ÚLTIMO AVISO: Isso limpará todo o banco de dados para testes. Confirmar exclusão total?")) {
      return;
    }

    setIsClearing(true);
    try {
      // A ordem importa para evitar erros de Foreign Key (embora o ON DELETE SET NULL ajude, é melhor limpar dependentes primeiro)

      // 1. Auditorias e Requisições (Dependentes)
      await db.auditSessions.clearAll();
      await db.requests.clearAll();

      // 2. Notificações
      await db.notifications.clearAll();

      // 3. Ativos (Vinculados a Depts e Emps)
      await db.assets.clearAll();

      // 4. Usuários (Vinculados a Emps)
      // Nota: Não podemos apagar o usuário atual da sessão Auth se estiver logado via Supabase Auth, 
      // mas aqui estamos limpando a tabela 'users' pública da aplicação.
      await db.users.clearAll();

      // 5. Colaboradores (Vinculados a Depts)
      await db.employees.clearAll();

      // 6. Departamentos (Base)
      await db.departments.clearAll();

      // 7. Configurações Auxiliares (Opcional, mas bom para reset total)
      await db.assetTypeConfigs.clearAll();
      await db.accountingAccounts.clearAll();

      alert("Limpeza do sistema concluída com sucesso! A página será recarregada.");
      window.location.reload();

    } catch (error: any) {
      console.error("Erro ao limpar banco:", error);
      alert("Ocorreu um erro ao tentar limpar o banco de dados. Verifique o console ou as permissões.");
    } finally {
      setIsClearing(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Card de Exportação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />
           <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center shadow-inner z-10">
              <Download className="w-10 h-10 text-emerald-600" />
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Exportação de Dados</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Gere um arquivo Excel (.xlsx) completo para backup ou para editar dados em massa e reimportar.
              </p>
           </div>
           <button 
            onClick={handleExportSystemData}
            className="z-10 bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Baixar Planilha Modelo
          </button>
        </div>

        {/* Card de Importação */}
        <div className="flex-1 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl flex flex-col items-center justify-center text-center space-y-6 relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -mr-8 -mt-8 z-0 group-hover:scale-110 transition-transform" />
           <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center shadow-inner z-10">
              {isImporting ? <Loader2 className="w-10 h-10 text-blue-600 animate-spin" /> : <Upload className="w-10 h-10 text-blue-600" />}
           </div>
           <div className="z-10">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Importação em Lote</h3>
              <p className="text-slate-500 font-medium mt-2 max-w-sm mx-auto text-sm">
                Carregue a planilha preenchida para atualizar ou criar múltiplos registros de Ativos e Colaboradores.
              </p>
           </div>

           <input 
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
           />

           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isImporting}
            className={`z-10 px-10 py-4 rounded-2xl font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center gap-2 transform hover:scale-105 active:scale-95 ${
              isImporting 
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-100'
            }`}
          >
            {isImporting ? 'Processando...' : 'Carregar Planilha .XLSX'}
            {!isImporting && <FileSpreadsheet className="w-5 h-5" />}
          </button>
          {isImporting && <p className="text-[10px] font-bold text-blue-600 animate-pulse">Isso pode levar alguns segundos...</p>}
        </div>
      </div>

      {/* CARD INTEGRAÇÕES */}
      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl relative overflow-hidden">
         <div className="flex items-start gap-6 relative z-10">
            <div className="w-16 h-16 bg-sky-500 rounded-2xl flex items-center justify-center shadow-lg shrink-0">
               <MessageSquare className="w-8 h-8 text-white" />
            </div>
            <div className="flex-1">
               <h3 className="text-2xl font-black text-slate-900 tracking-tight">Integração Telegram</h3>
               <p className="text-slate-500 font-medium mt-1 text-sm">
                 Configure um bot para receber notificações automáticas sobre novas solicitações de reparo.
               </p>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                  <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Bot Token</label>
                     <input 
                       type="password"
                       className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-bold outline-none focus:ring-2 focus:ring-sky-500 text-xs" 
                       placeholder="Ex: 123456:ABC-DEF1234ghIkl-zyx57W2v1u123ew11"
                       value={telegramConfig.telegramBotToken}
                       onChange={e => setTelegramConfig({...telegramConfig, telegramBotToken: e.target.value})}
                     />
                  </div>
                  <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chat ID (Responsável)</label>
                     <input 
                       className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-bold outline-none focus:ring-2 focus:ring-sky-500 text-xs" 
                       placeholder="Ex: -987654321"
                       value={telegramConfig.telegramChatId}
                       onChange={e => setTelegramConfig({...telegramConfig, telegramChatId: e.target.value})}
                     />
                  </div>
               </div>

               <div className="mt-4 flex items-center gap-3">
                  <button 
                    onClick={handleSaveIntegrations}
                    className="bg-sky-500 hover:bg-sky-600 text-white px-8 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] flex items-center gap-2 shadow-lg shadow-sky-200 transition-all active:scale-95"
                  >
                    <Save className="w-4 h-4" /> Salvar Configuração
                  </button>
                  {showConfigSuccess && (
                    <span className="text-emerald-600 font-bold text-xs flex items-center gap-1 animate-in fade-in slide-in-from-left-2">
                       <CheckCircle2 className="w-4 h-4" /> Salvo com sucesso!
                    </span>
                  )}
               </div>
            </div>
         </div>
      </div>

      <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8">
         <div className="space-y-6 w-full md:w-auto">
            <div className="flex items-center gap-4">
               <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                  <Database className="w-8 h-8 text-white" />
               </div>
               <div>
                  <h3 className="text-2xl font-black tracking-tight">Status do Banco de Dados</h3>
                  <p className="text-blue-200 text-sm font-bold uppercase tracking-widest">Conexão Segura</p>
               </div>
            </div>

            <div className="space-y-2 pt-2">
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <ShieldCheck className="w-4 h-4 text-emerald-500" /> PostgreSQL (Supabase)
               </div>
               <div className="flex items-center gap-4 text-sm font-bold text-slate-400">
                  <Activity className="w-4 h-4 text-blue-500" /> Replicação em Tempo Real
               </div>
            </div>
         </div>

         <div className="grid grid-cols-3 gap-8 w-full md:w-auto border-t md:border-t-0 md:border-l border-slate-700 pt-8 md:pt-0 md:pl-10">
            <div className="text-center">
               <span className="block text-3xl font-black">{assets.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Ativos</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{employees.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Pessoas</span>
            </div>
            <div className="text-center">
               <span className="block text-3xl font-black">{departments.length}</span>
               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Setores</span>
            </div>
