                          <div>
                            <span className="text-xs font-bold block leading-none">{module.label}</span>
                            {isAdminMasterModule && <span className="text-[8px] opacity-70">Obrigatório para Master</span>}
                          </div>
                        </div>
                        {formData.modules.includes(module.id) && <Check className="w-4 h-4" />}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-4 pt-6 border-t border-slate-100 shrink-0">
                <button type="button" onClick={() => setShowForm(false)} className="px-8 py-4 font-bold text-slate-500 hover:bg-slate-50 rounded-2xl transition-all">Cancelar</button>
                <button type="submit" className="px-12 py-4 font-black bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-black transition-all">
                  {editingUser ? 'Salvar Alterações' : 'Criar Conta Vinculada'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default UserManager;

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  Search, 
  Check, 
  AlertCircle,
  CreditCard,
  FileText,
  Package,
  Truck,
  X,
  Link as LinkIcon,
  CheckSquare,
  Square,
  MoreHorizontal,
  ChevronRight,
  ShieldCheck,
  Zap,
  Tag,
  QrCode,
  DollarSign,
  Plus,
  ArrowRight,
  ExternalLink,
  Loader2,
  Clock,
  Ban,
  Lock,
  PenTool
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation, Asset, HistoryEntry, AssetType, AssetTypeConfig, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onAssetCreated: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string; history?: HistoryEntry[] }) => Promise<void>;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  assetTypeConfigs: AssetTypeConfig[];
  currentUser: UserAccount;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ 
  requests, 
  employees, 
  onUpdateRequest, 
  onAssetCreated, 
  onAddRequest,
  assetTypeConfigs,
  currentUser
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Todos');
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);
  const [showDirectOrderModal, setShowDirectOrderModal] = useState(false);
  const [showReceiptForm, setShowReceiptForm] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // VERIFICAÇÃO DE PERMISSÕES (SEGREGAÇÃO DE FUNÇÃO)
  // Admin sempre tem todas as permissões
  const isApprover = currentUser.username === 'admin' || !!currentUser.canApprovePurchase;
  const isBuyer = currentUser.username === 'admin' || !!currentUser.canExecutePurchase;

  const [newDirectOrder, setNewDirectOrder] = useState({
    type: 'Notebook' as AssetType,
    observation: ''
  });

  const [receiptData, setReceiptData] = useState<Partial<Asset>>({
    brand: '',
    model: '',
    id: '',
    serialNumber: '',
    observations: '',
    purchaseValue: undefined 
  });

  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (employee?.name || 'Estoque').toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());
    const status = item.fulfillment.purchaseStatus || 'Pendente';
    const matchesStatus = statusFilter === 'Todos' || status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id?: string | null) => employees.find(e => e.id === id)?.name || 'Estoque TI (Reposição)';

  const handleUpdateQuotation = async (qIndex: number, field: keyof Quotation, value: any) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };
    const quotations = [...(item.quotations || [
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }, 
      { url: '', price: 0, deliveryPrediction: '' }
    ])];
    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = async (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Cotação Aprovada', 
      approvedQuotationIndex: qIndex 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleAuthorizeOrder = async () => {
    if (!isApprover) {
       alert("Acesso Negado: Apenas perfis com permissão de APROVAÇÃO (Diretoria/Gestão) podem autorizar a compra.");
       return;
    }
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Pedido Autorizado' 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleDenyOrder = async () => {
    if (!isApprover) {
       alert("Acesso Negado: Apenas perfis com permissão de APROVAÇÃO podem negar pedidos.");
       return;
    }
    if (!currentRequest || activeSelection === null) return;
    if (!window.confirm("ATENÇÃO: Deseja realmente NEGAR e encerrar este pedido de compra?")) return;

    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Reprovado' 
    };
    await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
    setActiveSelection(null);
  };

  const handleSetComprado = async (requestId: string, fIndex: number) => {
    if (!isBuyer) {
       alert("Acesso Negado: Apenas perfis com permissão de COMPRA (Financeiro/Compras) podem confirmar pagamentos.");
       return;
    }
    const req = requests.find(r => r.id === requestId);
    if (!req) return;
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIndex] = { ...newFulfillments[fIndex], purchaseStatus: 'Comprado' };
    await onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleOpenReceipt = () => {
    if (!currentFulfillment) return;

    // Regra: Capturar valor se NÃO for peça de reposição
    const isReplacementPart = currentFulfillment.type.toLowerCase().includes('peça') || 
                               currentFulfillment.type.toLowerCase().includes('reposição');

    let priceFromQuotation = 0;
    if (!isReplacementPart && currentFulfillment.approvedQuotationIndex !== undefined) {
      priceFromQuotation = currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex]?.price || 0;
    }

    setReceiptData({
      brand: '',
      model: '',
      id: '',
      serialNumber: '',
      observations: `Item recebido via Pedido de Compra referente à requisição ${currentRequest?.id}`,
      type: currentFulfillment.type,
      purchaseValue: priceFromQuotation 
    });
    setShowReceiptForm(true);
  };

  const handleFinalizeAndCreateAsset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentRequest || activeSelection === null || !currentFulfillment) return;
    setIsSubmitting(true);

    try {
      await onAssetCreated({
        id: receiptData.id || undefined,
        brand: receiptData.brand || '',
        model: receiptData.model || '',
        serialNumber: receiptData.serialNumber || '',
        type: currentFulfillment.type,
        departmentId: 'DEPT-1',
        status: currentRequest.employeeId ? 'Em Uso' : 'Disponível',
        assignedTo: currentRequest.employeeId || undefined,
        observations: receiptData.observations || '',
        purchaseValue: receiptData.purchaseValue || 0,
        photos: [],
        history: [
          {
            id: Math.random().toString(),
            date: new Date().toISOString(),
            type: 'Criação',
            description: `Tombamento via compra ref. ${currentRequest.id}. Valor registrado: R$ ${receiptData.purchaseValue?.toLocaleString('pt-BR')}`,
            performedBy: 'Sistema Financeiro'
          }
        ]
      });

      const newFulfillments = [...(currentRequest.itemFulfillments || [])];
      newFulfillments[activeSelection.fIndex] = { 
        ...newFulfillments[activeSelection.fIndex], 
        isDelivered: true, 
        linkedAssetId: receiptData.id || 'AUTO-GERADO'
      };

      await onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });

      setShowReceiptForm(false);
      setActiveSelection(null);
    } catch (err) {
      alert("Erro ao finalizar tombamento.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreateDirectOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await onAddRequest({
        requesterId: '1',
        employeeId: '', 
        items: [newDirectOrder.type],
        observation: newDirectOrder.observation,
        itemFulfillments: [{
          type: newDirectOrder.type,
          isPurchaseOrder: true,
          purchaseStatus: 'Pendente',
          quotations: [
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' },
            { url: '', price: 0, deliveryPrediction: '' }
          ]
        }]
      });
      setShowDirectOrderModal(false);
      setNewDirectOrder({ type: 'Notebook', observation: '' });
    } catch (err) {
      alert("Erro ao criar pedido.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 flex-1 w-full">
          {[
            { label: 'Cotações', count: purchaseItems.filter(i => (i.fulfillment.purchaseStatus || 'Pendente') === 'Pendente').length, color: 'text-amber-600', bg: 'bg-amber-50' },
            { label: 'Autorização', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Cotação Aprovada').length, color: 'text-blue-600', bg: 'bg-blue-50' },
            { label: 'Autorizados', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pedido Autorizado').length, color: 'text-indigo-600', bg: 'bg-indigo-50' },
            { label: 'Em Trânsito', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length, color: 'text-emerald-600', bg: 'bg-emerald-50' },
          ].map((stat, i) => (
            <div key={i} className={`${stat.bg} p-5 rounded-[1.5rem] border border-slate-100 shadow-sm`}>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{stat.label}</p>
              <p className={`text-2xl font-black ${stat.color} tracking-tight`}>{stat.count}</p>
            </div>
          ))}
        </div>
        <button 
          onClick={() => setShowDirectOrderModal(true)}
          className="w-full lg:w-auto bg-slate-900 hover:bg-black text-white px-8 py-5 rounded-2xl font-black shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-[10px] transition-all"
        >
          <Plus className="w-5 h-5" /> Nova Ordem de Compra
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Protocolo</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipamento</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Destinatário</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Workflow</th>
                <th className="px-6 py-5 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item) => (
                <tr 
                  key={`${item.request.id}-${item.index}`} 
                  className="hover:bg-slate-50/50 transition-colors group cursor-pointer" 
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                >
                  <td className="px-6 py-6 font-mono text-xs font-bold text-slate-400">{item.request.id}</td>
                  <td className="px-6 py-6 font-bold text-slate-800">{item.fulfillment.type}</td>
                  <td className="px-6 py-6">
                    <span className="text-sm font-bold text-slate-700">{getEmployeeName(item.request.employeeId)}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                      (item.fulfillment.purchaseStatus || 'Pendente') === 'Pendente' ? 'bg-amber-50 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Cotação Aprovada' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                      item.fulfillment.purchaseStatus === 'Pedido Autorizado' ? 'bg-indigo-50 text-indigo-600 border-indigo-200' :
                      item.fulfillment.purchaseStatus === 'Reprovado' ? 'bg-rose-50 text-rose-600 border-rose-200' : 
                      'bg-emerald-50 text-emerald-600 border-emerald-200'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <div className="flex items-center justify-end gap-2 text-blue-600 opacity-0 group-hover:opacity-100 transition-all font-black text-[10px] uppercase">
                      Gerenciar <ChevronRight className="w-4 h-4" />
                    </div>
                  </td>
                </tr>
              ))}
              {filteredItems.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs opacity-50">
                    Nenhum pedido de compra ativo.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {activeSelection && currentRequest && currentFulfillment && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setActiveSelection(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                    <ShoppingCart className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Gestão de Ordem de Compra</h3>
                    <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{currentRequest.id} • Item #{activeSelection.fIndex + 1}</p>
                  </div>
                </div>
                <button onClick={() => setActiveSelection(null)} className="p-3 hover:bg-slate-200 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
              <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Item Solicitado</p>
                <div className="flex items-center gap-4">
                   <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center border border-slate-200 shadow-sm">
                      <Package className="w-7 h-7 text-blue-600" />
                   </div>
                   <div>
                      <h4 className="text-lg font-black text-slate-900">{currentFulfillment.type}</h4>
                      <p className="text-xs font-bold text-slate-600">Para: {getEmployeeName(currentRequest.employeeId)}</p>
                   </div>
                </div>
              </div>

              {/* ETAPA 1: COTAÇÕES */}
              {(currentFulfillment.purchaseStatus || 'Pendente') === 'Pendente' && (
                <div className="space-y-6">
                  <div className="flex items-center gap-2">
                    <DollarSign className="w-5 h-5 text-amber-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Mapa Comparativo de Cotações</h4>
                  </div>
                  <div className="space-y-4">
                    {[0, 1, 2].map(qIdx => (
                      <div key={qIdx} className="bg-white border-2 border-slate-200 rounded-3xl p-6 hover:border-blue-400 transition-all shadow-sm">
                        <div className="flex items-center justify-between mb-4">
                           <span className="text-[10px] font-black uppercase bg-slate-100 px-3 py-1 rounded-full text-slate-600">Fornecedor {qIdx + 1}</span>
                           <button 
                            onClick={() => handleApproveQuotation(qIdx)}
                            className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 hover:bg-emerald-600 hover:text-white transition-all"
                           >
                              Escolher Fornecedor
                           </button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                           <div className="relative">
                              <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                              <input 
                                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" 
                                placeholder="Link do produto (URL)" 
                                value={currentFulfillment.quotations?.[qIdx]?.url || ''}
                                onChange={e => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                              />
                           </div>
                           <div className="relative">
                              <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                              <input 
                                type="number"
                                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" 
                                placeholder="Preço (R$)" 
                                value={currentFulfillment.quotations?.[qIdx]?.price || ''}
                                onChange={e => handleUpdateQuotation(qIdx, 'price', parseFloat(e.target.value))}
                              />
                           </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* ETAPA 2: AUTORIZAÇÃO */}
              {currentFulfillment.purchaseStatus === 'Cotação Aprovada' && (
                <div className="space-y-6 animate-in slide-in-from-bottom-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-5 h-5 text-blue-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Aprovação da Diretoria</h4>
                  </div>
                  <div className={`rounded-[2.5rem] p-8 text-white shadow-xl ${isApprover ? 'bg-blue-600' : 'bg-slate-400'}`}>
                     <p className="text-[10px] font-black uppercase opacity-70 mb-4 tracking-widest">Fornecedor Selecionado</p>
                     <div className="flex items-center justify-between mb-8">
                        <div>
                          <p className="text-3xl font-black">R$ {currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex || 0].price?.toLocaleString('pt-BR')}</p>
                          <p className="text-xs font-bold text-blue-100 mt-1">
                             Aguardando sua autorização para prosseguir com a compra.
                          </p>
                        </div>
                        <a 
                          href={currentFulfillment.quotations?.[currentFulfillment.approvedQuotationIndex || 0].url} 
                          target="_blank" 
                          className="bg-white/20 hover:bg-white/40 p-4 rounded-2xl transition-all"
                        >
                          <ExternalLink className="w-6 h-6" />
                        </a>
                     </div>

                     {!isApprover && (
                        <div className="bg-white/20 p-4 rounded-xl flex items-center gap-3 mb-4">
                           <Lock className="w-5 h-5 text-white" />
                           <span className="text-xs font-bold">Requer permissão de APROVADOR para prosseguir.</span>
                        </div>
                     )}

                     <div className="flex gap-4">
                        <button 
                          onClick={handleDenyOrder}
                          disabled={!isApprover}
                          className="flex-1 bg-white/20 text-white hover:bg-white hover:text-rose-600 font-black py-5 rounded-[2rem] uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                          <Ban className="w-5 h-5" /> Negar
                        </button>
                        <button 
                          onClick={handleAuthorizeOrder}
                          disabled={!isApprover}
                          className="flex-[2] bg-white text-blue-600 font-black py-5 rounded-[2rem] uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                          <CheckSquare className="w-5 h-5" /> Autorizar Pedido
                        </button>
                     </div>
                  </div>
                </div>
              )}

              {/* ETAPA 3: PAGAMENTO */}
              {currentFulfillment.purchaseStatus === 'Pedido Autorizado' && (
                <div className="space-y-6">
                  <div className="flex items-center gap-2">
                    <CreditCard className="w-5 h-5 text-indigo-600" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Financeiro</h4>
                  </div>
                  <div className={`rounded-[2.5rem] p-10 text-white shadow-xl text-center ${isBuyer ? 'bg-indigo-600' : 'bg-slate-400'}`}>
                     <p className="text-sm font-bold mb-8">O pedido foi autorizado. Realize o pagamento e confirme o envio abaixo.</p>

                     {!isBuyer && (
                        <div className="bg-white/20 p-4 rounded-xl flex items-center justify-center gap-3 mb-8">
                           <Lock className="w-5 h-5 text-white" />
                           <span className="text-xs font-bold">Requer permissão de COMPRADOR para finalizar.</span>
                        </div>
                     )}

                     <button 
                      onClick={() => handleSetComprado(currentRequest.id, activeSelection.fIndex)}
                      disabled={!isBuyer}
                      className="w-full bg-white text-indigo-600 font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed"
                     >
                        <Truck className="w-6 h-6" /> Confirmar Pagamento e Envio
                     </button>
                  </div>
                </div>
              )}

              {/* ETAPA 4: RECEBIMENTO */}
              {currentFulfillment.purchaseStatus === 'Comprado' && (
                <div className="space-y-6">
                   <div className="flex items-center gap-2 text-emerald-600">
                    <Truck className="w-6 h-6" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Equipamento em Trânsito</h4>
                  </div>
                  <div className="bg-emerald-600 rounded-[2.5rem] p-10 text-white shadow-xl text-center">
                     <Package className="w-16 h-16 mx-auto mb-6 animate-bounce" />
                     <p className="font-bold mb-8">O item está a caminho. Clique abaixo ao recebê-lo fisicamente.</p>
                     <button 
                      onClick={handleOpenReceipt}
                      className="w-full bg-white text-emerald-600 font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs"
                     >
                        Registrar Recebimento
                     </button>
                  </div>
                </div>
              )}

              {/* STATUS REPROVADO */}
              {currentFulfillment.purchaseStatus === 'Reprovado' && (
                <div className="space-y-6">
                   <div className="flex items-center gap-2 text-rose-600">
                    <Ban className="w-6 h-6" />
                    <h4 className="text-sm font-black uppercase tracking-widest text-slate-800">Pedido Recusado</h4>
                  </div>
                  <div className="bg-rose-100 rounded-[2.5rem] p-10 text-rose-800 shadow-sm text-center border border-rose-200">
                     <X className="w-16 h-16 mx-auto mb-6 opacity-50" />
                     <p className="font-bold">Este pedido foi negado pela diretoria e encerrado.</p>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* MODAL: NOVA ORDEM DIRETA */}
      {showDirectOrderModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <ShoppingCart className="w-5 h-5" />
                    <h3 className="text-xl font-black uppercase tracking-tight">Nova Ordem de Compra</h3>
                 </div>
                 <button onClick={() => setShowDirectOrderModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleCreateDirectOrder} className="p-10 space-y-6">
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Equipamento</label>
                    <select 
                      className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none"
                      value={newDirectOrder.type}
                      onChange={e => setNewDirectOrder({...newDirectOrder, type: e.target.value as AssetType})}
                    >
                      {(assetTypeConfigs.length > 0 ? assetTypeConfigs.map(t => t.name) : ASSET_TYPES).map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                 </div>
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold h-32 outline-none"
                      placeholder="Motivo da compra..."
                      value={newDirectOrder.observation}
                      onChange={e => setNewDirectOrder({...newDirectOrder, observation: e.target.value})}
                      required
                    />
                 </div>
                 <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs disabled:bg-slate-300"
                 >
                    {isSubmitting ? 'Processando...' : 'Abrir Ordem de Compra'}
                 </button>
              </form>
           </div>
        </div>
      )}

      {/* MODAL: TOMBAMENTO */}
      {showReceiptForm && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden">
              <div className="bg-emerald-600 p-8 text-white flex items-center justify-between">
                 <h3 className="text-xl font-black uppercase tracking-tight">Tombamento</h3>
                 <button onClick={() => setShowReceiptForm(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleFinalizeAndCreateAsset} className="p-10 space-y-6">
                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ID Patrimonial (Vazio = Auto)</label>
                    <input 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-mono font-black text-lg text-center" 
                      value={receiptData.id} 
                      onChange={e => setReceiptData({...receiptData, id: e.target.value})} 
                      placeholder="Ex: AST-5050"
                    />
                 </div>
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400">Marca</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-200" placeholder="Dell" value={receiptData.brand} onChange={e => setReceiptData({...receiptData, brand: e.target.value})} required />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400">Modelo</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-200" placeholder="G15" value={receiptData.model} onChange={e => setReceiptData({...receiptData, model: e.target.value})} required />
                    </div>
                 </div>

                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Número de Série (S/N)</label>
                    <input 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-emerald-600"
                      value={receiptData.serialNumber}
                      onChange={e => setReceiptData({...receiptData, serialNumber: e.target.value})}
                      placeholder="S/N do Fabricante"
                    />
                 </div>

                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor de Aquisição (R$)</label>
                    <input 
                      type="number"
                      step="0.01"
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-emerald-50/30 font-bold outline-none focus:ring-2 focus:ring-emerald-600"
                      value={receiptData.purchaseValue ?? ''}
                      onChange={e => {
                        const val = parseFloat(e.target.value);
                        setReceiptData({...receiptData, purchaseValue: isNaN(val) ? undefined : val})
                      }}
                      placeholder="0,00"
                    />
                 </div>

                 <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs">
                    {isSubmitting ? 'Salvando...' : 'Concluir e Registrar Ativo'}
                 </button>
              </form>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default PurchaseOrderManager;

import React, { useState, useMemo } from 'react';
import { 
  Wrench, 
  Search, 
  Plus, 
  X, 
  Activity, 
  CheckCircle2, 
  Package, 
  AlertCircle,
  Building2,
  Clock,
  ChevronRight,
  Info,
  Layers,
  ArrowRight,
  User,
  Settings2,
  ShoppingCart,
  Trash2,
  FileText,
  Zap,
  Loader2,
  History
} from 'lucide-react';
import { Asset, HistoryEntry, Employee, Department, AppNotification, EquipmentRequest, AssetType, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';
import { sendMaintenanceAlert } from '../services/telegramService';

interface MaintenanceManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  currentUser: UserAccount;
  onUpdateAsset: (asset: Asset) => Promise<void>;
  onAddNotification: (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => void;
  onAddRequest: (req: any) => Promise<void>;
}

const MaintenanceManager: React.FC<MaintenanceManagerProps> = ({ 
  assets, 
  employees, 
  companies, 
  currentUser, 
  onUpdateAsset, 
  onAddNotification, 
  onAddRequest 
}) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [employeeFilter, setEmployeeFilter] = useState(''); // Novo estado para filtro de usuário

  const [selectedAssetId, setSelectedAssetId] = useState('');
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);

  const [reason, setReason] = useState('');
  const [finalDiagnosis, setFinalDiagnosis] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPOForm, setShowPOForm] = useState(false);
  const [poType, setPoType] = useState<AssetType>('Mouse');
  const [validationError, setValidationError] = useState(false);

  const assetsInMaintenance = useMemo(() => 
    assets.filter(a => a.status === 'Manutenção')
  , [assets]);

  const availableForMaintenance = useMemo(() => 
    assets.filter(a => a.status !== 'Manutenção' && a.status !== 'Baixado')
  , [assets]);

  const filteredAvailable = availableForMaintenance.filter(a => {
    const matchesSearch = a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesEmployee = employeeFilter ? a.assignedTo === employeeFilter : true;

    return matchesSearch && matchesEmployee;
  });

  const handleOpenMaintenance = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAssetId || !reason.trim()) return;

    const asset = assets.find(a => a.id === selectedAssetId);
    if (!asset) return;

    setIsSubmitting(true);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Entrada em manutenção: ${reason}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...asset,
        status: 'Manutenção',
        observations: reason,
        history: [...(asset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);

      // Envia notificação para o Telegram
      await sendMaintenanceAlert(updatedAsset, reason, currentUser);

      setShowModal(false);
      setSelectedAssetId('');
      setReason('');
      setEmployeeFilter('');
    } catch (error) {
      alert("Erro ao iniciar manutenção.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleConcludeMaintenance = async () => {
    if (!detailAsset) return;

    const diagnosis = finalDiagnosis.trim();
    if (!diagnosis) {
      setValidationError(true);
      return;
    }

    setIsSubmitting(true);
    setValidationError(false);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-CONC-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Manutenção concluída. Laudo: ${diagnosis}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Disponível',
        assignedTo: undefined, // Libera o colaborador anterior
        observations: `Reparo finalizado em ${new Date().toLocaleDateString()}: ${diagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);
      alert("Manutenção concluída com sucesso! O ativo está disponível para uso.");
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error: any) {
      alert("Falha ao concluir: " + (error.message || "Erro de rede"));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRetireAsset = async () => {
    if (!detailAsset) return;

    const diagnosis = finalDiagnosis.trim();
    if (!diagnosis) {
      setValidationError(true);
      return;
    }

    if (!window.confirm("CONFIRMAÇÃO CRÍTICA: Deseja realmente realizar a BAIXA PATRIMONIAL permanente deste ativo? Esta ação removerá o ativo de circulação.")) {
      return;
    }

    setIsSubmitting(true);
    setValidationError(false);
    try {
      const historyEntry: HistoryEntry = {
        id: `HIST-BAIXA-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'Status',
        description: `BAIXA PATRIMONIAL DEFINITIVA: ${diagnosis}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Baixado',
        assignedTo: undefined, // Crucial: limpar vínculo
        departmentId: detailAsset.departmentId, // Mantemos depto original p/ histórico
        observations: `ATIVO INATIVADO/BAIXADO EM ${new Date().toLocaleDateString()}: ${diagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);

      onAddNotification({
        title: 'Baixa de Patrimônio',
        message: `O ativo ${detailAsset.id} foi inativado permanentemente.`,
        type: 'alert',
        targetModule: 'assets'
      });

      alert(`Baixa patrimonial do ativo ${detailAsset.id} realizada com sucesso!`);
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error: any) {
      console.error("Erro na baixa:", error);
      alert("Erro ao processar baixa patrimonial: " + (error.message || "Verifique a conexão ou permissões."));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreatePurchaseOrder = async () => {
    if (!detailAsset) return;
    setIsSubmitting(true);
    try {
      await onAddRequest({
        requesterId: currentUser.id,
        employeeId: null,
        items: [poType],
        observation: `[MANUTENÇÃO] Aquisição de peça (${poType}) para reparo do ativo ${detailAsset.id}.\nDiagnóstico Atual: ${finalDiagnosis || detailAsset.observations}`,
        itemFulfillments: [{ 
          type: poType, 
          isPurchaseOrder: true, 
          purchaseStatus: 'Pendente',
          quotations: [
             { url: '', price: 0, deliveryPrediction: '' },
             { url: '', price: 0, deliveryPrediction: '' },
             { url: '', price: 0, deliveryPrediction: '' }
          ]
        }]
      });

      setShowPOForm(false);
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');

      onAddNotification({
        title: 'Solicitação de Compra',
        message: `Pedido de compra iniciado para ${poType} (Ref: ${detailAsset.id}).`,
        type: 'info',
        targetModule: 'purchase-orders'
      });
      alert("Fluxo de compra iniciado com sucesso!\nO modal de manutenção foi fechado. Acompanhe a cotação no módulo 'Pedidos de Compra'.");
    } catch (e: any) {
      console.error(e);
      const errorMsg = e?.message || "Erro desconhecido";
      alert("Erro ao iniciar fluxo de compra: " + errorMsg);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">Centro de Manutenção</h3>
          <p className="text-slate-500 font-medium italic">Gestão técnica e descarte de equipamentos.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-amber-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Wrench className="w-5 h-5" />
          Nova Entrada de Reparo
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assetsInMaintenance.map(asset => (
          <div 
            key={asset.id} 
            onClick={() => {
              if (isSubmitting) return;
              setDetailAsset(asset);
              setFinalDiagnosis(''); 
              setValidationError(false);
              setShowDetailModal(true);
            }}
            className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm hover:shadow-xl hover:border-amber-400 transition-all group flex flex-col cursor-pointer active:scale-95"
          >
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 group-hover:bg-amber-600 group-hover:text-white transition-all duration-500 shadow-sm">
                <Activity className="w-7 h-7" />
              </div>
              <div className="flex flex-col items-end">
                 <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-1 shadow-lg shadow-amber-100">
                    Em Reparo
                 </span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter font-mono">{asset.id}</p>
              </div>
            </div>

            <div className="space-y-1 mb-6">
              <h4 className="text-xl font-black text-slate-800 tracking-tight leading-none group-hover:text-amber-600 transition-colors">{asset.type}</h4>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{asset.brand} {asset.model}</p>
            </div>

            <div className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 mb-6 flex-1">
               <div className="flex items-center gap-2 text-amber-600 mb-2">
                  <Info className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Diagnóstico Inicial</span>
               </div>
               <p className="text-xs text-slate-600 font-medium leading-relaxed italic line-clamp-3">
                 "{asset.observations}"
               </p>
            </div>

            <div className="flex items-center justify-between text-amber-600 font-black text-[10px] uppercase tracking-widest pt-2 border-t border-amber-100">
               <span>Painel de Encerramento</span>
               <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </div>
          </div>
        ))}

        {assetsInMaintenance.length === 0 && (
          <div className="col-span-full py-32 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-center space-y-4">
             <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-sm">
                <Settings2 className="w-10 h-10 text-slate-200" />
             </div>
             <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Sem Ativos em Manutenção</p>
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-100 bg-amber-600 text-white flex items-center justify-between">
                 <h3 className="text-2xl font-black tracking-tight flex items-center gap-3">
                   <Wrench className="w-7 h-7" /> Entrada em Manutenção
                 </h3>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>

              <form onSubmit={handleOpenMaintenance} className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="space-y-4">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Selecione o Equipamento</label>

                    {/* Filtro de Colaborador */}
                    <div className="space-y-2">
                       <select 
                         className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:ring-2 focus:ring-amber-500 transition-shadow"
                         value={employeeFilter}
                         onChange={(e) => setEmployeeFilter(e.target.value)}
                       >
                          <option value="">Filtrar por Colaborador (Todos)</option>
                          {employees.map(emp => (
                             <option key={emp.id} value={emp.id}>{emp.name} — {emp.sector}</option>
                          ))}
                       </select>
                    </div>

                    <div className="bg-slate-50 p-4 rounded-[2rem] border border-slate-200">
                       <div className="relative mb-4">
                          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                          <input 
                            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 font-bold outline-none focus:ring-2 focus:ring-amber-500" 
                            placeholder="Buscar por ID, Marca ou Modelo..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                          />
                       </div>
                       <div className="grid grid-cols-1 gap-2 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                          {filteredAvailable.map(asset => (
                             <div 
                               key={asset.id}
                               onClick={() => setSelectedAssetId(asset.id)}
                               className={`p-4 rounded-xl border flex items-center justify-between cursor-pointer transition-all ${
                                 selectedAssetId === asset.id 
                                   ? 'bg-amber-100 border-amber-300 shadow-md' 
                                   : 'bg-white border-slate-100 hover:border-amber-200'
                               }`}
                             >
                                <div className="flex items-center gap-3">
                                   <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${selectedAssetId === asset.id ? 'bg-amber-500 text-white' : 'bg-slate-100 text-slate-400'}`}>
                                      <Package className="w-4 h-4" />
                                   </div>
                                   <div>
                                      <p className="text-xs font-black text-slate-800">{asset.type} - {asset.brand} {asset.model}</p>
                                      <p className="text-[10px] text-slate-500 font-mono">{asset.id}</p>
                                   </div>
                                </div>
                                {selectedAssetId === asset.id && <CheckCircle2 className="w-5 h-5 text-amber-600" />}
                             </div>
                          ))}
                          {filteredAvailable.length === 0 && (
                            <p className="text-center py-4 text-xs font-bold text-slate-400 uppercase">Nenhum ativo disponível encontrado.</p>
                          )}
                       </div>
                    </div>
                 </div>

                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Relato do Problema / Motivo</label>
                    <textarea 
                      className="w-full p-6 rounded-[2rem] border border-slate-200 font-medium outline-none focus:ring-2 focus:ring-amber-500 h-32 bg-slate-50 focus:bg-white transition-colors"
                      placeholder="Descreva o defeito relatado pelo usuário ou motivo da manutenção preventiva..."
                      value={reason}
                      onChange={e => setReason(e.target.value)}
                      required
                    />
                 </div>
              </form>

              <div className="p-8 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
                 <button onClick={() => setShowModal(false)} className="px-8 py-4 font-bold text-slate-400 hover:bg-slate-100 rounded-2xl transition-all">Cancelar</button>
                 <button 
                   onClick={handleOpenMaintenance}
                   disabled={!selectedAssetId || !reason || isSubmitting}
                   className="px-10 py-4 bg-amber-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-amber-100 flex items-center gap-2 hover:bg-amber-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                 >
                   {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wrench className="w-4 h-4" />}
                   Confirmar Entrada
                 </button>
              </div>
           </div>
        </div>
      )}

      {showDetailModal && detailAsset && (
        <div className="fixed inset-0 z-[100] flex items-center justify-end p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl h-full md:h-auto md:max-h-[95vh] md:rounded-[3rem] shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-amber-100 rounded-2xl flex items-center justify-center text-amber-600 shadow-sm">
                       <Activity className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-xl font-black text-slate-900 tracking-tight leading-none mb-1">Diagnóstico & Reparo</h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{detailAsset.id} • {detailAsset.model}</p>
                    </div>
                 </div>
                 <button onClick={() => setShowDetailModal(false)} className="p-2 hover:bg-slate-200 rounded-full transition-all">
                    <X className="w-6 h-6 text-slate-400" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="bg-amber-50 p-6 rounded-3xl border border-amber-100 space-y-2">
                    <h4 className="text-[10px] font-black text-amber-700 uppercase tracking-widest flex items-center gap-2">
                      <AlertCircle className="w-4 h-4" /> Motivo da Entrada
                    </h4>
                    <p className="text-sm font-semibold text-slate-700 leading-relaxed italic">
                      "{detailAsset.observations}"
                    </p>
                 </div>

                 <div className="space-y-4">
                    <div className="flex items-center justify-between">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Laudo Técnico Final / Solução</label>
                       {validationError && <span className="text-[10px] font-bold text-rose-500 animate-pulse">Campo Obrigatório</span>}
                    </div>
                    <textarea 
                      className={`w-full p-6 rounded-[2rem] border ${validationError ? 'border-rose-300 ring-2 ring-rose-100' : 'border-slate-200'} font-medium outline-none focus:ring-2 focus:ring-blue-500 h-40 bg-white shadow-sm`}
                      placeholder="Descreva o procedimento realizado, peças trocadas ou motivo da condenação do equipamento..."
                      value={finalDiagnosis}
                      onChange={e => {
                        setFinalDiagnosis(e.target.value);
                        if(e.target.value.trim()) setValidationError(false);
                      }}
                    />
                 </div>

                 {showPOForm && (
                   <div className="bg-blue-50 p-6 rounded-[2rem] border border-blue-100 animate-in slide-in-from-top-4">
                      <h4 className="text-xs font-black text-blue-800 uppercase tracking-widest mb-4 flex items-center gap-2">
                         <ShoppingCart className="w-4 h-4" /> Solicitar Peça de Reposição
                      </h4>
                      <div className="space-y-3">
                         <label className="text-[10px] font-bold text-slate-500 uppercase">Tipo de Peça</label>
                         <select 
                           className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-sm outline-none"
                           value={poType}
                           onChange={(e) => setPoType(e.target.value as AssetType)}
                         >
                            {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                         </select>
                         <div className="flex gap-2 pt-2">
                            <button 
                              onClick={() => setShowPOForm(false)}
                              className="flex-1 py-3 bg-white border border-slate-200 rounded-xl font-bold text-xs text-slate-500"
                            >
                               Cancelar
                            </button>
                            <button 
                              onClick={handleCreatePurchaseOrder}
                              disabled={isSubmitting}
                              className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-lg hover:bg-blue-700"
                            >
                               {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin mx-auto" /> : 'Abrir Pedido'}
                            </button>
                         </div>
                      </div>
                   </div>
                 )}
              </div>

              <div className="p-6 bg-slate-50 border-t border-slate-100 grid grid-cols-1 md:grid-cols-3 gap-3">
                 {!showPOForm && (
                   <button 
                     onClick={() => setShowPOForm(true)}
                     className="py-4 bg-white border border-slate-200 text-slate-600 rounded-2xl font-black uppercase text-[9px] tracking-widest hover:border-blue-400 hover:text-blue-600 transition-all flex flex-col items-center justify-center gap-1"
                   >
                     <ShoppingCart className="w-4 h-4" />
                     Solicitar Peça
                   </button>
                 )}

                 <button 
                   onClick={handleRetireAsset}
                   disabled={isSubmitting}
                   className="py-4 bg-rose-50 border border-rose-100 text-rose-600 rounded-2xl font-black uppercase text-[9px] tracking-widest hover:bg-rose-100 hover:border-rose-300 transition-all flex flex-col items-center justify-center gap-1"
                 >
                   <Trash2 className="w-4 h-4" />
                   Condenar / Baixar
                 </button>

                 <button 
                   onClick={handleConcludeMaintenance}
                   disabled={isSubmitting}
                   className="py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-[9px] tracking-widest shadow-lg shadow-emerald-200 hover:bg-emerald-700 transition-all flex flex-col items-center justify-center gap-1 md:col-span-1"
                 >
                   <CheckCircle2 className="w-4 h-4" />
                   Concluir Reparo
                 </button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default MaintenanceManager;

export type AssetType = string;

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; 
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

// Estrutura Unificada
export interface AccountingAccount {
  id: string;
  code: string; // Número da Conta
  name: string; // Classificação Contábil
  costCenter?: string;
  type?: 'Ativo' | 'Despesa' | 'Custo' | 'Outros';
}

export interface AssetTypeConfig {
  id: string;
  name: string;
  accountId?: string; // Vínculo direto com a conta
}

export interface Asset {
  id: string;
