}

export interface Employee {
  id: string;
  departmentId: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
  isActive?: boolean;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
