const localDB = {
  save: (key: string, data: any) => {
    try {
      localStorage.setItem(`assettrack_${key}`, JSON.stringify(data));
    } catch (e) { console.error('Erro ao salvar cache local', e); }
  },
  get: (key: string) => {
